async def _fetch_image_bytes(prompt: str, width: int = 1024, height: int = 1024) -> bytes:
    """Fetch image bytes from Pollinations, retrying with free fallback models.
    Raises Exception if all attempts fail."""
    encoded = urllib.parse.quote(prompt)
    last_err = None
    for model in _IMG_MODELS:
        model_param = f"&model={model}" if model else ""
        url = f"{POLLINATIONS_BASE}/{encoded}?width={width}&height={height}&nologo=true{model_param}"
        for attempt in range(3):
            try:
                async with httpx.AsyncClient(timeout=60, follow_redirects=True) as client:
                    r = await client.get(url)
                if r.status_code == 200 and r.headers.get("content-type", "").startswith("image"):
                    return r.content
                if r.status_code == 402:
                    # Queue full — wait then retry
                    await asyncio.sleep(5 * (attempt + 1))
                    last_err = f"queue full (model={model or 'default'})"
                    continue
                last_err = f"HTTP {r.status_code} (model={model or 'default'})"
                break
            except Exception as e:
                last_err = str(e)
                await asyncio.sleep(3)
    raise Exception(f"Image generation failed: {last_err}")

