def _yt_base_opts(extra: dict = None) -> dict:
    """
    Base yt-dlp options for YouTube.
    Priority client order: tv_embedded → ios → android → mweb
    - tv_embedded: best for server/datacenter IPs — bypasses IP blocking without PO tokens
    - ios/android: native clients, no PO token needed
    - mweb: fallback mobile web client
    (web client requires PO tokens since 2025, causes 403 on server IPs — excluded)
    """
    opts = {
        "quiet":                   True,
        "no_warnings":             True,
        "noplaylist":              True,
        "socket_timeout":          30,
        "retries":                 5,
        "fragment_retries":        5,
        "geo_bypass":              True,
        "nocheckcertificate":      True,
        "sleep_interval_requests": 1,   # avoid rate-limit triggers
        # tv_embedded bypasses datacenter IP blocks best
        "extractor_args": {"youtube": {
            "player_client": ["tv_embedded", "ios", "android", "mweb"],
            "skip":          ["webpage"],
        }},
        "http_headers": {
            "User-Agent": (
                "Mozilla/5.0 (Linux; Android 13; Pixel 7) "
                "AppleWebKit/537.36 (KHTML, like Gecko) "
                "Chrome/126.0.0.0 Mobile Safari/537.36"
            ),
        },
    }
    # Use cookies if available (bypasses age-restriction + extra bot checks)
    if os.path.isfile(YOUTUBE_COOKIES_FILE):
        opts["cookiefile"] = YOUTUBE_COOKIES_FILE
    if extra:
        opts.update(extra)
    return opts

