def _ig_make_account(cookies: str, idx: int) -> dict:
    import time as _t
    return {"cookies": cookies, "ua": _IG_USER_AGENTS[idx % len(_IG_USER_AGENTS)],
            "last_req_time": 0.0, "cooldown_until": 0.0, "hour_start": _t.time(),
            "hour_count": 0, "is_dead": False, "fail_count": 0, "enabled": True}


def _ig_load_accounts() -> list:
    lst = []
    for i in range(1, 21):
        v = os.environ.get(f"IG_COOKIES_{i}", "").strip()
        if v:
            lst.append(_ig_make_account(v, i - 1))
    if not lst and os.path.exists(IG_COOKIES_FILE):
        with open(IG_COOKIES_FILE) as f:
            lines = [l.strip() for l in f if l.strip() and not l.startswith("#")]
        for i, c in enumerate(lines):
            lst.append(_ig_make_account(c, i))
    if not lst:
        try:
            with open("bot/insta_cookies.json") as f:
                cj = json.load(f)
            cs = "; ".join(f"{k}={v}" for k, v in cj.items() if v)
            if "sessionid=" in cs:
                lst.append(_ig_make_account(cs, 0))
        except Exception:
            pass
    return lst


def _ig_get_best() -> "dict | None":
    import time as _t
    now = _t.time()
    avail = []
    for a in _ig_accounts:
        if a["is_dead"] or not a["enabled"]: continue
        if a["cooldown_until"] > now: continue
        if now - a["hour_start"] >= 3600:
            a["hour_count"] = 0; a["hour_start"] = now
        if a["hour_count"] >= _IG_COOLDOWN["hourly_limit"]: continue
        avail.append(a)
    if avail:
        return sorted(avail, key=lambda a: a["last_req_time"])[0]
    on_cd = [a for a in _ig_accounts if not a["is_dead"] and a["enabled"] and a["cooldown_until"] > now]
    return sorted(on_cd, key=lambda a: a["cooldown_until"])[0] if on_cd else None


def _ig_mark_dead(acc: dict, reason: str = ""):
    acc["is_dead"] = True


def _ig_set_cooldown(acc: dict, kind: str):
    import time as _t
    acc["cooldown_until"] = _t.time() + _IG_COOLDOWN.get(kind, _IG_COOLDOWN["rate_limit"])
    acc["fail_count"] += 1


def _ig_build_headers(acc: dict) -> dict:
    import re as _re, random as _rnd
    c   = acc["cookies"]
    ua  = acc["ua"]
    csrf   = next((_m.group(1) for _m in [_re.search(r"csrftoken=([^;]+)", c)] if _m), "")
    ig_did = next((_m.group(1) for _m in [_re.search(r"ig_did=([^;]+)", c)] if _m), "")
    cv  = _rnd.choice(_IG_CHROME_VERSIONS)
    mob = "?1" if "Mobile" in ua else "?0"
    plt = "macOS" if "Macintosh" in ua else ("Linux" if "Linux" in ua else "Windows")
    return {
        "User-Agent": ua, "Accept": "*/*",
        "Accept-Language": _rnd.choice(_IG_ACCEPT_LANGS),
        "Accept-Encoding": "gzip, deflate, br",
        "X-IG-App-ID": "936619743392459", "X-IG-WWW-Claim": "0",
        "X-IG-Device-ID": ig_did,
        "X-Bloks-Version-Id": "ce555e5500576acd8e84a66e6e33c56e1a2a83a2c7a4df5c6e40b9de63e93b1",
        "X-CSRFToken": csrf,
        "X-IG-Bandwidth-Speed-KBPS": str(_rnd.choice(_IG_BANDWIDTHS)),
        "X-IG-Connection-Type": _rnd.choice(_IG_CONNECTIONS),
        "Cookie": c, "Referer": "https://www.instagram.com/",
        "Origin": "https://www.instagram.com", "X-Requested-With": "XMLHttpRequest",
        "Sec-Fetch-Dest": "empty", "Sec-Fetch-Mode": "cors", "Sec-Fetch-Site": "same-origin",
        "Sec-Ch-Ua": cv["sec"], "Sec-Ch-Ua-Mobile": mob, "Sec-Ch-Ua-Platform": f'"{plt}"',
        "Connection": "keep-alive",
    }


async def _ig_api_get(path: str, params: dict = None) -> dict:
    import random as _rnd, time as _t
    if not _ig_accounts:
        _ig_accounts.extend(_ig_load_accounts())
    attempts = max(1, sum(1 for a in _ig_accounts if not a["is_dead"] and a["enabled"]))
    for _ in range(attempts):
        acc = _ig_get_best()
        if acc is None:
            break
        elapsed = _t.time() - acc["last_req_time"]
        gap = _rnd.uniform(_IG_COOLDOWN["per_req_min"], _IG_COOLDOWN["per_req_max"])
        if elapsed < gap:
            await asyncio.sleep(gap - elapsed)
        await asyncio.sleep(_rnd.uniform(_IG_COOLDOWN["human_min"], _IG_COOLDOWN["human_max"]))
        acc["last_req_time"] = _t.time()
        acc["hour_count"] += 1
        url = path if path.startswith("http") else f"{_IG_API_BASE}{path}"
        try:
            async with httpx.AsyncClient(timeout=30, follow_redirects=False) as client:
                resp = await client.get(url, headers=_ig_build_headers(acc), params=params)
        except Exception:
            continue
        s = resp.status_code
        if s in (301, 302): _ig_mark_dead(acc, "redirect"); continue
        if s == 429: _ig_set_cooldown(acc, "rate_limit"); continue
        if s in (401, 403): _ig_mark_dead(acc, f"http_{s}"); continue
        if s == 404: raise Exception("not_found")
        body = resp.text
        if "<html" in body or "login" in body[:200]: _ig_mark_dead(acc, "login page"); continue
        try:
            parsed = resp.json()
        except Exception:
            continue
        msg = parsed.get("message", "")
        if msg in ("checkpoint_required", "login_required"):
            _ig_set_cooldown(acc, "checkpoint_required"); continue
        acc["fail_count"] = max(0, acc["fail_count"] - 1)
        return parsed
    raise Exception("No working Instagram accounts. Admin: /igaddcookie")


_ig_accounts.extend(_ig_load_accounts())


def _get_ig_client():
    """Return a cached instagrapi Client using the best available pool cookie."""
    global _ig_client_instance, _ig_client_sessionid
    import re as _re
    from instagrapi import Client as _IgClient
    acc = _ig_get_best()
    if acc:
        _m = _re.search(r"sessionid=([^;]+)", acc["cookies"])
        sessionid = _m.group(1).strip() if _m else ""
    else:
        try:
            with open("bot/insta_cookies.json") as _f:
                _cj = json.load(_f)
            sessionid = _cj.get("sessionid", "").strip()
        except Exception:
            sessionid = ""
    if not sessionid:
        raise Exception("No Instagram sessionid available. Add cookies via /igaddcookie.")
    if _ig_client_instance is None or _ig_client_sessionid != sessionid:
        cl = _IgClient()
        cl.delay_range = [1, 3]
        cl.login_by_sessionid(sessionid)
        _ig_client_instance  = cl
        _ig_client_sessionid = sessionid
    return _ig_client_instance

