# ── Custom Emoji Pack Storage ──────────────────────────────────────────────
_EMOJI_PACKS_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), "emoji_packs.json")

def _load_emoji_packs() -> dict:
    """Load saved emoji packs from disk and merge into PREMIUM_EMOJI."""
    try:
        with open(_EMOJI_PACKS_FILE, encoding="utf-8") as f:
            packs: dict = json.load(f)
        for emoji_map in packs.values():
            PREMIUM_EMOJI.update(emoji_map)
        return packs
    except FileNotFoundError:
        return {}
    except Exception:
        return {}

def _save_emoji_packs(packs: dict) -> None:
    try:
        with open(_EMOJI_PACKS_FILE, "w", encoding="utf-8") as f:
            json.dump(packs, f, ensure_ascii=False, indent=2)
    except Exception:
        pass

# Auto-load on startup — populates PREMIUM_EMOJI immediately
_emoji_packs: dict = _load_emoji_packs()

def pe(emoji: str, fallback: str = None) -> str:
    """Return premium tg-emoji HTML by plain emoji char.
    Usage: pe('⚡')  pe('✅', 'OK')
    Falls back to plain emoji if no mapping found."""
    eid = PREMIUM_EMOJI.get(emoji)
    fb = fallback if fallback is not None else emoji
    if not eid:
        return fb
    return f"<tg-emoji emoji-id='{eid}'>{fb}</tg-emoji>"

# Matches virtually all Unicode emoji / pictograph codepoints + variation selectors.
# Used by _pe_all() to strip plain emojis that have no premium mapping.
_BARE_EMOJI_RE = re.compile(
    r'[\U0001F000-\U0001FFFF'   # Misc symbols, pictographs, emoticons, transport, etc.
    r'\U00002194-\U000027BF'    # Arrows (↩↪), Misc Technical, Dingbats, Enclosed Alphanum
    r'\U00002900-\U00002BFF'    # Supplemental Arrows, Math operators, Misc symbols
    r'\u3030\u303D\u3297\u3299' # CJK misc emoji
    r'\uFE00-\uFE0F'            # Variation Selectors
    r'\u20E3'                   # Combining enclosing keycap
    r'\U0001F1E0-\U0001F1FF'    # Regional Indicator letters (flags)
    r']+',
    re.UNICODE
)

def _pe_all(text: str) -> str:
    """Replace every plain emoji in text with its premium tg-emoji version.
    Emojis NOT in PREMIUM_EMOJI are stripped entirely so no plain emoji leaks through.
    Skips content already inside <tg-emoji> tags to prevent double-wrapping."""
    if not text:
        return text
    # Split on existing tg-emoji tags so we never double-wrap
    parts = re.split(r'(<tg-emoji[^>]*>.*?</tg-emoji>)', str(text), flags=re.DOTALL)
    out = []
    for i, part in enumerate(parts):
        if i % 2 == 1:          # already a tg-emoji block — leave it alone
            out.append(part)
        else:
            # Pass 1 — upgrade known emojis to premium versions
            for emoji, eid in PREMIUM_EMOJI.items():
                if emoji in part:
                    part = part.replace(
                        emoji, f"<tg-emoji emoji-id='{eid}'>{emoji}</tg-emoji>"
                    )
            # Pass 2 — leave any remaining plain emojis as-is (normal emoji).
            # They were not in PREMIUM_EMOJI so they render as regular emoji.
            out.append(part)
    return ''.join(out)

def _strip_btn_emoji(text: str) -> str:
    """Remove plain emoji chars from button text that have no premium mapping.
    Premium-mapped emojis are preserved (they render via MessageEntity.CUSTOM_EMOJI).
    Any other plain emoji is stripped so buttons never show normal emojis."""
    src = PREMIUM_EMOJI if 'PREMIUM_EMOJI' in globals() else _BTN_EMOJI_IDS
    # Protect premium emojis with unique null-byte placeholders
    saved, work = {}, text
    for idx, emoji_char in enumerate(src):
        if emoji_char in work:
            ph = f'\x00{idx}\x00'
            work = work.replace(emoji_char, ph)
            saved[ph] = emoji_char
    # Strip remaining bare emojis
    work = _BARE_EMOJI_RE.sub('', work)
    # Restore premium emojis
    for ph, emoji_char in saved.items():
        work = work.replace(ph, emoji_char)
    return work

