async def _l34k_search(client, query: str) -> dict:
    """Call L34K OSINT API — returns raw response dict."""
    try:
        r = await client.get(
            L34K_API_URL,
            params={"query": query, "key": L34K_API_KEY},
            headers={"User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"},
            timeout=30,
        )
        return safe_json(r, {})
    except Exception:
        return {}

def _fmt_l34k(data: dict, query: str, title: str = "🔍 OSINT Search") -> str:
    """Format L34K API response into a readable Telegram message."""
    SEP = "<tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji>" * 21
    DEV = "<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"
    if not data.get("status") or not data.get("data"):
        return bq(f"{title}\n{SEP}\n🔎 Query: {h(str(query))}\n\n❌ No data found.\n{SEP}\n{DEV}")
    sources = data["data"]
    lines = [title, SEP, f"🔎 Query: {h(str(query))}", ""]
    total_records = 0
    for src_val in sources.values():
        if not isinstance(src_val, dict):
            continue
        src_title = src_val.get("title", "Unknown Source")
        records   = src_val.get("records") or []
        if not records:
            continue
        total_records += len(records)
        lines.append(f"📂 <b>{h(src_title)}</b> ({len(records)} records)")
        for rec in records[:5]:
            parts = []
            for k, v in rec.items():
                sv = str(v).strip()
                if sv and sv.lower() not in ("none", "null", "", "0"):
                    parts.append(f"{h(str(k))}: {h(sv)}")
            if parts:
                lines.append("  • " + " | ".join(parts[:5]))
        if len(records) > 5:
            lines.append(f"  ... +{len(records)-5} more records")
        lines.append("")
    if total_records == 0:
        return bq(f"{title}\n{SEP}\n🔎 Query: {h(str(query))}\n\n❌ No records found.\n{SEP}\n{DEV}")
    lines += [SEP, f"📊 Total Records: {total_records}", DEV]
    result = "\n".join(lines)
    if len(result) > 3800:
        result = result[:3750] + f"\n...\n{SEP}\n{DEV}"
    return bq(result)

async def _napi(client, endpoint: str, param: str, value: str) -> dict:
    """Legacy wrapper — now routes through L34K OSINT API."""
    return await _l34k_search(client, value)

_FELIX_STRIP = re.compile(
    r"felix(?:daddy|bhai|_bhai|api)?|@felix\w*|felixdaddy|t\.me/felix\w*|"
    r"the[\s\-]last[\s\-]bypass[\s\-]api|last[_\-]bypass",
    re.IGNORECASE
)

def _strip_felix(text: str) -> str:
    """Remove Felix branding from any string while preserving real data."""
    out = _FELIX_STRIP.sub("", text)
    out = re.sub(r"\s{2,}", " ", out)
    return out.strip()

def _fmt_napi(data: dict, title: str, label: str, val: str) -> str:
    # Fields that are always branding/meta — never real data
    SKIP = {
        "success","error","message","msg","developer","dev","key",
        "apikey","_raw","time","result_count","credit","response_time",
        "timestamp","version","api","endpoint","query","input",
        "by","author","owner","powered_by","built_by","made_by","created_by",
        "credits_used","credit_used","felix","felixdaddy","felixbhai",
        "dev_id","devname","dev_name","owner_id","n",
    }
    lines = [f"{title}\n\n{label}: {h(str(val))}"]
    seen_keys: set = set()
    def _collect(d, depth=0):
        if not isinstance(d, dict) or depth > 4:
            return
        for k, v in d.items():
            kl = str(k).lower().strip()
            if kl in SKIP or kl in seen_keys:
                continue
            if isinstance(v, dict):
                _collect(v, depth + 1)
            elif isinstance(v, list):
                if v and isinstance(v[0], dict):
                    for item in v[:3]:
                        _collect(item, depth + 1)
                elif v:
                    sv = _strip_felix(", ".join(str(i) for i in v[:10] if str(i).strip()))
                    sv = sv.strip()
                    if sv and sv.lower() not in ("none","null","n/a","","false","0","undefined","nan"):
                        seen_keys.add(kl)
                        lines.append(f"• {h(str(k).replace('_',' ').replace('-',' ').title())}: {h(sv)}")
            else:
                sv = _strip_felix(str(v).strip())
                if sv and sv.lower() not in ("none","null","n/a","","false","false","0","undefined","nan"):
                    seen_keys.add(kl)
                    lines.append(f"• {h(str(k).replace('_',' ').replace('-',' ').title())}: {h(sv)}")
    _collect(data)
    if len(lines) <= 1:
        lines.append("❌ No data found.")
    result = "\n".join(lines)
    result = _strip_felix(result)
    result += "\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"
    return bq(result)

