def _fmt_num_lookup(data: dict, title: str, number: str,
                    pn_info: dict | None = None,
                    page: int = 1, per_page: int = _NUM_PER_PAGE) -> str:
    """Format L34K OSINT API response — paginated, all fields per record."""
    # SEP (premium tg-emoji) used ONLY at header + footer — max 2 per message
    SEP  = "<tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji>" * 21
    # Plain divider between records — no premium emoji consumed
    DIV  = "─" * 21
    DEV  = "<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"
    country = data.get("country", "")
    total   = data.get("total_records") or data.get("total_results") or 0
    records = data.get("records") or []
    total_pages = max(1, -(-len(records) // per_page)) if records else 1

    lines = [f"{title}", SEP]
    # ── Header — only on page 1 ──
    if page == 1:
        lines.append(f"📱 Number       : {h(str(number))}")
        if country:
            flag = "🇮🇳" if "india" in country.lower() else ("🇧🇩" if "bangladesh" in country.lower() else ("🇵🇰" if "pakistan" in country.lower() else "🌍"))
            lines.append(f"{flag} Country      : {h(country)}")
        lines.append(f"📊 Total Records: {h(str(total))}")
        if pn_info:
            if pn_info.get("carrier"):  lines.append(f"📡 Carrier      : {h(pn_info['carrier'])}")
            if pn_info.get("region"):   lines.append(f"🗺 Region       : {h(pn_info['region'])}")
            if pn_info.get("timezone"): lines.append(f"🕐 Timezone     : {h(pn_info['timezone'])}")
            if pn_info.get("numtype"):  lines.append(f"📶 Type         : {h(pn_info['numtype'])}")
            valid = pn_info.get("valid")
            if valid is not None:       lines.append(f"✅ Valid        : {'Yes ✅' if valid else 'No ❌'}")
    if not records:
        lines += [SEP, "❌ No records found in database.", SEP, DEV]
        return bq("\n".join(lines))
    # ── Page slice ──
    start = (page - 1) * per_page
    end   = start + per_page
    page_records = records[start:end]
    for i, rec in enumerate(page_records, start + 1):
        lines.append(DIV)          # ← plain divider, zero premium emoji cost
        lines.append(f"📋 Record #{i}")
        for field, val in rec.items():
            fl = field.lower().strip()
            if fl in ("number", "made_by") or not val:
                continue
            sv = str(val).strip().lstrip("`").rstrip("`").strip()
            if not sv or sv.lower() in ("n/a", "none", "null", ""):
                continue
            icon = _NUMFIELD_ICONS.get(fl, "•")
            label = field.replace("_", " ").title()
            lines.append(f"{icon} {label:<14}: {h(sv)}")
    # Footer uses SEP once
    lines += [SEP, f"📄 Page {page}/{total_pages}  •  {DEV}"]
    return bq("\n".join(lines))


def _build_numpage_kb(numtype: str, number: str, page: int, total_pages: int) -> InlineKeyboardMarkup:
    """Build Prev / Page indicator / Next keyboard for number lookup pagination.
    numtype: 'ind' or 'bd'
    """
    row = []
    if page > 1:
        row.append(SBtn("👈 Prev",
                        style="primary",
                        callback_data=f"numpage|{numtype}|{number}|{page-1}",
                        icon_custom_emoji_id="5780626368068851417"))
    row.append(SBtn(f"📄 {page}/{total_pages}",
                    style="success",
                    callback_data="noop"))
    if page < total_pages:
        row.append(SBtn("Next ➡️",
                        style="danger",
                        callback_data=f"numpage|{numtype}|{number}|{page+1}",
                        icon_custom_emoji_id="6082250599733141850"))
    return InlineKeyboardMarkup([row, [SBtn("🏠 Main Menu", style="success", callback_data="back_home")]])


