_SPAM_WINDOW  = 2.0   # seconds between clicks to count as rapid
_SPAM_NUKE    = 8     # rapid hits that trigger the initial 30s block
_SPAM_EXTEND  = 30.0  # seconds added per attempt during initial block
_SPAM_HARD_BLOCK     = 600.0  # 10 minute hard lock
_SPAM_HARD_THRESHOLD = 4      # attempts during block before hard lock kicks in

