# ── AI Ignore List (owner can mute specific users from AI) ──
AI_IGNORE_FILE = "bot/ai_ignored.json"

def _load_ai_ignored() -> set:
    try:
        with open(AI_IGNORE_FILE) as f:
            return set(str(x) for x in json.load(f))
    except Exception:
        return set()

def _save_ai_ignored(s: set):
    os.makedirs("bot", exist_ok=True)
    with open(AI_IGNORE_FILE, "w") as f:
        json.dump(list(s), f)

_ai_ignored_users: set = _load_ai_ignored()

