async def log_all_messages(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message or not update.effective_user:
        return
    uid = str(update.effective_user.id)
    if is_owner(uid):
        return
    users_data = load_users()
    if users_data.get(uid, {}).get("is_admin"):
        return

    chat_type = update.effective_chat.type
    text = update.message.text or update.message.caption or ""

    # In groups, only log when the bot is actually involved (mention or reply to bot)
    if chat_type in ("group", "supergroup"):
        is_mention = _bot_username and f"@{_bot_username}" in (text or "").lower()
        is_reply_to_bot = (
            update.message.reply_to_message is not None and
            update.message.reply_to_message.from_user is not None and
            update.message.reply_to_message.from_user.id == context.bot.id
        )
        if not is_mention and not is_reply_to_bot:
            return
        chat_name = update.effective_chat.title or "Group"
        src = f"👥 Group: {chat_name}"
    else:
        src = "💬 Private DM"

    if text.startswith("/"):
        cmd = text.split()[0]
        action_type = f"⌨️ Command: {cmd}  [{src}]"
    else:
        action_type = f"💬 Message  [{src}]"

    asyncio.create_task(
        send_user_log(context.bot, update.effective_user, action_type, text or "[non-text]")
    )


def is_paused() -> bool:
    return os.path.exists(PAUSE_FILE)

def get_user(users, uid, username="", first_name=""):
    uid = str(uid)
    if uid not in users:
        users[uid] = {
            "credits": 3, "banned": False,
            "is_admin": is_owner(uid),
            "last_claim": None, "username": username,
            "first_name": first_name,
        }
    else:
        if username:
            users[uid]["username"] = username
        if first_name:
            users[uid]["first_name"] = first_name
    return users[uid], uid

def find_user_by_username(users, raw):
    raw = raw.lstrip("@").lower()
    for uid, u in users.items():
        if (u.get("username") or "").lower() == raw:
            return u, uid
    return None, None

def is_owner(uid):
    return str(uid) in (str(ADMIN_ID), str(OWNER_ID))

def is_premium(user):
    if user.get("is_admin"):
        return True
    if not user.get("premium"):
        return False
    until = user.get("premium_until")
    if until is None:
        return True  # lifetime
    return datetime.now() < datetime.fromisoformat(until)

def get_role(user, uid):
    if is_owner(uid):
        return "<tg-emoji emoji-id='6255570556104477305'>😎</tg-emoji> OWNER"
    if user.get("is_admin"):
        return "<tg-emoji emoji-id='6253517256794311831'>😎</tg-emoji> ADMIN"
    if is_premium(user):
        return "💎 PREMIUM"
    return "<tg-emoji emoji-id='5166063676687385916'>👤</tg-emoji> USER"

def credit_display(user):
    if user.get("is_admin") or is_premium(user):
        return "∞"
    return str(user["credits"])

def get_user_level(user, uid=""):
    """Return (level_num, level_badge, progress_bar) based on credits + referrals."""
    if is_owner(uid):
        return 99, "<tg-emoji emoji-id='6255570556104477305'>😎</tg-emoji> OWNER LVL MAX", "██████████ 100%"
    if user.get("is_admin"):
        return 50, "<tg-emoji emoji-id='6253517256794311831'>😎</tg-emoji> ADMIN LVL MAX", "██████████ 100%"

    refers  = user.get("total_refers", 0) or 0
    credits = user.get("credits", 0) or 0
    score   = refers * 10 + credits

    LEVELS = [
        (0,    1,  "🆕 Newbie",    0,    10),
        (10,   2,  "🌱 Beginner",  10,   25),
        (25,   3,  "⭐ Rookie",    25,   50),
        (50,   4,  "🥉 Bronze",    50,   100),
        (100,  5,  "🥈 Silver",    100,  200),
        (200,  6,  "🥇 Gold",      200,  400),
        (400,  7,  "💎 Platinum",  400,  700),
        (700,  8,  "💫 Diamond",   700,  1200),
        (1200, 9,  "🔥 Master",    1200, 2500),
        (2500, 10, "⚡ Legendary", 2500, 2500),
    ]

    level_num, badge, low, high = 1, "🆕 Newbie", 0, 10
    for min_score, num, lbl, lo, hi in LEVELS:
        if score >= min_score:
            level_num, badge, low, high = num, lbl, lo, hi

    # Progress bar
    if level_num == 10:
        bar = "██████████ MAX"
    else:
        span    = max(1, high - low)
        filled  = min(10, int((score - low) / span * 10))
        bar     = "█" * filled + "░" * (10 - filled) + f" {min(100, int((score-low)/span*100))}%"

    return level_num, badge, bar


def _needs_charge(user):
    """True only when this user should be charged credits (not admin, not premium)."""
    return not user.get("is_admin") and not is_premium(user)

def spend_credit(users, uid):
    uid = str(uid)
    if users[uid].get("is_admin") or is_premium(users[uid]):
        return True
    if users[uid]["credits"] <= 0:
        return False
    users[uid]["credits"] -= 1
    save_users(users)
    return True

def has_credits(users, uid):
    uid = str(uid)
    if users[uid].get("is_admin") or is_premium(users[uid]):
        return True
    return users[uid]["credits"] > 0

def is_autoapprove(chat_id):
    cfg = load_config()
    return str(chat_id) in cfg.get("autoapprove_chats", [])

def safe_json(r, default=None):
    if default is None:
        default = {}
    try:
        if not r.text.strip():
            return default
        return r.json()
    except Exception:
        return default

def h(text):
    return _html.escape(str(text))

def bq(text):
    return f"<blockquote><b>{text}</b></blockquote>"

_TG_EMOJI_RE = re.compile(r"<tg-emoji[^>]*>(.*?)</tg-emoji>", re.DOTALL)
def strip_tg_emoji(text: str) -> str:
    """Remove all <tg-emoji> tags, keeping only the fallback character inside.
    Regular bots cannot send custom emoji — Telegram returns Document_invalid."""
    return _TG_EMOJI_RE.sub(r"\1", text)

def _ld(action: str, emoji="⌛", sub="Please wait...") -> str:
    """Static loading message (initial frame before animation starts) — HTML."""
    first_emoji = emoji[0] if isinstance(emoji, (list, tuple)) else emoji
    first_sub   = sub[0]   if isinstance(sub,   (list, tuple)) else sub
    return (
        f"<blockquote>"
        f"<b>{first_emoji} {action}</b>\n"
        f"▱▱▱▱▱▱▱▱▱▱\n"
        f"<i>{first_sub}</i>"
        f"</blockquote>"
    )

# ── Animated loading frames (progress bar bounces back and forth) ──
_ANIM_FRAMES = [
    "▰▱▱▱▱▱▱▱▱▱",
    "▰▰▰▱▱▱▱▱▱▱",
    "▰▰▰▰▰▱▱▱▱▱",
    "▰▰▰▰▰▰▰▱▱▱",
    "▰▰▰▰▰▰▰▰▰▱",
    "▰▰▰▰▰▰▰▰▰▰",
    "▱▰▰▰▰▰▰▰▰▰",
    "▱▱▱▰▰▰▰▰▰▰",
    "▱▱▱▱▱▰▰▰▰▰",
    "▱▱▱▱▱▱▱▰▰▰",
    "▱▱▱▱▱▱▱▱▱▰",
    "▱▱▱▱▱▱▱▱▱▱",
]

async def _anim_start(msg, action: str, emoji="⌛", sub="Please wait...") -> "asyncio.Task":
    """Start animating a loading message. Emoji list cycles each frame. Cancel task to stop."""
    _emojis = emoji if isinstance(emoji, (list, tuple)) else [emoji]
    _subs   = sub   if isinstance(sub,   (list, tuple)) else [sub]
    async def _loop():
        i = 0
        while True:
            try:
                await asyncio.sleep(1.0)
                frame     = _ANIM_FRAMES[i % len(_ANIM_FRAMES)]
                cur_emoji = _emojis[i % len(_emojis)]
                cur_sub   = _subs[i   % len(_subs)]
                safe_emoji = strip_tg_emoji(cur_emoji) if "<tg-emoji" in str(cur_emoji) else cur_emoji
                await msg.edit_text(
                    f"<blockquote><b>{safe_emoji} {action}</b>\n{frame}\n<i>{cur_sub}</i></blockquote>",
                    parse_mode=ParseMode.HTML
                )
                i += 1
            except asyncio.CancelledError:
                break
            except Exception:
                i += 1
                continue
    return asyncio.create_task(_loop())

