# ── Random emoji reactions (like Baka bot — reacts to user messages sometimes) ──
_REACT_PREMIUM_ID = "6147464060305676048"

async def _react_random(update: Update, chance: float = 0.40) -> None:
    """React to the user's message with a premium custom emoji (~40% chance by default)."""
    if random.random() > chance:
        return
    try:
        await update.message.set_reaction([ReactionTypeCustomEmoji(custom_emoji_id=_REACT_PREMIUM_ID)])
    except Exception:
        pass

def fmt_ai(text: str, max_lines: int = 30) -> str:
    """Clean AI markdown to plain text."""
    t = str(text)
    # Strip markdown formatting → plain text
    t = re.sub(r'\*\*(.+?)\*\*',   r'\1', t, flags=re.DOTALL)
    t = re.sub(r'__(.+?)__',       r'\1', t, flags=re.DOTALL)
    t = re.sub(r'\*([^*\n]+?)\*',  r'\1', t)
    t = re.sub(r'_([^_\n]+?)_',    r'\1', t)
    t = re.sub(r'`([^`\n]+)`',     r'\1', t)
    t = re.sub(r'#{1,6}\s+',       '',    t)
    t = re.sub(r'\n{3,}',          '\n\n', t)
    t = t.strip()
    lines = t.splitlines()
    if len(lines) > max_lines:
        t = "\n".join(lines[:max_lines])
    return t

def _ai_body(text: str) -> str:
    """Format AI response body — plain text cleanup + _sc_cap style per line.
    Latin first letters become bold (𝐇ello); Bengali/other text is untouched."""
    raw = fmt_ai(text)
    return "\n".join(_sc_cap(line) if line.strip() else line for line in raw.split("\n"))

def schedule_delete(msg):
    asyncio.create_task(_delete_later(msg))

async def _delete_later(msg):
    # Build a per-user tracking key so only ONE response per user is alive at a time.
    # In private chats: chat.id == user.id — perfect 1-to-1 key.
    # In groups: use chat.id + the original requester's id (from reply_to_message).
    try:
        chat_id = msg.chat.id
        orig_uid = None
        if msg.reply_to_message and msg.reply_to_message.from_user:
            orig_uid = msg.reply_to_message.from_user.id
        track_key = f"{chat_id}_{orig_uid or 'bot'}"

        # Delete the previous tracked response for this user immediately
        old = _schedule_tracked.get(track_key)
        if old and old.message_id != msg.message_id:
            try:
                await old.delete()
            except Exception:
                pass
        _schedule_tracked[track_key] = msg
    except Exception:
        track_key = None

    # Wait 3 minutes, then delete this message
    await asyncio.sleep(DELETE_AFTER)
    try:
        await msg.delete()
    except Exception:
        pass

    # Clean up tracker if this is still the tracked message
    try:
        if track_key and _schedule_tracked.get(track_key) is msg:
            del _schedule_tracked[track_key]
    except Exception:
        pass

def delete_query_msg(query):
    asyncio.create_task(_delete_msg(query.message))

async def set_active_msg(uid_str: str, msg):
    """Track the latest panel message for a user; delete the previous one."""
    old = _active_msg.get(uid_str)
    if old:
        try:
            await old.delete()
        except Exception:
            pass
    _active_msg[uid_str] = msg

def clear_active_msg(uid_str: str):
    """Remove active message tracking for a user (without deleting)."""
    _active_msg.pop(uid_str, None)

async def _check_maintenance(update: Update) -> bool:
    """Returns True (and notifies user) if bot is in maintenance mode."""
    if is_paused() and not is_owner(update.effective_user.id):
        sent = await update.message.reply_text(
            bq("🔧 Maintenance Mode\n\nBot is under maintenance. Please try again later.\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"),
            parse_mode=ParseMode.HTML
        )
        schedule_delete(sent)
        return True
    return False

async def _check_feature(update: Update, feature: str) -> bool:
    """Returns True (and notifies user) if feature is disabled for non-admins.
    Bot admins can always use any feature regardless of its enabled/disabled state."""
    if not is_enabled(feature):
        uid = str(update.effective_user.id)
        # Allow owner and bot admins to bypass feature restrictions
        if is_owner(uid):
            return False
        users = load_users()
        if users.get(uid, {}).get("is_admin"):
            return False
        sent = await update.message.reply_text(
            bq("🚫 Feature Disabled\n\nThis feature has been disabled by the admin.\n\nUse /start to see available features.\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"),
            parse_mode=ParseMode.HTML
        )
        schedule_delete(sent)
        return True
    return False

async def _check_banned(update: Update, user: dict) -> bool:
    """Returns True (and notifies user) if user is banned."""
    if user.get("banned"):
        sent = await update.message.reply_text(
            bq("⛔ You are banned from using this bot.\n\nContact admin if you think this is a mistake."),
            parse_mode=ParseMode.HTML
        )
        schedule_delete(sent)
        return True
    return False

async def _check_credits(update: Update, user: dict) -> bool:
    """Returns True (and notifies user) if user has no credits."""
    if not user.get("is_admin") and user.get("credits", 0) <= 0:
        sent = await update.message.reply_text(
            bq("❌ Insufficient Credits\n\nUse /start to claim your daily credits (+3).\n\n💡 Or use /ai — I can do it for you!\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"),
            parse_mode=ParseMode.HTML
        )
        schedule_delete(sent)
        return True
    return False

