# ── Player2 MCP helpers ──
async def mcp_init(client: httpx.AsyncClient) -> str | None:
    try:
        resp = await client.post(
            MCP_URL, headers=HEADERS_P2,
            json={
                "jsonrpc": "2.0", "id": 1,
                "method": "initialize",
                "params": {
                    "protocolVersion": "2024-11-05",
                    "capabilities": {},
                    "clientInfo": {"name": "shuvo-bot", "version": "2.0"},
                },
            },
            timeout=30,
        )
        return resp.headers.get("mcp-session-id")
    except Exception:
        return None

async def mcp_call(client: httpx.AsyncClient, session_id: str, tool: str, params: dict) -> dict:
    headers = {**HEADERS_P2, "mcp-session-id": session_id}
    resp = await client.post(
        MCP_URL, headers=headers,
        json={
            "jsonrpc": "2.0", "id": 2,
            "method": "tools/call",
            "params": {"name": tool, "arguments": params},
        },
        timeout=60,
    )
    data = resp.json()
    result = data.get("result") or {}
    content = result.get("content") or []
    if content and isinstance(content, list):
        for item in content:
            if item.get("type") == "text":
                try:
                    return json.loads(item["text"])
                except Exception:
                    return {"raw": item["text"]}
    return data

async def mcp_poll_job(client: httpx.AsyncClient, session_id: str,
                       check_tool: str, job_id: str,
                       interval: int = 10, max_wait: int = 300) -> dict:
    elapsed = 0
    while elapsed < max_wait:
        await asyncio.sleep(interval)
        elapsed += interval
        result = await mcp_call(client, session_id, check_tool, {"job_id": job_id})
        status = result.get("status", "")
        if status in ("completed", "succeeded", "failed", "done"):
            return result
    return {"status": "timeout"}

def is_quota_error(result: dict) -> bool:
    raw = str(result).lower()
    return any(k in raw for k in ("quota", "limit", "exceeded", "rate", "insufficient",
                                   "no credit", "credits", "balance"))

async def generate_image_player2(prompt: str) -> str | None:
    async with httpx.AsyncClient() as client:
        session_id = await mcp_init(client)
        if not session_id:
            return None
        result = await mcp_call(client, session_id, "generate_image", {"prompt": prompt})
        if is_quota_error(result):
            return "QUOTA"
        return result.get("image_url") or result.get("url") or None

async def generate_image_fallback(prompt: str) -> bytes:
    return await _fetch_image_bytes(prompt)

async def _send_audio_robust(context, chat_id: int, url: str, caption: str):
    try:
        await context.bot.send_audio(chat_id=chat_id, audio=url,
                                     caption=caption, parse_mode=ParseMode.MARKDOWN_V2)
        return
    except Exception:
        pass
    try:
        async with httpx.AsyncClient(follow_redirects=True) as dl:
            r = await dl.get(url, timeout=90)
            bio = BytesIO(r.content)
            bio.name = "music.mp3"
        await context.bot.send_audio(chat_id=chat_id, audio=bio,
                                     caption=caption, parse_mode=ParseMode.MARKDOWN_V2)
        return
    except Exception:
        pass
    try:
        await context.bot.send_document(chat_id=chat_id, document=url,
                                        caption=caption, parse_mode=ParseMode.MARKDOWN_V2)
    except Exception:
        await context.bot.send_message(chat_id=chat_id,
                                       text=f"🎵 Music ready\\! [Download here]({url})",
                                       parse_mode=ParseMode.MARKDOWN_V2)

def _esc(text: str) -> str:
    for ch in r"\_*[]()~`>#+-=|{}.!":
        text = text.replace(ch, f"\\{ch}")
    return text

def get_required_channels():
    cfg = load_config()
    return cfg.get("required_channels", [])

def _get_channel_ident(ch: dict):
    """Priority: chat_id (int) > @username. Returns None if nothing usable."""
    chat_id = ch.get("chat_id")
    if chat_id:
        try:
            return int(chat_id)
        except (ValueError, TypeError):
            pass
    uname = ch.get("username", "").strip()
    if uname and not uname.startswith("http"):
        return uname if uname.startswith("@") else f"@{uname}"
    return None

async def check_force_join(bot, user_id: int) -> list:
    """
    Always does a live get_chat_member check for every channel.
    Returns list of channel dicts the user has NOT joined.
    Also auto-caches chat_id into config if it was missing.
    """
    cfg = load_config()
    channels = cfg.get("required_channels", [])
    unjoined = []
    cfg_dirty = False

    for i, ch in enumerate(channels):
        ident = _get_channel_ident(ch)

        if ident is None:
            # No identifier — block user, admin needs to fix this entry
            unjoined.append(ch)
            continue

        try:
            member = await bot.get_chat_member(ident, user_id)
            if member.status in ("left", "kicked", "banned"):
                unjoined.append(ch)
        except Exception as e:
            err = str(e).lower()
            if any(x in err for x in ("chat not found", "bot is not", "forbidden",
                                       "user not found", "participant_id_invalid")):
                unjoined.append(ch)
            # Unknown error → give benefit of doubt (don't punish user)

        # Auto-cache chat_id if missing
        if not ch.get("chat_id"):
            try:
                chat = await bot.get_chat(ident)
                cfg["required_channels"][i]["chat_id"] = chat.id
                cfg_dirty = True
            except Exception:
                pass

    if cfg_dirty:
        save_config(cfg)

    return unjoined

async def check_force_join_verify(bot, user_id: int) -> list:
    """Same as check_force_join — used for the Verify button. Always live."""
    return await check_force_join(bot, user_id)

def force_join_keyboard(unjoined: list) -> InlineKeyboardMarkup:
    """
    One JOIN button per unjoined channel.
    Button label format: "🔔 JOIN {title}"  e.g. "🔔 JOIN SHUVO MODS"
    Last button: ✅ verify.
    """
    rows = []
    for ch in unjoined:
        title = ch.get("title", "Channel")
        link = ch.get("link", "").strip()
        if not link or not link.startswith("http"):
            uname = ch.get("username", "").lstrip("@")
            link = f"https://t.me/{uname}" if uname else "https://t.me"
        rows.append([SBtn(f"🔔 JOIN {title}", style="danger", url=link)])
    rows.append([SBtn("✅ Joined All — Verify Now", style="success", callback_data="verify_join")])
    return InlineKeyboardMarkup(rows)

async def is_group_member(bot, user_id):
    try:
        member = await bot.get_chat_member(REQUIRED_GROUP, user_id)
        return member.status not in ("left", "kicked", "banned")
    except Exception:
        return False


async def _fetch_userid_info(client, query: str, is_username: bool = False) -> dict:
    """
    API: felixcaller-ze0u.onrender.com (TG ID/username → phone)
    Dev: @Shuvobhai
    """
    url = USERNAME_API_URL.format(query) if is_username else USERID_API_URL.format(query)

    def _parse_abdulapi(data: dict) -> list:
        """Parse API response — supports ShadowOSINT, felix, new (username-usrid-to-num) and old (abdulstoreapi) format."""
        records = []

        # ── ShadowOSINT flat format: shadowosintapi.co08.art ──
        if data.get("status") is True and data.get("phone") and not isinstance(data.get("data"), dict):
            num = str(data.get("phone", "")).strip()
            cc  = str(data.get("country_code", "")).strip()
            if num:
                cc_digits = cc.lstrip("+")
                if cc_digits and num.startswith(cc_digits):
                    num = num[len(cc_digits):]
            records.append({
                "phone":        num,
                "country":      str(data.get("country", "")).strip(),
                "country_code": cc,
                "first_name":   str(data.get("first_name", "") or "").strip(),
                "username":     str(data.get("username", "") or "").strip().lstrip("@"),
                "tg_id":        str(data.get("tg_id", "") or "").strip(),
                "total_groups": None,
                "source":       "ShadowOSINT",
            })
            return records

        # ── Felix API format: felixcaller-ze0u.onrender.com ──
        if isinstance(data.get("location"), dict) and data["location"].get("phone_number"):
            loc  = data["location"]
            uinf = data.get("username_info") or {}
            num  = str(loc.get("phone_number", "")).strip()
            cc   = str(loc.get("country_code", "")).strip()
            if num:
                cc_digits = cc.lstrip("+")
                if cc_digits and num.startswith(cc_digits):
                    num = num[len(cc_digits):]
                records.append({
                    "phone":        num,
                    "country":      str(loc.get("country", "")).strip(),
                    "country_code": cc,
                    "first_name":   str(uinf.get("name", "") or "").strip(),
                    "username":     str(uinf.get("username", "") or "").strip().lstrip("@"),
                    "tg_id":        str(uinf.get("telegram_id", "") or "").strip(),
                    "total_groups": None,
                    "source":       "FelixAPI",
                })
            return records

        # ── New API format ──
        if data.get("status") is True and isinstance(data.get("data"), dict):
            for source_val in data["data"].values():
                if not isinstance(source_val, dict):
                    continue
                for rec in source_val.get("records", []):
                    num = str(rec.get("phone", "")).strip()
                    cc  = str(rec.get("country_code", "")).strip()
                    if num:
                        if cc:
                            cc_digits = cc.lstrip("+")
                            if num.startswith(cc_digits):
                                num = num[len(cc_digits):]
                        records.append({
                            "phone":        num,
                            "country":      str(rec.get("country", "")).strip(),
                            "country_code": cc,
                            "first_name":   str(rec.get("first_name", "") or "").strip(),
                            "total_groups": None,
                            "source":       "CyberBanner",
                        })
            return records

        # ── Old API fallback ──
        d = data.get("data") or {}
        if isinstance(d, dict) and d.get("found"):
            num = str(d.get("number", "")).strip()
            cc  = str(d.get("country_code", "")).strip()
            if num:
                if cc:
                    cc_digits = cc.lstrip("+")
                    if num.startswith(cc_digits):
                        num = num[len(cc_digits):]
                records.append({
                    "phone":        num,
                    "country":      str(d.get("country", "")).strip(),
                    "country_code": cc,
                    "first_name":   str(d.get("first_name", "") or "").strip(),
                    "total_groups": None,
                    "source":       "AbdulStore",
                })
        return records

    try:
        r = await client.get(url,
                             headers={"User-Agent": "Mozilla/5.0"},
                             timeout=12)
        data = safe_json(r, {})
        records = _parse_abdulapi(data)
        if records:
            best = records[0]
            return {
                "phone":        best["phone"],
                "country":      best["country"],
                "country_code": best["country_code"],
                "first_name":   best["first_name"],
                "total_groups": best["total_groups"],
                "all_records":  records,
            }
    except Exception:
        pass

    # Nothing found
    return {
        "phone": "", "country": "", "country_code": "",
        "first_name": "", "total_groups": None, "all_records": [],
    }


