# POWERED AI — Groq with full tool calling
# ══════════════════════════════════════════════

def _is_queue_full(data: dict) -> bool:
    """Check if pollinations.ai returned a queue-full error."""
    err = data.get("error", {})
    err_msg = (err.get("message", "") if isinstance(err, dict) else str(err)).lower()
    return "queue" in err_msg and ("full" in err_msg or "queued" in err_msg)

async def _ai_post_with_retry(client: httpx.AsyncClient, payload: dict, tools: list | None = None) -> dict:
    """POST to pollinations.ai with fallback model retry on queue-full."""
    models_to_try = [GROQ_MODEL] + _AI_FALLBACK_MODELS
    last_data = {}
    for i, model in enumerate(models_to_try):
        body = {**payload, "model": model}
        if tools:
            body["tools"] = tools
            body["tool_choice"] = "auto"
        try:
            r = await client.post(
                GROQ_API_BASE,
                headers={"Authorization": f"Bearer {GROQ_API_KEY}", "Content-Type": "application/json"},
                json=body,
                timeout=28
            )
            last_data = safe_json(r)
        except Exception:
            last_data = {}
            continue
        if _is_queue_full(last_data):
            if i < len(models_to_try) - 1:
                await asyncio.sleep(0.8)
            continue
        # Got a usable response (even if it's an error we can show)
        return last_data
    return last_data  # return last attempt regardless


async def ai_groq_powered(uid: str, user_message: str, users: dict, update: Update = None) -> dict:
    """
    Super-powered AI with tool calling.
    Returns dict: {
        'text': str (AI reply),
        'tool_result_html': str or None,
        'tool_name': str or None,
        'credit_spent': bool,
        'image_url': str or None,
    }
    """
    global _ai_history
    if not GROQ_API_KEY:
        return {"text": "❌ AI service unavailable. Try again later.", "tool_result_html": None, "tool_name": None, "credit_spent": False, "image_url": None}

    history = _ai_history.get(uid, [])
    history.append({"role": "user", "content": user_message})
    if len(history) > 10:
        history = history[-10:]

    messages = [{"role": "system", "content": AI_SYSTEM_PROMPT}] + history

    try:
        async with httpx.AsyncClient(timeout=30) as client:
            # First call: let AI decide if it wants to use a tool
            data = await _ai_post_with_retry(client, {"messages": messages, "max_tokens": 320}, tools=GROQ_TOOLS)
            choice = data.get("choices", [{}])[0]
            msg = choice.get("message", {})
            tool_calls = msg.get("tool_calls")

            # No tool call → plain AI response
            if not tool_calls:
                reply = msg.get("content", "")
                if not reply:
                    err_obj = data.get("error", {})
                    err_msg = err_obj.get("message", "Unknown error") if isinstance(err_obj, dict) else str(err_obj)
                    err_code = err_obj.get("code", 0) if isinstance(err_obj, dict) else 0
                    if any(x in str(err_msg).lower() for x in ("user not found", "auth", "401", "invalid", "api key", "unauthorized", "no auth")):
                        friendly = "AI service error. Try again later! 🌸 Dev: @Shuvobhai"
                    elif "rate" in str(err_msg).lower() or err_code == 429:
                        friendly = "AI is busy right now — rate limit hit. Try again in a moment~ 😅"
                    elif "model" in str(err_msg).lower():
                        friendly = "AI model unavailable right now. Try again later! 🌸"
                    else:
                        friendly = f"AI thik thak respond korte parteche na 😢 Try again!\n({h(str(err_msg)[:100])})"
                    return {"text": f"❌ {friendly}", "tool_result_html": None, "tool_name": None, "credit_spent": False, "image_url": None}
                history.append({"role": "assistant", "content": reply})
                _ai_history[uid] = history[-10:]
                return {"text": reply, "tool_result_html": None, "tool_name": None, "credit_spent": False, "image_url": None}

            # Tool call detected!
            tc = tool_calls[0]
            tool_name = tc.get("function", {}).get("name", "")
            tool_args_raw = tc.get("function", {}).get("arguments", "{}")
            try:
                tool_args = json.loads(tool_args_raw)
            except Exception:
                tool_args = {}
            tool_call_id = tc.get("id", "call_0")

            # Credit check for paid tools
            credit_spent = False
            if tool_name not in FREE_AI_TOOLS:
                if not has_credits(users, uid):
                    history.append({"role": "assistant", "content": "❌ Insufficient credits to execute this lookup."})
                    _ai_history[uid] = history[-10:]
                    return {
                        "text": "❌ Insufficient credits!\n\nAI er through lookup korte 1 credit laage. /start koro daily credit claim korte.",
                        "tool_result_html": None, "tool_name": tool_name, "credit_spent": False, "image_url": None
                    }
                spend_credit(users, uid)
                credit_spent = True

            # Execute the tool
            tool_html, tool_plain, is_image = await execute_ai_tool(tool_name, tool_args, uid, users)

            # Send tool result back to AI for a final summary
            messages_with_tool = messages + [
                {"role": "assistant", "content": "", "tool_calls": tool_calls},
                {
                    "role": "tool",
                    "tool_call_id": tool_call_id,
                    "content": tool_plain
                }
            ]
            data2 = await _ai_post_with_retry(client, {"messages": messages_with_tool, "max_tokens": 320})
            final_reply = data2.get("choices", [{}])[0].get("message", {}).get("content", "")
            if not final_reply:
                final_reply = "✅ Done! Result is shown above."

            # Update history
            history.append({"role": "assistant", "content": f"[Used tool: {tool_name}] {final_reply}"})
            _ai_history[uid] = history[-10:]

            return {
                "text": final_reply,
                "tool_result_html": tool_html,
                "tool_name": tool_name,
                "credit_spent": credit_spent,
                "image_url": tool_args.get("prompt") if is_image else None,
                "is_image_tool": is_image,
                "image_prompt": tool_args.get("prompt", "") if is_image else "",
            }

    except Exception as e:
        return {"text": f"❌ AI error: {str(e)[:200]}", "tool_result_html": None, "tool_name": None, "credit_spent": False, "image_url": None}


async def ai_groq(uid: str, user_message: str) -> str:
    """Simple AI call without tool calling (used for admin diagnose, group AI etc.)"""
    global _ai_history
    if not GROQ_API_KEY:
        return "❌ AI service unavailable. Try again later."
    history = _ai_history.get(uid, [])
    history.append({"role": "user", "content": user_message})
    if len(history) > 10:
        history = history[-10:]
    messages = [{"role": "system", "content": AI_SYSTEM_PROMPT}] + history
    try:
        async with httpx.AsyncClient(timeout=30) as client:
            data = await _ai_post_with_retry(client, {"messages": messages, "max_tokens": 320})
            reply = data.get("choices", [{}])[0].get("message", {}).get("content", "")
            if not reply:
                err_obj = data.get("error", {})
                err_msg = err_obj.get("message", "Unknown error") if isinstance(err_obj, dict) else str(err_obj)
                if _is_queue_full(data):
                    return "❌ AI busy ache ekhon 😅 Ektu por try koro!"
                if any(x in str(err_msg).lower() for x in ("user not found", "auth", "401", "invalid", "api key", "unauthorized", "no auth")):
                    return "❌ AI service error. Try again later! 🌸"
                return f"❌ AI thik respond korte parteche na 😢 Try again! ({str(err_msg)[:80]})"
            history.append({"role": "assistant", "content": reply})
            _ai_history[uid] = history[-10:]
            return reply
    except Exception as e:
        return f"❌ AI error: {str(e)[:200]}"


async def _send_ai_powered_response(update: Update, uid: str, users: dict, user_message: str):
    """Send the full AI powered response including tool results to the user."""
    # ── Owner bypass: owner always gets full access ──
    _is_owner_req = is_owner(uid)

    # ── AI ignore check: skip silently if user is ignored by owner ──
    if not _is_owner_req and str(uid) in _ai_ignored_users:
        return  # silently ignore — no response at all

    # React to user's message randomly (like Baka bot ~40% of the time)
    asyncio.create_task(_react_random(update, chance=0.40))

    sent      = await update.message.reply_text(_ld("SHUVO AI", ["🤖","🧠","💭","✨","🌸","⚡"], ["Thinking...","Processing query...","Running tools...","Generating response...","Almost done..."]), parse_mode=ParseMode.HTML)
    _anim     = await _anim_start(sent, "SHUVO AI", ["🤖","🧠","💭","✨","🌸","⚡"], ["Thinking...","Processing query...","Running tools...","Generating response...","Almost done..."])

    result    = await ai_groq_powered(uid, user_message, users, update)

    _anim.cancel()
    await asyncio.sleep(0.05)   # let cancel propagate before editing

    try:
        # If there's a tool result, show it first
        if result.get("tool_result_html"):
            tool_name = result.get("tool_name", "")
            credit_note = " (1cr)" if result.get("credit_spent") else " (free)"

            # Check if it's an image generation tool
            if result.get("is_image_tool"):
                prompt = result.get("image_prompt", "")
                try:
                    img_bytes = await _fetch_image_bytes(prompt)
                    await sent.delete()
                    photo_sent = await update.message.reply_photo(
                        photo=img_bytes,
                        caption=f"🎨 AI Image\n{h(prompt[:200])}\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> @Shuvobhai"
                    )
                    schedule_delete(photo_sent)
                    if result.get("text"):
                        ai_sent = await update.message.reply_text(
                            f"{pe('🤖')} 𝐒ʜᴜᴠᴏ 𝐀ɪ{credit_note}\n\n{_ai_body(result['text'])}"
                        )
                        schedule_delete(ai_sent)
                    return
                except Exception:
                    pass

            # Show tool result
            await sent.edit_text(result["tool_result_html"], parse_mode=ParseMode.HTML)
            schedule_delete(sent)

            # Show AI commentary
            if result.get("text"):
                ai_comment = await update.message.reply_text(
                    f"<blockquote>{pe('🌸')} <b>𝐒ʜᴜᴠᴏ 𝐀ɪ</b>{credit_note}\n\n{_ai_body(result['text'])}</blockquote>",
                    parse_mode=ParseMode.HTML
                )
                schedule_delete(ai_comment)
        else:
            # Pure text AI response
            await sent.edit_text(
                f"<blockquote>{pe('🌸')} <b>𝐒ʜᴜᴠᴏ 𝐀ɪ</b>\n\n{_ai_body(result['text'])}</blockquote>",
                parse_mode=ParseMode.HTML
            )
            schedule_delete(sent)
    except Exception:
        try:
            await sent.edit_text(
                f"<blockquote>{pe('🌸')} <b>𝐒ʜᴜᴠᴏ 𝐀ɪ</b>\n\n{_ai_body(result.get('text', 'Kichhu ekta problem hoilo, abar try koro!'))}</blockquote>",
                parse_mode=ParseMode.HTML
            )
        except Exception:
            pass


