def _build_level_banner(user, uid="") -> BytesIO:
    """Overlay level info onto the static banner and return a PNG BytesIO."""
    from PIL import Image, ImageDraw, ImageFont

    FONT_BOLD = "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf"
    FONT_REG  = "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf"

    img = Image.open(BANNER_FILE).convert("RGBA")
    W, H = img.size

    lv_num, lv_badge, _ = get_user_level(user, uid)

    # Progress calculation
    refers  = (user.get("total_refers") or 0)
    credits = (user.get("credits") or 0)
    score   = refers * 10 + credits
    THRESHOLDS = [0, 10, 25, 50, 100, 200, 400, 700, 1200, 2500]
    lo = THRESHOLDS[min(lv_num - 1, 9)]
    hi = THRESHOLDS[min(lv_num, 9)]
    if lv_num >= 10 or hi == lo:
        pct = 100
    else:
        pct = min(100, int((score - lo) / (hi - lo) * 100))

    uname = user.get("username") or user.get("first_name") or "User"
    cred  = credit_display(user)

    # ── Panel dimensions ──
    PAD    = 24
    PH     = 130          # panel height
    PY     = H - PH       # panel top-y
    BAR_H  = 18
    RADIUS = 14

    overlay = Image.new("RGBA", (W, H), (0, 0, 0, 0))
    od = ImageDraw.Draw(overlay)

    # Dark gradient panel
    od.rectangle([(0, PY), (W, H)], fill=(0, 0, 0, 175))

    # Cyan accent bar along the top of panel
    od.rectangle([(0, PY), (W, PY + 3)], fill=(0, 220, 255, 230))

    img = Image.alpha_composite(img, overlay)
    draw = ImageDraw.Draw(img)

    # ── Fonts ──
    try:
        f_name  = ImageFont.truetype(FONT_BOLD, 28)
        f_level = ImageFont.truetype(FONT_BOLD, 22)
        f_small = ImageFont.truetype(FONT_REG,  18)
        f_pct   = ImageFont.truetype(FONT_BOLD, 16)
    except Exception:
        f_name = f_level = f_small = f_pct = ImageFont.load_default()

    # ── Left block: username + level badge ──
    name_text  = f"@{uname}"
    level_text = f"Lv.{lv_num}  {lv_badge}"

    draw.text((PAD, PY + 12), name_text,  font=f_name,  fill=(255, 255, 255, 255))
    draw.text((PAD, PY + 46), level_text, font=f_level, fill=(0, 220, 255, 255))

    # ── Right block: credits ──
    cr_text = f"<tg-emoji emoji-id='5224257782013769471'>💰</tg-emoji> {cred} cr"
    bb = draw.textbbox((0, 0), cr_text, font=f_level)
    cr_w = bb[2] - bb[0]
    draw.text((W - PAD - cr_w, PY + 46), cr_text, font=f_level, fill=(255, 220, 50, 255))

    # ── Progress bar ──
    BX1 = PAD
    BX2 = W - PAD
    BY  = PY + 86
    BAR_W = BX2 - BX1

    # Background track
    draw.rounded_rectangle([(BX1, BY), (BX2, BY + BAR_H)],
                            radius=RADIUS // 2, fill=(60, 60, 80, 220))

    # Filled portion
    filled_w = max(RADIUS, int(BAR_W * pct / 100))
    bar_color = (0, 220, 255, 255) if pct < 100 else (255, 200, 0, 255)
    draw.rounded_rectangle([(BX1, BY), (BX1 + filled_w, BY + BAR_H)],
                            radius=RADIUS // 2, fill=bar_color)

    # Percentage label centered on bar
    pct_str = f"{pct}%" if lv_num < 10 else "MAX"
    bb2 = draw.textbbox((0, 0), pct_str, font=f_pct)
    tx  = BX1 + (BAR_W - (bb2[2] - bb2[0])) // 2
    ty  = BY + (BAR_H - (bb2[3] - bb2[1])) // 2 - 1
    draw.text((tx, ty), pct_str, font=f_pct, fill=(0, 0, 0, 255))

    # Next-level hint
    if lv_num < 10:
        NEXT_LABELS = ["","","🌱 Beginner","⭐ Rookie","🥉 Bronze","🥈 Silver",
                       "🥇 Gold","💎 Platinum","💫 Diamond","🔥 Master","⚡ Legendary"]
        hint = f"Next: {NEXT_LABELS[lv_num + 1] if lv_num + 1 <= 10 else ''}"
        draw.text((BX2 - draw.textbbox((0,0), hint, font=f_small)[2] + draw.textbbox((0,0), hint, font=f_small)[0],
                   BY + BAR_H + 4), hint, font=f_small, fill=(180, 180, 200, 200))

    buf = BytesIO()
    img.convert("RGB").save(buf, format="PNG", optimize=True)
    buf.seek(0)
    return buf


START_VIDEOS = [
    "bot/start1.mp4",
    "bot/start2.mp4",
]
_VIDEO_IDS_FILE = "bot/video_ids.json"

def _load_video_ids() -> dict:
    try:
        with open(_VIDEO_IDS_FILE, "r") as f:
            return json.load(f)
    except Exception:
        return {}

def _save_video_ids(data: dict):
    try:
        with open(_VIDEO_IDS_FILE, "w") as f:
            json.dump(data, f)
    except Exception:
        pass

# Cache Telegram file_ids — loaded from disk so they survive restarts
_start_video_file_ids: dict = _load_video_ids()

async def _send_menu_photo(target, user, uid, extra="", reply_markup=None):
    markup  = reply_markup or build_menu_page(0, user["is_admin"])
    caption = main_menu_text(user, uid) + extra
    uid_str = str(uid)
    msg     = None

    send_kw = dict(caption=caption, reply_markup=markup, parse_mode=ParseMode.HTML)

    # ── Try random start video first ──
    _vid_path = random.choice(START_VIDEOS)
    if os.path.exists(_vid_path) or _vid_path in _start_video_file_ids:
        try:
            cached_fid = _start_video_file_ids.get(_vid_path)
            if cached_fid:
                # Reuse Telegram file_id — instant, no upload
                video_src = cached_fid
            else:
                video_src = open(_vid_path, "rb")

            if hasattr(target, "reply_video"):
                msg = await target.reply_video(video=video_src, **send_kw)
            else:
                msg = await target.message.reply_video(video=video_src, **send_kw)

            if not isinstance(video_src, str):
                video_src.close()

            # Cache the file_id returned by Telegram — also save to disk
            # so it survives restarts on Railway / Render free tier
            if msg and msg.video and not cached_fid:
                _start_video_file_ids[_vid_path] = msg.video.file_id
                _save_video_ids(_start_video_file_ids)

            if msg:
                await set_active_msg(uid_str, msg)
            return msg
        except Exception:
            pass

    # ── Fallback: dynamic level banner ──
    photo = None
    try:
        photo = _build_level_banner(user, uid)
    except Exception:
        pass

    try:
        if photo:
            if hasattr(target, "reply_photo"):
                msg = await target.reply_photo(photo=photo, **send_kw)
            else:
                msg = await target.message.reply_photo(photo=photo, **send_kw)
        else:
            with open(BANNER_FILE, "rb") as f:
                if hasattr(target, "reply_photo"):
                    msg = await target.reply_photo(photo=f, **send_kw)
                else:
                    msg = await target.message.reply_photo(photo=f, **send_kw)
    except Exception:
        try:
            if hasattr(target, "reply_text"):
                msg = await target.reply_text(caption, reply_markup=markup, parse_mode=ParseMode.HTML)
            else:
                msg = await target.message.reply_text(caption, reply_markup=markup, parse_mode=ParseMode.HTML)
        except Exception:
            pass

    if msg:
        await set_active_msg(uid_str, msg)
    return msg


async def start(update: Update, context: ContextTypes.DEFAULT_TYPE):
    users = load_users()
    tg_user = update.effective_user
    is_new_user = str(tg_user.id) not in users
    user, uid = get_user(
        users, tg_user.id,
        username=tg_user.username or "",
        first_name=tg_user.first_name or ""
    )
    if user["banned"]:
        sent = await update.message.reply_text(bq("⛔ You are banned from using this bot."))
        schedule_delete(sent); return

    if not user.get("is_admin") and not is_owner(tg_user.id):
        unjoined = await check_force_join(context.bot, tg_user.id)
        if unjoined:
            names = "\n".join(f"  🔹 {h(ch['title'])}" for ch in unjoined)
            sent = await update.message.reply_text(
                bq(
                    f"📢 Join Required!\n\n"
                    f"<tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji><tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji>\n"
                    f"To use SHUVO BOT you must join:\n\n"
                    f"{names}\n\n"
                    f"After joining all channels/groups,\n"
                    f"tap ✅ Verify below to unlock the bot."
                ),
                reply_markup=force_join_keyboard(unjoined)
            )
            schedule_delete(sent)
            return

    now = datetime.now()
    last = user.get("last_claim")
    claimed = False
    extra_note = ""

    # ── Referral handling ──
    ref_bonus_note = ""
    if is_new_user and context.args:
        arg = context.args[0]
        if arg.startswith("ref_"):
            referrer_id = arg[4:]
            if referrer_id != uid and referrer_id in users:
                referrer = users[referrer_id]
                if not referrer.get("banned"):
                    referrer["credits"] = referrer.get("credits", 0) + 3
                    referrer["total_refers"] = referrer.get("total_refers", 0) + 1
                    user["referred_by"] = referrer_id
                    save_users(users)
                    ref_bonus_note = f"\n👥 Referred by user {referrer_id} — they earned +3 credits!"
                    try:
                        await context.bot.send_message(
                            chat_id=int(referrer_id),
                            text=bq(
                                f"🎉 New Referral!\n\n"
                                f"Someone joined using your link!\n"
                                f"<tg-emoji emoji-id='5224257782013769471'>💰</tg-emoji> +3 Credits added to your account.\n"
                                f"📊 Total Refers: {referrer.get('total_refers', 0)}"
                            )
                        )
                    except Exception:
                        pass

    if is_new_user:
        user["last_claim"] = now.isoformat()
        save_users(users)
        name = tg_user.first_name or "User"
        extra_note = (
            f"\n\n<blockquote>"
            f"<b>🎊 Welcome, {h(name)}!</b>\n"
            f"<b><tg-emoji emoji-id='5262889711466193287'>🎁</tg-emoji></b> +3 Welcome Credits added!\n"
            f"<b>📅</b> Claim +3 more every 24h via /start\n"
            f"<b>💡 Tip:</b> /ai handles everything!"
            f"{ref_bonus_note}"
            f"</blockquote>"
        )
        write_log(f"NEW USER: {uid} (@{tg_user.username or 'N/A'} | {tg_user.first_name or ''}) joined")
    elif last:
        last_dt = datetime.fromisoformat(last)
        if (now - last_dt).total_seconds() >= 86400:
            user["credits"] += 3
            user["last_claim"] = now.isoformat()
            claimed = True
            save_users(users)
    else:
        user["last_claim"] = now.isoformat()
        save_users(users)

    if claimed:
        extra_note = (
            f"\n\n<blockquote>"
            f"<b>✅ Daily Claim!</b>  <b><tg-emoji emoji-id='5262889711466193287'>🎁</tg-emoji> +3 Credits added!</b>\n"
            f"<b>⏰</b> Come back in 24 hours for more"
            f"</blockquote>"
        )

    context.user_data["pending"] = PENDING_NONE
    try:
        await update.message.set_reaction([ReactionTypeCustomEmoji(custom_emoji_id="6242406378263025026")])
    except Exception:
        pass
    sent = await _send_menu_photo(update.message, user, uid, extra=extra_note)
    schedule_delete(sent)


