def _help_kb(page: str) -> InlineKeyboardMarkup:
    if page == "home":
        return _HELP_PAGES["home"]["kb"]
    return InlineKeyboardMarkup([[InlineKeyboardButton("🏠 Back to Menu", callback_data="help_home")]])

async def help_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    page = _HELP_PAGES["home"]
    await update.message.reply_text(
        page["text"],
        parse_mode=ParseMode.HTML,
        reply_markup=_help_kb("home")
    )


