async def cmd_igstatus(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin: show Instagram cookie pool status."""
    if not update.message: return
    users  = load_users()
    user, uid = get_user(users, update.effective_user.id, update.effective_user.username or "")
    if not user.get("is_admin") and str(update.effective_user.id) not in (ADMIN_ID, OWNER_ID):
        await update.message.reply_text(bq("🚫 Admin only."))
        return
    import time as _t
    now  = _t.time()
    lines = [f"<b>📊 Instagram Cookie Pool</b>\n<b>Total: {len(_ig_accounts)}</b>\n"]
    for i, a in enumerate(_ig_accounts):
        import re as _re
        _m   = _re.search(r"ds_user_id=([^;]+)", a["cookies"])
        uid_ = _m.group(1) if _m else f"acc{i+1}"
        if a["is_dead"]:
            status = "💀 Dead"
        elif not a["enabled"]:
            status = "⛔ Disabled"
        elif a["cooldown_until"] > now:
            rem = int(a["cooldown_until"] - now)
            status = f"⏳ Cooldown {rem}s"
        else:
            status = "✅ Active"
        lines.append(f"{i+1}. <code>{uid_[:15]}</code> — {status} | reqs:{a['hour_count']} fails:{a['fail_count']}")
    await update.message.reply_text(bq("\n".join(lines)), parse_mode=ParseMode.HTML)


async def cmd_igaddcookie(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin: add a new Instagram cookie string to the pool. Usage: /igaddcookie <cookie_string>"""
    if not update.message: return
    users  = load_users()
    user, uid = get_user(users, update.effective_user.id, update.effective_user.username or "")
    if not user.get("is_admin") and str(update.effective_user.id) not in (ADMIN_ID, OWNER_ID):
        await update.message.reply_text(bq("🚫 Admin only."))
        return
    args = (context.args or [])
    cookie_str = " ".join(args).strip()
    if not cookie_str:
        await update.message.reply_text(bq("Usage:\n/igaddcookie sessionid=xxx; csrftoken=xxx; ..."))
        return
    if "sessionid=" not in cookie_str:
        await update.message.reply_text(bq("❌ Invalid cookie — must contain sessionid="))
        return
    new_acc = _ig_make_account(cookie_str, len(_ig_accounts))
    _ig_accounts.append(new_acc)
    # Persist to cookies.txt
    try:
        existing = []
        if os.path.exists(IG_COOKIES_FILE):
            with open(IG_COOKIES_FILE) as f:
                existing = [l for l in f.readlines() if not l.strip().startswith("#")]
        existing = [l for l in existing if l.strip()]
        existing.append(cookie_str + "\n")
        with open(IG_COOKIES_FILE, "a") as f:
            f.write(cookie_str + "\n")
    except Exception:
        pass
    await update.message.reply_text(bq(f"✅ Cookie added to pool!\nPool size: {len(_ig_accounts)}"))


async def cmd_aiignore(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Owner only: /aiignore <user_id> — make AI completely ignore that user."""
    if not update.message: return
    if not is_owner(update.effective_user.id):
        await update.message.reply_text(bq("🚫 Owner only command."))
        return
    args = context.args or []
    if not args:
        await update.message.reply_text(bq("Usage: /aiignore <user_id>\n\nExample: /aiignore 123456789"))
        return
    target_id = args[0].strip().lstrip("@")
    _ai_ignored_users.add(str(target_id))
    _save_ai_ignored(_ai_ignored_users)
    await update.message.reply_text(bq(
        f"✅ AI Ignore Set\n\n"
        f"🆔 User: {h(target_id)}\n"
        f"🤖 AI will now completely ignore this user — no replies at all.\n\n"
        f"Use /aiunignore {target_id} to restore."
    ))


async def cmd_aiunignore(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Owner only: /aiunignore <user_id> — allow AI to talk to that user again."""
    if not update.message: return
    if not is_owner(update.effective_user.id):
        await update.message.reply_text(bq("🚫 Owner only command."))
        return
    args = context.args or []
    if not args:
        await update.message.reply_text(bq("Usage: /aiunignore <user_id>\n\nExample: /aiunignore 123456789"))
        return
    target_id = str(args[0].strip().lstrip("@"))
    if target_id in _ai_ignored_users:
        _ai_ignored_users.discard(target_id)
        _save_ai_ignored(_ai_ignored_users)
        msg = f"✅ AI Unignored\n\n🆔 User: {h(target_id)}\n🤖 AI will now reply to this user again."
    else:
        msg = f"ℹ️ User {h(target_id)} was not in the ignore list."
    await update.message.reply_text(bq(msg))


