async def _do_pin_search(update: Update, context, query: str, uid: str, users: dict):
    """AI-assisted Pinterest search → download top 10 images/videos."""
    import yt_dlp, asyncio, shutil, aiohttp
    MAX_ITEMS = 10
    sent = await update.message.reply_text(
        bq(f"🔍 Searching Pinterest for: <b>{_e(query)}</b>\n\n⏳ Please wait…"),
        parse_mode=ParseMode.HTML
    )

    # AI generates a cleaner search query for better results
    try:
        ai_query = await ai_groq(uid, (
            f"Improve this Pinterest search keyword to get best image results. "
            f"Return ONLY the improved keyword, nothing else: '{query}'"
        ))
        ai_query = ai_query.strip().strip('"').strip("'") or query
    except Exception:
        ai_query = query

    search_url = f"https://www.pinterest.com/search/pins/?q={ai_query.replace(' ', '+')}"
    tmp_dir = tempfile.mkdtemp()

    try:
        opts = {
            "quiet": True, "no_warnings": True,
            "socket_timeout": 45, "retries": 2,
            "geo_bypass": True, "nocheckcertificate": True,
            "playlistend": MAX_ITEMS,
            "format": "best[ext=mp4]/best[ext=jpg]/best[ext=jpeg]/best[ext=png]/best",
            "outtmpl": os.path.join(tmp_dir, "%(autonumber)s.%(ext)s"),
        }
        if os.path.exists(_PINT_COOKIES_FILE):
            opts["cookiefile"] = _PINT_COOKIES_FILE

        loop = asyncio.get_event_loop()

        def _extract_info():
            with yt_dlp.YoutubeDL({"quiet": True, "no_warnings": True,
                                    "cookiefile": _PINT_COOKIES_FILE if os.path.exists(_PINT_COOKIES_FILE) else None,
                                    "playlistend": MAX_ITEMS, "socket_timeout": 30}) as ydl:
                return ydl.extract_info(search_url, download=False)

        await sent.edit_text(
            bq(f"🔍 AI Query: <b>{_e(ai_query)}</b>\n\n📥 Downloading top {MAX_ITEMS} results…"),
            parse_mode=ParseMode.HTML
        )

        info = await loop.run_in_executor(None, _extract_info)

        entries = []
        if info:
            if "entries" in info:
                entries = [e for e in (info.get("entries") or []) if e][:MAX_ITEMS]
            else:
                entries = [info]

        if not entries:
            await sent.edit_text(bq(f"❌ No results for: {_e(query)}\n\n😎 DEV @Shuvobhai"), parse_mode=ParseMode.HTML)
            return

        await sent.edit_text(
            bq(f"📌 Found {len(entries)} results!\n\n⬇️ Downloading & sending…"),
            parse_mode=ParseMode.HTML
        )

        media_group = []
        video_list  = []
        sent_count  = 0

        for i, entry in enumerate(entries, 1):
            if not entry: continue
            try:
                pin_url   = entry.get("webpage_url") or entry.get("url") or ""
                vtitle    = (entry.get("title") or query)[:50]
                thumb_url = (entry.get("thumbnail") or entry.get("url") or "")
                # Determine type — if has video formats, it's a video pin
                fmts = entry.get("formats") or []
                is_video = any(f.get("vcodec") not in (None, "none") for f in fmts)

                if is_video and pin_url:
                    # Flush accumulated photos first
                    if media_group:
                        try:
                            await update.message.reply_media_group(media=media_group)
                        except Exception:
                            pass
                        media_group = []
                    # Download and send video separately
                    vtmp = tempfile.mkdtemp()
                    vtmpl = os.path.join(vtmp, "%(title).40s.%(ext)s")
                    vopts = {**opts, "outtmpl": vtmpl}
                    def _dlv(url=pin_url, tmpl=vtmpl, od=vtmp):
                        with yt_dlp.YoutubeDL({**opts, "outtmpl": tmpl}) as ydl:
                            vi = ydl.extract_info(url, download=True)
                            return ydl.prepare_filename(vi), od
                    try:
                        vpath, vtd = await loop.run_in_executor(None, _dlv)
                        if not os.path.exists(vpath):
                            for fn in os.listdir(vtd): vpath = os.path.join(vtd, fn); break
                        with open(vpath, "rb") as vf:
                            video_list.append((vpath, vtitle, vtd))
                            await update.message.reply_video(
                                video=vf, caption=f"<b>📌 {_e(vtitle)}</b>", parse_mode=ParseMode.HTML,
                                supports_streaming=True
                            )
                        sent_count += 1
                    except Exception:
                        shutil.rmtree(vtmp, ignore_errors=True)
                elif thumb_url:
                    from telegram import InputMediaPhoto
                    cap = f"<b>📌 {_e(vtitle)}</b>" if i == 1 else None
                    media_group.append(InputMediaPhoto(media=thumb_url, caption=cap, parse_mode=ParseMode.HTML))
                    sent_count += 1
                    if len(media_group) >= 10:
                        try:
                            await update.message.reply_media_group(media=media_group)
                        except Exception:
                            pass
                        media_group = []
            except Exception:
                continue

        # Send remaining photo batch
        if media_group:
            try:
                await update.message.reply_media_group(media=media_group)
            except Exception:
                pass

        if sent_count == 0:
            await sent.edit_text(bq(f"❌ Could not download any results.\n\n😎 DEV @Shuvobhai"), parse_mode=ParseMode.HTML)
            return

        await sent.edit_text(
            bq(f"📌 PINTEREST SEARCH\n\n🔎 Query: {_e(query)}\n✅ Sent {sent_count} results!\n\n😎 DEV @Shuvobhai"),
            parse_mode=ParseMode.HTML,
            reply_markup=after_result_keyboard()
        )
    except Exception as e:
        err_msg = str(e)[:250]
        try:
            await sent.edit_text(
                bq(f"❌ Pinterest Search Failed!\n\n{err_msg}\n\n😎 DEV @Shuvobhai"),
                parse_mode=ParseMode.HTML
            )
        except Exception:
            pass
    finally:
        shutil.rmtree(tmp_dir, ignore_errors=True)


