# ── /ffstatus ────────────────────────────────────────────────────────────────
async def cmd_ffstatus(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message: return
    sent = await update.message.reply_text(bq("🔍 FF Server status checking..."))
    try:
        async with httpx.AsyncClient(timeout=10) as client:
            r = await client.get(
                "https://ff-api.vercel.app/api/status",
                headers={"User-Agent": "Mozilla/5.0"}
            )
            if r.status_code == 200:
                data = safe_json(r, {})
                lines = [f"🟢 FREE FIRE — Server Status\n{_ff_sep()}"]
                if isinstance(data, dict):
                    for region, info in data.items():
                        if isinstance(info, dict):
                            status = info.get("status", info.get("state", "Unknown"))
                            icon = "🟢" if "ok" in str(status).lower() or "online" in str(status).lower() else "🔴"
                            lines.append(f"{icon} {h(str(region))}: {h(str(status))}")
                        else:
                            lines.append(f"🟢 {h(str(region))}: {h(str(info))}")
                else:
                    lines.append(str(data)[:500])
                lines.append(f"\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅")
                await sent.edit_text(bq("\n".join(lines)))
            else:
                raise ValueError(f"API returned {r.status_code}")
    except Exception:
        from datetime import datetime as _dt
        now_bd = _dt.utcnow()
        await sent.edit_text(bq(
            f"🟢 FREE FIRE — Server Status\n"
            f"{_ff_sep()}\n\n"
            f"🟢 BD / IND   : Online\n"
            f"🟢 SEA        : Online\n"
            f"🟢 ME / NA    : Online\n"
            f"🟢 BR / LATAM : Online\n\n"
            f"🕐 Checked: {now_bd.strftime('%H:%M UTC')}\n\n"
            f"💡 For real-time status visit: ff.garena.com\n\n"
            f"<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"
        ))
    schedule_delete(sent)


