async def _fetch_ffguild(msg, gid: str):
    sent = await msg.reply_text(bq(f"🏅 Guild {h(gid)} info fetch korchi..."))
    try:
        async with httpx.AsyncClient(timeout=12) as client:
            r = await client.get(
                f"https://ff-api.vercel.app/api/guild?id={gid}",
                headers={"User-Agent": "Mozilla/5.0"}
            )
            if r.status_code == 200:
                data = safe_json(r, {})
                if data and isinstance(data, dict):
                    sep = "<tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji>" * 16
                    name = data.get("name", data.get("guildName", "N/A"))
                    level = data.get("level", data.get("guildLevel", "N/A"))
                    members = data.get("members", data.get("memberCount", "N/A"))
                    cap = data.get("capacity", data.get("maxMember", "N/A"))
                    leader = data.get("leader", data.get("captainName", "N/A"))
                    score = data.get("score", data.get("guildScore", "N/A"))
                    region = data.get("region", "N/A")
                    await sent.edit_text(bq(
                        f"🏅 FREE FIRE — Guild Info\n{sep}\n\n"
                        f"🏷 Name    : {h(str(name))}\n"
                        f"🆔 Guild ID: {h(str(gid))}\n"
                        f"⭐ Level   : {h(str(level))}\n"
                        f"👑 Leader  : {h(str(leader))}\n"
                        f"👥 Members : {h(str(members))}/{h(str(cap))}\n"
                        f"🏆 Score   : {h(str(score))}\n"
                        f"🌐 Region  : {h(str(region))}\n\n"
                        f"<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"
                    ))
                    schedule_delete(sent); return
            raise ValueError(f"API {r.status_code}")
    except Exception:
        await sent.edit_text(bq(
            f"🏅 Guild Info — {h(gid)}\n\n"
            f"❌ Guild data pawa jacche na.\n\n"
            f"💡 Tips:\n"
            f"  • Tumi FF te guild open kore 'Guild ID' dekho\n"
            f"  • Settings → Profile → Guild\n\n"
            f"<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"
        ))
    schedule_delete(sent)


