async def _generate_voice(text: str, voice: str, out_path: str):
    """Generate TTS audio using edge_tts with slightly slower rate for clarity."""
    communicate = edge_tts.Communicate(text, voice, rate="-8%", volume="+0%")
    await communicate.save(out_path)

async def _send_voice_reply(update: Update, text: str, voice: str):
    """Generate TTS and send as high-quality OGG OPUS voice note."""
    with tempfile.NamedTemporaryFile(suffix=".mp3", delete=False) as f:
        mp3_tmp = f.name
    ogg_tmp = mp3_tmp.replace(".mp3", ".ogg")
    try:
        await _generate_voice(text, voice, mp3_tmp)
        # Convert MP3 → OGG OPUS 128kbps for best Telegram voice quality
        proc = await asyncio.create_subprocess_exec(
            "ffmpeg", "-y", "-i", mp3_tmp,
            "-c:a", "libopus", "-b:a", "128k",
            "-vbr", "on", "-compression_level", "10",
            ogg_tmp,
            stdout=asyncio.subprocess.DEVNULL,
            stderr=asyncio.subprocess.DEVNULL,
        )
        await proc.wait()
        audio_path = ogg_tmp if os.path.exists(ogg_tmp) and os.path.getsize(ogg_tmp) > 0 else mp3_tmp
        with open(audio_path, "rb") as audio:
            await update.message.reply_voice(voice=audio)
    finally:
        for p in (mp3_tmp, ogg_tmp):
            try:
                os.unlink(p)
            except Exception:
                pass

async def cmd_voice(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message: return
    if await _check_maintenance(update): return
    users = load_users()
    user, uid = get_user(users, update.effective_user.id, update.effective_user.username or "")
    if await _check_banned(update, user): return
    if not user.get("is_admin") and "voice" in user.get("blocked_cmds", []):
        sent = await update.message.reply_text(bq("🚫 Voice feature has been disabled for your account.\n\nContact admin."))
        schedule_delete(sent); return
    if await _check_feature(update, "voice"): return
    if not user.get("is_admin") and user.get("credits", 0) <= 0:
        sent = await update.message.reply_text(bq("❌ Insufficient credits.\n\n💡 Claim daily credits via /start."))
        schedule_delete(sent); return

    args      = context.args or []
    lang_code = ""
    text_parts= []

    for a in args:
        if a.lower() in VOICE_MAP and not lang_code:
            lang_code = a.lower()
        else:
            text_parts.append(a)

    voice     = VOICE_MAP.get(lang_code, VOICE_DEFAULT)
    text      = " ".join(text_parts).strip()

    if not text and update.message.reply_to_message:
        rp = update.message.reply_to_message
        text = (rp.text or rp.caption or "").strip()

    if not text:
        lang_list = "bd/bn · bdm · en · enm · us · uk · ukf · hi · him · ar · fr · de · ja · ko · zh · ru · es · tr · ur · ta · te · pt · it"
        sent = await update.message.reply_text(
            bq(
                "🎙 Voice Convert\n\n"
                "Usage:\n"
                "• /voice Hello world — Bangla voice (default)\n"
                "• /voice en Hello world — English voice\n"
                "• Reply any message with /voice bd\n\n"
                f"🌍 Language codes: {lang_list}\n\n"
                "/cancel to go back."
            )
        )
        context.user_data["pending"]      = PENDING_VOICE
        context.user_data["voice_lang"]   = lang_code
        schedule_delete(sent)
        return

    if not spend_credit(users, uid):
        sent = await update.message.reply_text(bq("❌ Insufficient credits."))
        schedule_delete(sent); return

    sent = await update.message.reply_text(_ld("Converting to voice...", ["🎙️","🔊","🎤","📢","🌊","✨"], ["Synthesising speech...","Converting text...","Building audio...","Rendering voice...","Almost done..."]), parse_mode=ParseMode.HTML)
    try:
        await _send_voice_reply(update, text, voice)
        await sent.delete()
    except Exception as e:
        await sent.edit_text(bq(f"❌ Voice convert failed: {h(str(e)[:200])}\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"))
        schedule_delete(sent)

