async def _do_randomuser(sent):
    try:
        async with httpx.AsyncClient(timeout=15) as client:
            r = await client.get(RANDOMUSER_API_BASE)
            data = safe_json(r)
            res_list = data.get("results", [{}])
            u = res_list[0] if res_list else {}
            name = u.get("name", {})
            full_name = f"{name.get('first','')} {name.get('last','')}".strip()
            loc = u.get("location", {})
            result = bq(
                f"🎲 Random User\n\n"
                f"<tg-emoji emoji-id='5166063676687385916'>👤</tg-emoji> Name: {h(full_name)}\n"
                f"🚻 Gender: {h(u.get('gender','N/A').title())}\n"
                f"📧 Email: {h(u.get('email','N/A'))}\n"
                f"<tg-emoji emoji-id='5465169893580086142'>⭐</tg-emoji> Phone: {h(u.get('phone','N/A'))}\n"
                f"🏙 City: {h(loc.get('city','N/A'))}\n"
                f"🌍 Country: {h(loc.get('country','N/A'))}\n"
                f"🎂 Age: {h(u.get('dob',{}).get('age','N/A'))}\n\n"
                f"<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"
            )
            await sent.edit_text(result)
    except Exception as e:
        await sent.edit_text(bq(f"❌ Error: {h(str(e)[:200])}"))
    schedule_delete(sent)


