async def cmd_holiday(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message: return
    # Optional: /holiday  OR  /holiday US  OR  /holiday 2026 US
    args = context.args or []
    year    = "2025"
    country = "BD"
    if args:
        if args[0].isdigit():
            year    = args[0]
            country = args[1].upper() if len(args) > 1 else "BD"
        else:
            country = args[0].upper()
            year    = args[1] if len(args) > 1 and args[1].isdigit() else "2025"

    sent = await update.message.reply_text(bq(f"🗓 {year} ke holidays dhoond raha hoon ({h(country)})..."))
    try:
        async with httpx.AsyncClient(timeout=12) as client:
            r = await client.get(f"https://date.nager.at/api/v3/PublicHolidays/{year}/{country}")
            data = safe_json(r, [])

        if not isinstance(data, list) or not data:
            await sent.edit_text(bq(f"❌ '{h(country)}' ke liye {year} mein holidays nahi mile.\nSupported codes: BD, IN, US, GB, etc."))
            schedule_delete(sent); return

        today_str = datetime.now().strftime("%Y-%m-%d")
        upcoming  = [h for h in data if h.get("date", "") >= today_str]
        show      = upcoming[:10] if upcoming else data[:10]

        lines = [f"🗓 Public Holidays — {h(country.upper())} ({year})\n"]
        for hol in show:
            date  = hol.get("date", "")
            name  = hol.get("name", "")
            local = hol.get("localName", "")
            label = f"{h(name)}" + (f" ({h(local)})" if local and local != name else "")
            lines.append(f"📅 {date}  •  {label}")

        if len(data) > 10:
            lines.append(f"\n…and {len(data)-10} more holidays.")

        await sent.edit_text(bq("\n".join(lines) + "\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"))
    except Exception as e:
        await sent.edit_text(bq(f"❌ Error: {h(str(e)[:200])}"))
    schedule_delete(sent)


# ── /time ──────────────────────────────────────────────────────────────────
async def cmd_time(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message: return
    # /time  OR  /time Asia/Kolkata  OR  /time Europe/London
    tz = " ".join(context.args).strip().replace(" ", "_") if context.args else "Asia/Dhaka"
    sent = await update.message.reply_text(bq(f"🕐 Time fetch kar raha hoon ({h(tz)})..."))
    try:
        async with httpx.AsyncClient(timeout=12) as client:
            r = await client.get(f"https://worldtimeapi.org/api/timezone/{tz}")
            data = safe_json(r, {})

        if "error" in data or not data.get("datetime"):
            await sent.edit_text(bq(
                f"❌ Timezone nahi mila: {h(tz)}\n\n"
                f"💡 Examples:\n• /time Asia/Dhaka\n• /time Asia/Kolkata\n• /time Europe/London\n• /time America/New_York"
            ))
            schedule_delete(sent); return

        raw_dt   = data.get("datetime", "")           # e.g. 2025-06-06T14:30:00+06:00
        day_of_w = data.get("day_of_week", 0)
        days     = ["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"]
        weekday  = days[day_of_w] if 0 <= day_of_w <= 6 else ""
        # Parse readable time
        dt_part  = raw_dt[:19].replace("T", " ") if len(raw_dt) >= 19 else raw_dt
        offset   = raw_dt[19:] if len(raw_dt) > 19 else ""
        abbr     = data.get("abbreviation", "")

        await sent.edit_text(bq(
            f"🕐 World Time\n\n"
            f"🌍 Timezone : {h(tz)}\n"
            f"📅 Date/Time: {h(dt_part)} {h(offset)}\n"
            f"📆 Day      : {h(weekday)}\n"
            f"⏰ Zone abbr: {h(abbr)}\n\n"
            f"<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"
        ))
    except Exception as e:
        await sent.edit_text(bq(f"❌ Error: {h(str(e)[:200])}"))
    schedule_delete(sent)


# ── /dict ──────────────────────────────────────────────────────────────────
async def cmd_dict(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message: return
    word = " ".join(context.args).strip() if context.args else ""
    if not word:
        sent = await update.message.reply_text(bq("📚 Word likho!\nExample: /dict serendipity"))
        schedule_delete(sent); return
    sent = await update.message.reply_text(bq(f"📚 '{h(word)}' ka meaning dhoond raha hoon..."))
    try:
        async with httpx.AsyncClient(timeout=12) as client:
            r = await client.get(f"https://api.dictionaryapi.dev/api/v2/entries/en/{word}")
            data = safe_json(r, [])

        if isinstance(data, dict) and data.get("title") == "No Definitions Found":
            await sent.edit_text(bq(f"❌ '{h(word)}' ka koi definition nahi mila."))
            schedule_delete(sent); return

        entry    = data[0] if isinstance(data, list) and data else {}
        word_out = entry.get("word", word)
        phonetic = entry.get("phonetic", "")
        meanings = entry.get("meanings", [])

        lines = [f"📚 Dictionary — {h(word_out)}"]
        if phonetic:
            lines.append(f"🔊 {h(phonetic)}")
        lines.append("")

        for meaning in meanings[:3]:
            part = meaning.get("partOfSpeech", "")
            defs = meaning.get("definitions", [])
            if part:
                lines.append(f"〔{h(part)}〕")
            for i, d in enumerate(defs[:2], 1):
                defn    = d.get("definition", "")
                example = d.get("example", "")
                lines.append(f"{i}. {h(defn)}")
                if example:
                    lines.append(f"   📝 {h(example)}")
            synonyms = meaning.get("synonyms", [])
            if synonyms:
                lines.append(f"   🔁 Synonyms: {h(', '.join(synonyms[:5]))}")
            lines.append("")

        await sent.edit_text(bq("\n".join(lines).rstrip() + "\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"))
    except Exception as e:
        await sent.edit_text(bq(f"❌ Error: {h(str(e)[:200])}"))
    schedule_delete(sent)


# ── /lyrics ────────────────────────────────────────────────────────────────
async def cmd_lyrics(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message: return
    # Usage: /lyrics Artist - Song  OR  /lyrics Artist Song Title
    raw = " ".join(context.args).strip() if context.args else ""
    if not raw:
        sent = await update.message.reply_text(bq(
            "🎵 Artist aur song name likho!\n"
            "Examples:\n"
            "• /lyrics Arijit Singh - Tum Hi Ho\n"
            "• /lyrics Ed Sheeran Shape of You"
        ))
        schedule_delete(sent); return

    # Split on " - " if present, else take first word as artist, rest as title
    if " - " in raw:
        parts  = raw.split(" - ", 1)
        artist = parts[0].strip()
        title  = parts[1].strip()
    else:
        words  = raw.split()
        artist = words[0]
        title  = " ".join(words[1:]) if len(words) > 1 else words[0]

    sent = await update.message.reply_text(bq(f"🎵 '{h(artist)} — {h(title)}' ke lyrics dhoond raha hoon..."))
    try:
        async with httpx.AsyncClient(timeout=15) as client:
            r = await client.get(
                f"https://api.lyrics.ovh/v1/{artist}/{title}",
                headers={"User-Agent": "ShuvoBot/1.0"},
            )
            data = safe_json(r, {})

        if "error" in data or not data.get("lyrics"):
            await sent.edit_text(bq(
                f"❌ Lyrics nahi mila: {h(artist)} — {h(title)}\n\n"
                f"💡 Tip: Artist aur song name thoda check karo."
            ))
            schedule_delete(sent); return

        lyrics = data["lyrics"].strip()
        header = f"🎵 {h(artist)} — {h(title)}\n\n"

        # Telegram message limit ~4096 chars; keep header + truncate if needed
        max_lyrics = 3800 - len(header)
        if len(lyrics) > max_lyrics:
            lyrics = lyrics[:max_lyrics].rsplit("\n", 1)[0] + "\n\n…(truncated)"

        await sent.edit_text(bq(header + h(lyrics) + "\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"))
    except Exception as e:
        await sent.edit_text(bq(f"❌ Error: {h(str(e)[:200])}"))
    schedule_delete(sent)


