ANILIST_API = "https://graphql.anilist.co"

async def _anilist_search(name: str) -> dict | None:
    query = """
    query ($search: String) {
        Media(search: $search, type: ANIME, sort: SEARCH_MATCH) {
            id
            title { romaji english native }
            episodes
            status
            seasonYear
            description(asHtml: false)
            genres
            averageScore
            duration
            siteUrl
            streamingEpisodes { title url site }
            externalLinks { url site type language }
        }
    }
    """
    try:
        async with httpx.AsyncClient(timeout=15) as client:
            r = await client.post(
                ANILIST_API,
                json={"query": query, "variables": {"search": name}},
                headers={"Content-Type": "application/json", "Accept": "application/json"}
            )
            data = safe_json(r, {})
            return data.get("data", {}).get("Media")
    except Exception:
        return None


async def cmd_anime(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Search anime info, languages and streaming/download links."""
    if not update.message:
        return
    if await _check_maintenance(update): return
    users = load_users()
    user, uid = get_user(users, update.effective_user.id, update.effective_user.username or "")
    if await _check_banned(update, user): return
    if not user.get("is_admin") and "fun" in user.get("blocked_cmds", []):
        sent = await update.message.reply_text(bq("🚫 Fun commands have been disabled for your account.\n\nContact admin."))
        schedule_delete(sent); return

    args = " ".join(context.args).strip() if context.args else ""

    if not args:
        sent = await update.message.reply_text(
            bq(
                "🎌 Anime Search\n\n"
                "Usage:\n"
                "• /anime Naruto\n"
                "• /anime Attack on Titan S1E1\n"
                "• /anime One Piece S2E5 Hindi\n\n"
                "Bot will show info, available languages & streaming links!"
            )
        )
        schedule_delete(sent)
        return

    # Parse episode: S1E5 or s01e05
    ep_match = re.search(r'\bS(\d+)E(\d+)\b', args, re.IGNORECASE)
    season_num = int(ep_match.group(1)) if ep_match else None
    ep_num    = int(ep_match.group(2)) if ep_match else None

    # Parse language keyword
    lang_keywords = ["hindi", "english", "japanese", "tamil", "telugu", "arabic", "sub", "dub", "bengali"]
    req_lang = None
    for kw in lang_keywords:
        if re.search(rf'\b{kw}\b', args, re.IGNORECASE):
            req_lang = kw.capitalize()
            break

    # Clean name from episode + lang tokens
    name = args
    if ep_match:
        name = name[:ep_match.start()].strip()
    if req_lang:
        name = re.sub(rf'\b{req_lang}\b', '', name, flags=re.IGNORECASE).strip()
    name = name.strip(" ,.-")

    sent = await update.message.reply_text(_ld("Searching anime...", ["🎌","🌸","⛩️","🗡️","🌟","✨"], ["Searching anime DB...","Scanning titles...","Loading info...","Almost done..."]), parse_mode=ParseMode.HTML)
    anim = await _anim_start(sent, "Searching anime...", ["🎌","🌸","⛩️","🗡️","🌟","✨"], ["Searching anime DB...","Scanning titles...","Loading info...","Almost done..."])

    anime = await _anilist_search(name)
    anim.cancel()
    if not anime:
        await sent.edit_text(
            bq(f"❌ '{h(name)}' — Anime not found!\n\nTry a different spelling.")
        )
        schedule_delete(sent)
        return

    title_en = (anime.get("title") or {}).get("english") or ""
    title_ro = (anime.get("title") or {}).get("romaji") or ""
    title_na = (anime.get("title") or {}).get("native") or ""
    title    = title_en or title_ro

    total_eps = anime.get("episodes") or "?"
    status    = (anime.get("status") or "?").replace("_", " ").title()
    score     = anime.get("averageScore") or "N/A"
    genres    = ", ".join((anime.get("genres") or [])[:4]) or "N/A"
    year      = anime.get("seasonYear") or ""
    duration  = anime.get("duration") or "?"
    anilist_url = anime.get("siteUrl") or ""

    desc = re.sub(r'<[^>]+>', '', (anime.get("description") or "No description.")).strip()
    desc = desc[:200] + "..." if len(desc) > 200 else desc

    # Streaming platforms + languages
    ext_links = anime.get("externalLinks") or []
    platforms: dict = {}
    for link in ext_links:
        if (link.get("type") or "") == "STREAMING":
            site = link.get("site") or ""
            url  = link.get("url") or ""
            lang = link.get("language") or "Japanese"
            if site and url:
                if site not in platforms:
                    platforms[site] = {"url": url, "langs": set()}
                platforms[site]["langs"].add(lang)

    platform_lines = []
    for site, info in list(platforms.items())[:6]:
        langs = ", ".join(sorted(info["langs"]))
        platform_lines.append(f"  • {h(site)} [{h(langs)}]")

    platform_text = "\n".join(platform_lines) if platform_lines else "  • Crunchyroll / Funimation / Netflix"

    # Language-specific note
    lang_note = ""
    if req_lang:
        matched_sites = [s for s, i in platforms.items() if req_lang in i["langs"]]
        if matched_sites:
            lang_note = f"\n✅ {h(req_lang)} available on: {h(', '.join(matched_sites))}"
        else:
            lang_note = f"\n⚠️ {h(req_lang)} dub/sub: Not found on major platforms"

    # Episode-specific link
    ep_note = ""
    streaming_eps = anime.get("streamingEpisodes") or []
    if ep_match and streaming_eps:
        ep_index = ep_num - 1 if ep_num else 0
        ep_data  = streaming_eps[ep_index] if ep_index < len(streaming_eps) else streaming_eps[-1]
        ep_url   = ep_data.get("url") or ""
        ep_title = ep_data.get("title") or f"Episode {ep_num}"
        ep_site  = ep_data.get("site") or ""
        if ep_url:
            ep_note = (
                f"\n\n🎬 S{season_num}E{ep_num} Link:\n"
                f"  • {h(ep_title)}"
                + (f" on {h(ep_site)}" if ep_site else "")
                + f"\n\n💡 Copy that link → send to /download to get the file!"
            )

    msg = (
        f"🎌 {h(title)}"
        + (f"\n{h(title_na)}" if title_na else "")
        + f"\n\n"
        f"📺 Episodes: {total_eps}  |  <tg-emoji emoji-id='5465169893580086142'>⭐</tg-emoji> Score: {score}/100\n"
        f"📅 Year: {year}  |  ⏱ {duration} min/ep\n"
        f"📌 Status: {status}\n"
        f"🎭 Genres: {h(genres)}\n"
        + (f"\n📝 {h(desc)}\n" if desc else "")
        + f"\n🌐 Watch on:\n{platform_text}"
        + lang_note
        + ep_note
        + (f"\n\n<tg-emoji emoji-id='5215441850537618106'>🔗</tg-emoji> AniList Page" if anilist_url else "")
    )

    await sent.edit_text(bq(msg), disable_web_page_preview=True)
    schedule_delete(sent)


async def cmd_sticker(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Reply to any message with /sticker to convert text into a sticker."""
    if not update.message:
        return
    reply = update.message.reply_to_message
    if not reply:
        sent = await update.message.reply_text(
            bq("↩️ Reply to a message with /sticker to turn it into a sticker!")
        )
        schedule_delete(sent)
        return
    text = (reply.text or reply.caption or "").strip()
    if not text:
        sent = await update.message.reply_text(
            bq("❌ That message has no text to convert.")
        )
        schedule_delete(sent)
        return

    sender      = reply.from_user
    sender_name = (sender.first_name or "User") if sender else "User"

    try:
        from PIL import Image, ImageDraw, ImageFont
        import io, textwrap, math

        FONT_BOLD = "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf"
        FONT_REG  = "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf"

        SIZE_NAME = 26
        SIZE_TEXT = 24
        PADDING   = 28
        MAX_W     = 460
        RADIUS    = 22

        try:
            fn = ImageFont.truetype(FONT_BOLD, SIZE_NAME)
            ft = ImageFont.truetype(FONT_REG,  SIZE_TEXT)
        except Exception:
            fn = ft = ImageFont.load_default()

        # ── Wrap text ──────────────────────────────────────────────
        wrapped_lines: list[str] = []
        for raw_line in text.splitlines():
            if not raw_line:
                wrapped_lines.append("")
                continue
            wrapped_lines.extend(textwrap.wrap(raw_line, width=22) or [""])

        # ── Measure sizes ─────────────────────────────────────────
        def text_size(draw: ImageDraw.ImageDraw, txt: str, font):
            bbox = draw.textbbox((0, 0), txt, font=font)
            return bbox[2] - bbox[0], bbox[3] - bbox[1]

        tmp = Image.new("RGBA", (1, 1))
        td  = ImageDraw.Draw(tmp)
        name_w, name_h  = text_size(td, sender_name, fn)
        line_h = SIZE_TEXT + 8
        text_block_h    = len(wrapped_lines) * line_h
        max_line_w      = max((text_size(td, l, ft)[0] for l in wrapped_lines if l), default=name_w)

        bubble_w = min(MAX_W, max(name_w, max_line_w) + PADDING * 2 + 8)
        bubble_h = PADDING + name_h + 10 + text_block_h + PADDING

        # ── Canvas (transparent, 512×512 max) ─────────────────────
        CW = 512
        CH = min(512, bubble_h + 48)
        img  = Image.new("RGBA", (CW, CH), (0, 0, 0, 0))
        draw = ImageDraw.Draw(img)

        bx = (CW - bubble_w) // 2
        by = (CH - bubble_h) // 2

        # Bubble fill (dark Telegram-like)
        BUBBLE  = (36, 36, 56, 240)
        NAME_C  = (110, 168, 254, 255)   # blue accent
        TEXT_C  = (220, 220, 235, 255)
        ACCENT  = (110, 168, 254, 255)

        draw.rounded_rectangle(
            [bx, by, bx + bubble_w, by + bubble_h],
            radius=RADIUS, fill=BUBBLE
        )
        # Left accent bar
        draw.rounded_rectangle(
            [bx, by + 10, bx + 4, by + bubble_h - 10],
            radius=2, fill=ACCENT
        )

        # Sender name
        draw.text((bx + PADDING, by + PADDING // 2), sender_name, font=fn, fill=NAME_C)

        # Message lines
        ty = by + PADDING // 2 + name_h + 10
        for line in wrapped_lines:
            draw.text((bx + PADDING, ty), line, font=ft, fill=TEXT_C)
            ty += line_h

        # ── Export as WebP sticker ─────────────────────────────────
        buf = io.BytesIO()
        img.save(buf, format="WEBP", quality=90)
        buf.seek(0)

        await update.message.reply_sticker(sticker=InputFile(buf, filename="sticker.webp"))
        try:
            await update.message.delete()
        except Exception:
            pass

    except Exception as e:
        print(f"[cmd_sticker] error: {e}")
        sent = await update.message.reply_text(f"❌ Sticker banate problem hoilo:\n{e}")
        schedule_delete(sent)


async def cmd_quote(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Reply to any message with /q to turn it into a quote sticker (full text, auto-scaled)."""
    if not update.message:
        return
    reply = update.message.reply_to_message
    if not reply:
        sent = await update.message.reply_text(
            bq("↩️ Kisi ke message ka reply karo /q se quote sticker banane ke liye!")
        )
        schedule_delete(sent)
        return

    text = (reply.text or reply.caption or "").strip()
    if not text:
        sent = await update.message.reply_text(
            bq("❌ Us message mein koi text nahi hai.")
        )
        schedule_delete(sent)
        return

    sender      = reply.from_user
    sender_name = (sender.first_name or "User") if sender else "User"
    if sender and sender.last_name:
        sender_name = f"{sender.first_name} {sender.last_name}"

    try:
        import io, textwrap
        from PIL import Image, ImageDraw, ImageFont

        FONT_BOLD = "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf"
        FONT_REG  = "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf"

        CW      = 512          # sticker canvas width  (always 512)
        PADDING = 28
        RADIUS  = 20
        MAX_CH  = 512          # sticker canvas height limit

        def ts(draw, txt, font):
            b = draw.textbbox((0, 0), txt, font=font)
            return b[2] - b[0], b[3] - b[1]

        # ── Auto-scale font so FULL text fits inside 512×512 ─────────
        best = None
        for size_text in range(26, 9, -1):          # try 26 → 10 pt
            size_name = max(size_text + 2, 12)
            size_mark = max(size_text * 3, 30)
            try:
                fn    = ImageFont.truetype(FONT_BOLD, size_name)
                ft    = ImageFont.truetype(FONT_REG,  size_text)
                fmark = ImageFont.truetype(FONT_BOLD, size_mark)
            except Exception:
                fn = ft = fmark = ImageFont.load_default()

            chars_per_line = max(12, int((CW - PADDING * 2 - 12) / (size_text * 0.6)))
            wrapped: list[str] = []
            for raw in text.splitlines():
                if not raw:
                    wrapped.append("")
                else:
                    wrapped.extend(textwrap.wrap(raw, width=chars_per_line) or [""])

            tmp  = Image.new("RGBA", (1, 1))
            td   = ImageDraw.Draw(tmp)
            lh   = size_text + 6
            _, nh = ts(td, sender_name, fn)
            _, mh = ts(td, "\u201c", fmark)

            bubble_h = PADDING + mh // 2 + 8 + len(wrapped) * lh + 16 + nh + PADDING
            ch       = bubble_h + 40

            if ch <= MAX_CH:
                best = (size_text, size_name, size_mark, fn, ft, fmark,
                        wrapped, lh, nh, mh, bubble_h, ch)
                break

        # Fallback: use smallest size, crop canvas to 512
        if best is None:
            size_text, size_name, size_mark = 10, 12, 30
            try:
                fn    = ImageFont.truetype(FONT_BOLD, size_name)
                ft    = ImageFont.truetype(FONT_REG,  size_text)
                fmark = ImageFont.truetype(FONT_BOLD, size_mark)
            except Exception:
                fn = ft = fmark = ImageFont.load_default()
            chars_per_line = max(12, int((CW - PADDING * 2 - 12) / (size_text * 0.6)))
            wrapped = []
            for raw in text.splitlines():
                if not raw:
                    wrapped.append("")
                else:
                    wrapped.extend(textwrap.wrap(raw, width=chars_per_line) or [""])
            tmp = Image.new("RGBA", (1, 1))
            td  = ImageDraw.Draw(tmp)
            lh  = size_text + 6
            _, nh = ts(td, sender_name, fn)
            _, mh = ts(td, "\u201c", fmark)
            bubble_h = PADDING + mh // 2 + 8 + len(wrapped) * lh + 16 + nh + PADDING
            ch = min(MAX_CH, bubble_h + 40)
            best = (size_text, size_name, size_mark, fn, ft, fmark,
                    wrapped, lh, nh, mh, bubble_h, ch)

        (size_text, size_name, size_mark, fn, ft, fmark,
         wrapped, lh, nh, mh, bubble_h, ch) = best

        bubble_w = CW - 32

        # ── Build canvas ─────────────────────────────────────────────
        bg   = Image.new("RGBA", (CW, ch), (0, 0, 0, 0))
        draw = ImageDraw.Draw(bg)

        # Dark gradient background
        for y in range(ch):
            t = y / ch
            r = int(10 + 20 * t)
            g = int(10 + 10 * t)
            b = int(30 + 30 * t)
            draw.line([(0, y), (CW, y)], fill=(r, g, b, 255))

        bx = 16
        by = (ch - bubble_h) // 2

        BUBBLE = (20, 20, 42, 230)
        NAME_C = (120, 180, 255, 255)
        TEXT_C = (225, 225, 240, 255)
        ACCENT = (100, 140, 255, 255)
        MARK_C = (100, 140, 255, 55)

        # Bubble
        draw.rounded_rectangle(
            [bx, by, bx + bubble_w, by + bubble_h],
            radius=RADIUS, fill=BUBBLE
        )
        # Left accent bar
        draw.rounded_rectangle(
            [bx, by + 10, bx + 5, by + bubble_h - 10],
            radius=2, fill=ACCENT
        )
        # Top glow strip
        draw.rounded_rectangle(
            [bx + 10, by, bx + bubble_w - 10, by + 3],
            radius=2, fill=(*ACCENT[:3], 100)
        )

        # Decorative opening quote mark
        cur_y = by + PADDING // 2
        draw.text((bx + PADDING - 4, cur_y - 6), "\u201c", font=fmark, fill=MARK_C)

        # Full message text — every line, no cuts
        cur_y += mh // 2 + 8
        for line in wrapped:
            draw.text((bx + PADDING, cur_y), line, font=ft, fill=TEXT_C)
            cur_y += lh

        # Divider
        cur_y += 8
        draw.line(
            [(bx + PADDING, cur_y), (bx + bubble_w - PADDING, cur_y)],
            fill=(*ACCENT[:3], 50), width=1
        )
        cur_y += 10

        # Sender name
        draw.text((bx + PADDING, cur_y), f"— {sender_name}", font=fn, fill=NAME_C)

        # ── Export as WebP sticker ────────────────────────────────────
        buf = io.BytesIO()
        bg.save(buf, format="WEBP", quality=90)
        buf.seek(0)

        await update.message.reply_sticker(sticker=InputFile(buf, filename="quote.webp"))
        try:
            await update.message.delete()
        except Exception:
            pass

    except Exception as e:
        print(f"[cmd_quote] error: {e}")
        sent = await update.message.reply_text(f"❌ Quote sticker banate problem hoilo:\n{e}")
        schedule_delete(sent)


async def cmd_bypass_toggle(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message:
        return
    chat = update.effective_chat
    if chat.type not in ("group", "supergroup"):
        sent = await update.message.reply_text(
            bq("❌ This command only works inside a group.")
        )
        schedule_delete(sent)
        return
    uid = str(update.effective_user.id)
    try:
        member = await context.bot.get_chat_member(chat.id, int(uid))
        is_admin = member.status in ("administrator", "creator")
    except Exception:
        is_admin = False
    if not is_admin and not is_owner(uid):
        sent = await update.message.reply_text(
            bq("🚫 Only group admins can toggle bypass.")
        )
        schedule_delete(sent)
        return
    args = context.args or []
    arg = args[0].lower() if args else ""
    cid = str(chat.id)
    if arg == "on":
        _bypass_disabled_groups.discard(cid)
        sent = await update.message.reply_text(
            bq("✅ Auto Bypass: ON\n\nNow I'll automatically bypass any link sent in this group.\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅")
        )
    elif arg == "off":
        _bypass_disabled_groups.add(cid)
        sent = await update.message.reply_text(
            bq("🔴 Auto Bypass: OFF\n\nAuto bypass is now disabled in this group.\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅")
        )
    else:
        status = "🔴 OFF" if cid in _bypass_disabled_groups else "✅ ON"
        sent = await update.message.reply_text(
            bq(f"<tg-emoji emoji-id='5215441850537618106'>🔗</tg-emoji> Auto Bypass Status: {status}\n\n"
               f"Use:\n"
               f"• /by on — Enable auto bypass\n"
               f"• /by off — Disable auto bypass\n\n"
               f"<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅")
        )
    schedule_delete(sent)


