                    f"<blockquote><b>❌ Play failed!</b>\n\n"
                    f"<code>{_e(err_raw[:300])}</code>\n\n"
                    f"Alada song name ba YouTube link diye try koro.\n\n"
                    f"<b>Dev</b> @Shuvobhai</blockquote>",
