def _vc_dur_fmt(sec: int) -> str:
    """Format seconds → M:SS or H:MM:SS."""
    sec = int(sec or 0)
    if sec >= 3600:
        return f"{sec//3600}:{(sec%3600)//60:02d}:{sec%60:02d}"
    return f"{sec//60}:{sec%60:02d}"


def _vc_controls_kb(chat_id: int) -> InlineKeyboardMarkup:
    """Return inline control buttons for the VC player."""
    paused = _vc_paused.get(chat_id, False)
    loop   = _vc_loop.get(chat_id, 0)
    loop_lbl = {0: "➡️ Off", 1: "🔂 Single", 10: "🔁 Queue"}.get(loop, "➡️ Off")
    play_pause = "▶️ Resume" if paused else "⏸ Pause"
    return InlineKeyboardMarkup([
        [
            InlineKeyboardButton(play_pause,  callback_data=f"vc_pp_{chat_id}"),
            InlineKeyboardButton("⏭ Skip",   callback_data=f"vc_skip_{chat_id}"),
            InlineKeyboardButton("⏹ Stop",   callback_data=f"vc_stop_{chat_id}"),
        ],
        [
            InlineKeyboardButton(f"🔁 Loop: {loop_lbl}", callback_data=f"vc_loop_{chat_id}"),
            InlineKeyboardButton("🔀 Shuffle",           callback_data=f"vc_shuffle_{chat_id}"),
            InlineKeyboardButton("📋 Queue",              callback_data=f"vc_queue_{chat_id}"),
        ],
    ])


def _vc_thumb_dark_bg(w: int, h: int):
    """Create a dark purple-blue gradient background."""
    from PIL import Image, ImageDraw
    img = Image.new("RGBA", (w, h))
    draw = ImageDraw.Draw(img)
    for y in range(h):
        r = int(12 + (y / h) * 18)
        g = int(8  + (y / h) * 12)
        b = int(32 + (y / h) * 28)
        draw.line([(0, y), (w, y)], fill=(r, g, b, 255))
    return img


async def _vc_make_thumb(title: str, uploader: str, duration_str: str, thumb_url: str = "") -> str | None:
    """
    Generate a beautiful now-playing card image using PIL.
    Returns the temp file path (caller must delete) or None on failure.
    """
    import asyncio, io, os, tempfile, textwrap
    loop = asyncio.get_event_loop()

    def _sync_gen():
        try:
            from PIL import Image, ImageDraw, ImageFont, ImageFilter, ImageEnhance
            import urllib.request

            W, H = 800, 420

            # ── Background ───────────────────────────────────────────────────
            if thumb_url:
                try:
                    req = urllib.request.Request(
                        thumb_url, headers={"User-Agent": "Mozilla/5.0"})
                    with urllib.request.urlopen(req, timeout=6) as resp:
                        raw = resp.read()
                    bg_src = Image.open(io.BytesIO(raw)).convert("RGBA").resize((W, H))
                    bg = ImageEnhance.Brightness(
                        bg_src.filter(ImageFilter.GaussianBlur(18))
                    ).enhance(0.38)
                except Exception:
                    bg = _vc_thumb_dark_bg(W, H)
            else:
                bg = _vc_thumb_dark_bg(W, H)

            # ── Dark semi-transparent overlay ────────────────────────────────
            overlay = Image.new("RGBA", (W, H), (0, 0, 0, 130))
            bg = Image.alpha_composite(bg.convert("RGBA"), overlay)
            draw = ImageDraw.Draw(bg)

            # ── Fonts ────────────────────────────────────────────────────────
            FONT_PATHS = [
                "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
                "/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf",
                "/usr/share/fonts/truetype/freefont/FreeSansBold.ttf",
            ]
            FONT_REG_PATHS = [
                "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
                "/usr/share/fonts/truetype/liberation/LiberationSans-Regular.ttf",
                "/usr/share/fonts/truetype/freefont/FreeSans.ttf",
            ]
            def _try_font(paths, size):
                for p in paths:
                    if os.path.exists(p):
                        try:
                            return ImageFont.truetype(p, size)
                        except Exception:
                            pass
                return ImageFont.load_default()

            font_header = _try_font(FONT_PATHS, 20)
            font_title  = _try_font(FONT_PATHS, 38)
            font_info   = _try_font(FONT_REG_PATHS, 22)
            font_small  = _try_font(FONT_REG_PATHS, 17)

            RED   = (255, 50,  50,  255)
            WHITE = (255, 255, 255, 255)
            GRAY  = (180, 180, 180, 220)
            LGRAY = (130, 130, 130, 200)

            # ── Header bar ───────────────────────────────────────────────────
            draw.rectangle([(0, 0), (W, 56)], fill=(0, 0, 0, 110))
            draw.text((22, 16), "🎙  SHUVO VC PLAYER  —  NOW PLAYING", fill=WHITE, font=font_header)

            # ── Left accent stripe ───────────────────────────────────────────
            draw.rectangle([(22, 76), (28, 310)], fill=RED)

            # ── Title (word-wrap, max 3 lines) ───────────────────────────────
            wrapped = textwrap.wrap(title[:90], width=30)[:3]
            ty = 82
            for line in wrapped:
                draw.text((44, ty), line, fill=WHITE, font=font_title)
                ty += 50

            # ── Metadata ─────────────────────────────────────────────────────
            draw.text((44, ty + 8),  f"🎤  {uploader[:48]}", fill=GRAY, font=font_info)
            draw.text((44, ty + 38), f"⏱  {duration_str}",  fill=GRAY, font=font_info)

            # ── Progress bar ─────────────────────────────────────────────────
            BX, BY, BW = 40, 358, W - 80
            draw.rectangle([(BX, BY), (BX + BW, BY + 7)], fill=(60, 60, 60, 200))
            prog = int(BW * 0.28)
            draw.rectangle([(BX, BY), (BX + prog, BY + 7)], fill=RED)
            draw.ellipse([(BX + prog - 9, BY - 6), (BX + prog + 9, BY + 13)], fill=RED)

            # ── Time labels ──────────────────────────────────────────────────
            draw.text((BX,            BY + 16), "0:00",       fill=LGRAY, font=font_small)
            draw.text((BX + BW - 45,  BY + 16), duration_str, fill=LGRAY, font=font_small)

            # ── Bottom branding ───────────────────────────────────────────────
            draw.text((BX + BW - 90, H - 22), "@Shuvobhai", fill=(100, 100, 100, 180), font=font_small)

            # ── Save ─────────────────────────────────────────────────────────
            tmp = tempfile.NamedTemporaryFile(suffix=".jpg", delete=False, dir="/tmp")
            bg.convert("RGB").save(tmp.name, "JPEG", quality=90)
            return tmp.name
        except Exception:
            return None

    return await loop.run_in_executor(None, _sync_gen)


# ── Invidious — YouTube mirror that bypasses bot detection ───────────────────
# Primary known-working instance first; dynamic discovery fills the rest
async def _invidious_dl(query: str, out_dir: str) -> tuple:
    """
    Download audio for VC playback using yt-dlp (fast, reliable).
    Falls back to Invidious proxy only if yt-dlp fails.
    Returns (filepath, info_dict).
    """
    import yt_dlp, asyncio, os, re

    loop = asyncio.get_event_loop()

    # ── Check for cookies file ──────────────────────────────────────────────
    _cookie_file = os.path.join(os.path.dirname(os.path.abspath(__file__)), "bot", "yt_cookies.txt")
    _cookies_arg = _cookie_file if os.path.exists(_cookie_file) and os.path.getsize(_cookie_file) > 50 else None

    _yt_re = re.compile(r'(?:v=|youtu\.be/|shorts/|live/)([A-Za-z0-9_-]{11})')
    is_url = _yt_re.search(query) is not None or query.startswith("http")
    search_query = query if is_url else f"ytsearch1:{query}"

    out_tmpl = os.path.join(out_dir, "audio.%(ext)s")

    ydl_opts = {
        "format":            "bestaudio[ext=m4a]/bestaudio[ext=webm]/bestaudio/best",
        "outtmpl":           out_tmpl,
        "quiet":             True,
        "no_warnings":       True,
        "noplaylist":        True,
        "extract_flat":      False,
        "socket_timeout":    15,
        "retries":           3,
        "fragment_retries":  3,
    }
    if _cookies_arg:
        ydl_opts["cookiefile"] = _cookies_arg

    def _blocking_dl():
        with yt_dlp.YoutubeDL(ydl_opts) as ydl:
            info = ydl.extract_info(search_query, download=True)
            if "entries" in info:
                info = info["entries"][0]
            return info

    try:
        info = await loop.run_in_executor(None, _blocking_dl)
    except Exception as ytdlp_err:
        # ── Fallback: Invidious proxy ───────────────────────────────────────
        import aiohttp
        _INVIDIOUS = [
            "https://inv.nadeko.net",
            "https://iv.ggtyler.dev",
            "https://invidious.nerdvpn.de",
            "https://inv.thepixora.com",
        ]
        _yt_re2 = re.compile(r'(?:v=|youtu\.be/|shorts/|live/)([A-Za-z0-9_-]{11})')

        async def _inv_try(instance, sess):
            m = _yt_re2.search(query)
            video_id = m.group(1) if m else None
            if not video_id:
                async with sess.get(
                    f"{instance}/api/v1/search",
                    params={"q": query, "type": "video",
                            "fields": "videoId,title,lengthSeconds,author", "hl": "en"},
                    timeout=aiohttp.ClientTimeout(total=10),
                ) as r:
                    if r.status != 200:
                        raise ValueError(f"search {r.status}")
                    results = await r.json()
                if not results or not isinstance(results, list):
                    raise ValueError("no results")
                video_id = results[0]["videoId"]
            async with sess.get(
                f"{instance}/api/v1/videos/{video_id}",
                timeout=aiohttp.ClientTimeout(total=10),
            ) as r:
                if r.status != 200:
                    raise ValueError(f"info {r.status}")
                data = await r.json()
            fmts = [f for f in data.get("adaptiveFormats", [])
                    if f.get("type", "").startswith("audio/") and f.get("itag")]
            if not fmts:
                raise ValueError("no audio formats")
            fmts.sort(key=lambda x: int(x.get("bitrate", 0)), reverse=True)
            best = fmts[0]
            ext = "m4a" if "mp4" in best.get("type", "") else "webm"
            out_path = os.path.join(out_dir, f"audio.{ext}")
            proxy_url = f"{instance}/latest_version?id={video_id}&itag={best['itag']}&local=true"
            async with sess.get(proxy_url, timeout=aiohttp.ClientTimeout(total=180),
                                allow_redirects=True) as r2:
                if r2.status not in (200, 206):
                    raise ValueError(f"proxy {r2.status}")
                with open(out_path, "wb") as fh:
                    async for chunk in r2.content.iter_chunked(65536):
                        fh.write(chunk)
            if not os.path.exists(out_path) or os.path.getsize(out_path) < 1000:
                raise ValueError("empty file")
            return out_path, {
                "title": str(data.get("title") or query)[:80],
                "uploader": str(data.get("author") or "YouTube")[:50],
                "duration": int(data.get("lengthSeconds") or 0),
                "webpage_url": f"https://www.youtube.com/watch?v={video_id}",
            }

        connector = aiohttp.TCPConnector(limit=4)
        last_err = ytdlp_err
        async with aiohttp.ClientSession(connector=connector) as sess:
            for inst in _INVIDIOUS:
                try:
                    return await _inv_try(inst, sess)
                except Exception as ex:
                    last_err = ex
        raise last_err or ValueError("All download methods failed")

    # ── Find the downloaded file ────────────────────────────────────────────
    _audio_exts = (".m4a", ".mp3", ".webm", ".opus", ".ogg", ".aac")
    filepath = None
    for f in os.listdir(out_dir):
        if any(f.endswith(ext) for ext in _audio_exts):
            filepath = os.path.join(out_dir, f)
            break
    if not filepath or not os.path.exists(filepath):
        raise ValueError("yt-dlp did not save the audio file")

    return filepath, {
        "title":       str(info.get("title") or query)[:80],
        "uploader":    str(info.get("uploader") or info.get("channel") or "YouTube")[:50],
        "duration":    int(info.get("duration") or 0),
        "webpage_url": str(info.get("webpage_url") or info.get("original_url") or ""),
        "thumbnail":   str(info.get("thumbnail") or ""),
    }


async def _vc_init():
    """Lazily initialise Pyrogram client + PyTgCalls."""
    global _vc_client, _vc_calls
    if _vc_calls is not None:
        return True
    try:
        from pyrogram import Client
        from pytgcalls import PyTgCalls, filters as tgfilters
        from pytgcalls.types import MediaStream, AudioQuality

        _vc_client = Client(
            name="vc_player",
            api_id=VC_API_ID,
            api_hash=VC_API_HASH,
            session_string=VC_SESSION,
            no_updates=False,
        )
        await _vc_client.start()
        _vc_calls = PyTgCalls(_vc_client)

        async def _on_stream_end(client, update):
            try:
                cid = update.chat_id
            except AttributeError:
                return
            loop_mode = _vc_loop.get(cid, 0)
            cur = _vc_current.get(cid)

            # 🔂 Single loop — replay same track
            if loop_mode == 1 and cur:
                try:
                    await client.play(
                        cid,
                        MediaStream(cur["filepath"], audio_parameters=AudioQuality.HIGH,
                                    video_flags=MediaStream.Flags.IGNORE)
                    )
                except Exception:
                    _vc_current.pop(cid, None)
                return

            # 🔁 Queue loop — re-add current to end of queue
            if loop_mode == 10 and cur:
                _vc_queue.setdefault(cid, []).append((
                    cur["title"], cur["filepath"], cur["requested_by"],
                    cur.get("duration", 0), cur.get("url", "")
                ))

            _vc_current.pop(cid, None)
            _vc_paused.pop(cid, None)
            nxt = _vc_queue.get(cid, [])
            if nxt:
                item = nxt.pop(0)
                nxt_title, nxt_path, nxt_req = item[0], item[1], item[2]
                nxt_dur  = item[3] if len(item) > 3 else 0
                nxt_url  = item[4] if len(item) > 4 else ""
                _vc_current[cid] = {
                    "title": nxt_title, "filepath": nxt_path,
                    "requested_by": nxt_req, "duration": nxt_dur, "url": nxt_url
                }
                try:
                    await client.play(
                        cid,
                        MediaStream(nxt_path, audio_parameters=AudioQuality.HIGH,
                                    video_flags=MediaStream.Flags.IGNORE)
                    )
                except Exception:
                    _vc_current.pop(cid, None)
            else:
                _vc_loop.pop(cid, None)
                try:
                    await client.leave_call(cid)
                except Exception:
                    pass

        _vc_calls.add_handler(_on_stream_end, tgfilters.stream_end)
        await _vc_calls.start()
        return True
    except Exception as e:
        _vc_client = None
        _vc_calls  = None
        raise RuntimeError(f"VC init failed: {e}")


async def _vc_ensure_joined(chat_id: int):
    """Make the userbot join the group if it is not already a member."""
    if _vc_client is None:
        return
    try:
        await _vc_client.get_chat(chat_id)
    except Exception:
        try:
            await _vc_client.join_chat(chat_id)
            await asyncio.sleep(1)
        except Exception:
            pass


async def _vc_play_next(chat_id: int) -> bool:
    """Internal: play next in queue. Returns True if next played, False if queue empty."""
    from pytgcalls.types import MediaStream, AudioQuality
    nxt = _vc_queue.get(chat_id, [])
    if not nxt:
        _vc_current.pop(chat_id, None)
        _vc_paused.pop(chat_id, None)
        try:
            await _vc_calls.leave_call(chat_id)
        except Exception:
            pass
        return False
    item = nxt.pop(0)
    nxt_title, nxt_path, nxt_req = item[0], item[1], item[2]
    nxt_dur = item[3] if len(item) > 3 else 0
    nxt_url = item[4] if len(item) > 4 else ""
    _vc_current[chat_id] = {
        "title": nxt_title, "filepath": nxt_path,
        "requested_by": nxt_req, "duration": nxt_dur, "url": nxt_url
    }
    _vc_paused.pop(chat_id, None)
    await _vc_calls.play(
        chat_id,
        MediaStream(nxt_path, audio_parameters=AudioQuality.HIGH,
                    video_flags=MediaStream.Flags.IGNORE)
    )
    return True


async def cmd_playvc(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Play a song in the group Voice Chat.
    Usage: /playvc <song name>  |  /playvc -f <song> (force play, skip queue)
    """
    import yt_dlp, os, shutil
    try:
        from pytgcalls.types import MediaStream, AudioQuality
    except ImportError:
        await update.message.reply_text(bq("❌ Voice Chat feature not available on this server."))
        return

    tg_user = update.effective_user
    chat    = update.effective_chat
    users   = load_users()
    user, uid = get_user(users, tg_user.id,
                         username=tg_user.username or "",
                         first_name=tg_user.first_name or "")

    if user["banned"]:
        sent = await update.message.reply_text(bq("⛔ You are banned."))
        schedule_delete(sent); return

    if chat.type not in ("group", "supergroup"):
        sent = await update.message.reply_text(
            bq("❌ /playvc only works in groups!\n\nAdd me to a group, start a Voice Chat, then use /playvc.")
        )
        schedule_delete(sent); return

    args = context.args or []
    force = False
    if args and args[0].lower() in ("-f", "--force", "force"):
        force = True
        args = args[1:]

    query_text = " ".join(args).strip()
    if not query_text:
        sent = await update.message.reply_text(
            "<blockquote>"
            "<b>🎙 SHUVO VC PLAYER 🎙</b>\n\n"
            "<b>Commands:</b>\n"
            "▶ /playvc &lt;song&gt; — Play song in VC\n"
            "▶ /playvc -f &lt;song&gt; — Force play (interrupt queue)\n"
            "📥 /push &lt;song&gt; — Add to queue\n"
            "⏸ /pausevc — Pause\n"
            "▶️ /resumevc — Resume\n"
            "⏭ /skipvc — Skip current\n"
            "⏹ /stopvc — Stop &amp; leave VC\n"
            "🔁 /loopvc — Toggle loop mode\n"
            "🔀 /shufflevc — Shuffle queue\n"
            "📋 /vcqueue — Show queue\n\n"
            "<b>ℹ️</b> Voice Chat must be <b>active</b> in the group!"
            "</blockquote>",
            parse_mode=ParseMode.HTML
        )
        schedule_delete(sent); return

    sent = await update.message.reply_text(
        f"<blockquote><b>🎙 VC Player</b>\n"
        f"🔎 Searching: <i>{_e(query_text)}</i>\n\n"
        f"⏳ Please wait...</blockquote>",
        parse_mode=ParseMode.HTML
    )

    tmp_dir = tempfile.mkdtemp()
    try:
        # Use Invidious to bypass YouTube bot-detection on server IPs
        filepath, info = await _invidious_dl(query_text, tmp_dir)

        _audio_exts = (".m4a", ".mp3", ".webm", ".opus", ".ogg", ".aac")
        if not os.path.exists(filepath):
            for f in os.listdir(tmp_dir):
                if f.endswith(_audio_exts):
                    filepath = os.path.join(tmp_dir, f)
                    break

        title    = (info.get("title")    or query_text)[:80]
        uploader = (info.get("uploader") or info.get("channel") or "YouTube")[:50]
        duration = int(info.get("duration") or 0)
        yt_url   = info.get("webpage_url") or info.get("url") or ""
        req_name = tg_user.first_name or tg_user.username or str(uid)

        await sent.edit_text(
            f"<blockquote><b>🎙 VC Player</b>\n"
            f"✅ Found: <b>{_e(title)}</b>\n\n"
            f"🔌 Connecting to Voice Chat...</blockquote>",
            parse_mode=ParseMode.HTML
        )
        await _vc_init()

        chat_id = chat.id
        await _vc_ensure_joined(chat_id)

        from pytgcalls.types import GroupCallConfig
        from pytgcalls.exceptions import NoActiveGroupCall

        already_playing = chat_id in _vc_current

        if already_playing and not force:
            # ── Add to queue ──
            _vc_queue.setdefault(chat_id, []).append(
                (title, filepath, req_name, duration, yt_url)
            )
            pos = len(_vc_queue[chat_id])
            dur_str = _vc_dur_fmt(duration)
            await sent.edit_text(
                f"<blockquote>"
                f"<b>📋 Added to Queue #{pos}</b>\n\n"
                f"<b>🎵</b> {_e(title)}\n"
                f"<b>🎤</b> {_e(uploader)}\n"
                f"<b>⏱</b> {dur_str}\n\n"
                f"<b>▶ Now Playing</b>: {_e(_vc_current[chat_id]['title'])}"
                f"</blockquote>",
                parse_mode=ParseMode.HTML,
                reply_markup=_vc_controls_kb(chat_id)
            )
            schedule_delete(sent, timeout=30)
            return

        if already_playing and force:
            # ── Force play: push current back to front of queue, play new ──
            cur = _vc_current[chat_id]
            _vc_queue.setdefault(chat_id, []).insert(0, (
                cur["title"], cur["filepath"], cur["requested_by"],
                cur.get("duration", 0), cur.get("url", "")
            ))

        # ── Play immediately ──
        thumb_url = info.get("thumbnail", "")
        _vc_current[chat_id] = {
            "title": title, "filepath": filepath,
            "requested_by": req_name, "duration": duration,
            "url": yt_url, "thumbnail": thumb_url,
        }
        _vc_paused.pop(chat_id, None)
        try:
            await _vc_calls.play(
                chat_id,
                MediaStream(filepath, audio_parameters=AudioQuality.HIGH,
                            video_flags=MediaStream.Flags.IGNORE),
                GroupCallConfig(auto_start=False),
            )
        except NoActiveGroupCall:
            _vc_current.pop(chat_id, None)
            shutil.rmtree(tmp_dir, ignore_errors=True)
            await sent.edit_text(
                "<blockquote>"
                "<b>❌ No Active Voice Chat!</b>\n\n"
                "Group-এ Voice Chat চালু নেই। Admin কে বলো Voice Chat start করতে।\n\n"
                "<b>Steps:</b>\n"
                "1️⃣ Group name tap করো → Voice Chat → Start\n"
                "2️⃣ তারপর আবার /playvc দাও\n\n"
                "<b><tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> Dev</b> @Shuvobhai"
                "</blockquote>",
                parse_mode=ParseMode.HTML
            )
            schedule_delete(sent)
            return

        dur_str  = _vc_dur_fmt(duration)
        q_count  = len(_vc_queue.get(chat_id, []))
        loop_lbl = {0: "Off", 1: "🔂 Single", 10: "🔁 Queue"}.get(_vc_loop.get(chat_id, 0), "Off")
        force_tag = "  ⚡ Force played" if (already_playing and force) else ""

        caption = (
            f"<b>🎙 SHUVO VC PLAYER{force_tag}</b>\n\n"
            f"<b>▶ Now Playing</b>\n"
            f"<b>🎵</b> {_e(title)}\n"
            f"<b>🎤</b> {_e(uploader)}\n"
            f"<b>⏱</b> {dur_str}  |  <b>👤</b> {_e(req_name)}\n\n"
            f"<b>📋 Queue</b>: {q_count}  |  <b>🔁 Loop</b>: {loop_lbl}"
        )

        # ── Generate now-playing thumbnail card ─────────────────────────────
        thumb_path = await _vc_make_thumb(title, uploader, dur_str, thumb_url)
        try:
            await sent.delete()
        except Exception:
            pass
        if thumb_path:
            import os as _os
            try:
                await update.message.reply_photo(
                    photo=thumb_path,
                    caption=caption,
                    parse_mode=ParseMode.HTML,
                    reply_markup=_vc_controls_kb(chat_id),
                )
            except Exception:
                await update.message.reply_text(
                    f"<blockquote>{caption}</blockquote>",
                    parse_mode=ParseMode.HTML,
                    reply_markup=_vc_controls_kb(chat_id),
                )
            finally:
                try:
                    _os.unlink(thumb_path)
                except Exception:
                    pass
        else:
            await update.message.reply_text(
                f"<blockquote>{caption}</blockquote>",
                parse_mode=ParseMode.HTML,
                reply_markup=_vc_controls_kb(chat_id),
            )

    except Exception as e:
        import traceback as _tb
        _tb.print_exc()
        err_raw = str(e)
        # Detect YouTube bot/cookie error and give clear guidance
        _needs_cookies = any(kw in err_raw.lower() for kw in [
            "sign in", "bot", "cookies", "confirm", "not a bot",
            "requested format is not available"
        ])
        try:
            if _needs_cookies:
                await sent.edit_text(
                    "<blockquote><b>🍪 YouTube Cookies Required!</b>\n\n"
                    "YouTube এই server-এ cookies ছাড়া video দিচ্ছে না।\n\n"
                    "<b>Fix করতে:</b>\n"
                    "1️⃣ Chrome-এ <b>youtube.com</b> login করো\n"
                    "2️⃣ <b>Get cookies.txt LOCALLY</b> extension দিয়ে Export করো\n"
                    "3️⃣ <a href='https://batbin.me'>batbin.me</a>-তে paste করো → raw link নাও\n"
                    "4️⃣ Send করো: <code>/cookievc https://batbin.me/raw/xxxxx</code>\n\n"
                    "<b>Admin only:</b> /cookievc command</blockquote>",
                    parse_mode=ParseMode.HTML,
                    disable_web_page_preview=True
                )
            else:
                await sent.edit_text(
                    f"<blockquote><b>❌ VC Play Failed!</b>\n\n"
                    f"<code>{_e(err_raw[:200])}</code>\n\n"
                    f"<b>Make sure:</b>\n"
                    f"• Voice Chat is <b>active</b> in the group\n"
                    f"• Userbot has joined the group\n\n"
                    f"<b><tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> Dev</b> @Shuvobhai</blockquote>",
                    parse_mode=ParseMode.HTML
                )
            schedule_delete(sent)
        except Exception:
            pass
        shutil.rmtree(tmp_dir, ignore_errors=True)


async def cmd_push(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/push <song> — Add a song to the VC queue (downloads in background, plays if nothing is on)."""
    import yt_dlp, os, shutil
    try:
        from pytgcalls.types import MediaStream, AudioQuality
    except ImportError:
        await update.message.reply_text(bq("❌ Voice Chat feature not available."))
        return

    tg_user = update.effective_user
    chat    = update.effective_chat
    users   = load_users()
    user, uid = get_user(users, tg_user.id,
                         username=tg_user.username or "",
                         first_name=tg_user.first_name or "")

    if user["banned"]:
        sent = await update.message.reply_text(bq("⛔ You are banned."))
        schedule_delete(sent); return

    if chat.type not in ("group", "supergroup"):
        sent = await update.message.reply_text(bq("❌ /push only works in groups!"))
        schedule_delete(sent); return

    args = context.args or []
    query_text = " ".join(args).strip()
    if not query_text:
        sent = await update.message.reply_text(
            bq("📥 Usage: /push <song name>\n\nAdds a song to the queue.\nExample: /push Believer Imagine Dragons"),
            parse_mode=ParseMode.HTML
        )
        schedule_delete(sent); return

    sent = await update.message.reply_text(
        f"<blockquote><b>📥 Queue Add</b>\n"
        f"🔎 Searching: <i>{_e(query_text)}</i>...</blockquote>",
        parse_mode=ParseMode.HTML
    )

    tmp_dir = tempfile.mkdtemp()
    try:
        # Use Invidious to bypass YouTube bot-detection on server IPs
        filepath, info = await _invidious_dl(query_text, tmp_dir)

        audio_exts = (".m4a", ".mp3", ".webm", ".opus", ".ogg", ".aac")
        if not os.path.exists(filepath):
            for f in os.listdir(tmp_dir):
                if f.endswith(audio_exts):
                    filepath = os.path.join(tmp_dir, f)
                    break

        title    = (info.get("title")    or query_text)[:80]
        uploader = (info.get("uploader") or info.get("channel") or "YouTube")[:50]
        duration = int(info.get("duration") or 0)
        yt_url   = info.get("webpage_url") or info.get("url") or ""
        req_name = tg_user.first_name or tg_user.username or str(uid)
        chat_id  = chat.id
        dur_str  = _vc_dur_fmt(duration)

        # If something is playing, add to queue
        if _vc_calls is not None and chat_id in _vc_current:
            _vc_queue.setdefault(chat_id, []).append(
                (title, filepath, req_name, duration, yt_url)
            )
            pos = len(_vc_queue[chat_id])
            await sent.edit_text(
                f"<blockquote>"
                f"<b>📥 Added to Queue #{pos}</b>\n\n"
                f"<b>🎵</b> {_e(title)}\n"
                f"<b>🎤</b> {_e(uploader)}\n"
                f"<b>⏱</b> {dur_str}\n\n"
                f"<b>▶ Now Playing</b>: {_e(_vc_current[chat_id]['title'])}"
                f"</blockquote>",
                parse_mode=ParseMode.HTML,
                reply_markup=_vc_controls_kb(chat_id)
            )
            schedule_delete(sent, timeout=60)
            return

        # Nothing playing — initialize VC and play immediately
        await sent.edit_text(
            f"<blockquote><b>📥 Queue Add</b>\n✅ Found: <b>{_e(title)}</b>\n\n🔌 Connecting to VC...</blockquote>",
            parse_mode=ParseMode.HTML
        )
        await _vc_init()
        await _vc_ensure_joined(chat_id)

        from pytgcalls.types import GroupCallConfig
        vc_call = await _vc_calls.get_full_chat(chat_id)
        if vc_call is None:
            await sent.edit_text(
                "<blockquote><b>❌ No Active Voice Chat!</b>\n\nStart a Voice Chat in this group first, then use /push.</blockquote>",
                parse_mode=ParseMode.HTML
            )
            schedule_delete(sent)
            shutil.rmtree(tmp_dir, ignore_errors=True)
            return

        _vc_current[chat_id] = {
            "title": title, "filepath": filepath,
            "requested_by": req_name, "duration": duration, "url": yt_url
        }
        _vc_paused.pop(chat_id, None)
        await _vc_calls.play(
            chat_id,
            MediaStream(filepath, audio_parameters=AudioQuality.HIGH,
                        video_flags=MediaStream.Flags.IGNORE),
            GroupCallConfig(auto_start=False),
        )
        await sent.edit_text(
            f"<blockquote>"
            f"<b>▶ Now Playing</b>\n"
            f"<b>🎵</b> {_e(title)}\n"
            f"<b>🎤</b> {_e(uploader)}\n"
            f"<b>⏱</b> {dur_str}\n"
            f"<b><tg-emoji emoji-id='5166063676687385916'>👤</tg-emoji></b> {_e(req_name)}"
            f"</blockquote>",
            parse_mode=ParseMode.HTML,
            reply_markup=_vc_controls_kb(chat_id)
        )

    except Exception as e:
        err = str(e)[:200]
        try:
            await sent.edit_text(
                f"<blockquote><b>❌ Push Failed!</b>\n\n<code>{_e(err)}</code></blockquote>",
                parse_mode=ParseMode.HTML
            )
            schedule_delete(sent)
        except Exception:
            pass
        shutil.rmtree(tmp_dir, ignore_errors=True)


async def cmd_cookievc(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/cookievc <url> — Admin: update YouTube cookies from a URL (pastebin/batbin raw link)."""
    tg_user = update.effective_user
    users   = load_users()
    user, uid = get_user(users, tg_user.id,
                         username=tg_user.username or "",
                         first_name=tg_user.first_name or "")

    if not user.get("admin") and not user.get("owner"):
        sent = await update.message.reply_text(bq("⛔ Admin only command."))
        schedule_delete(sent); return

    args = context.args or []
    if not args:
        sent = await update.message.reply_text(
            bq("🍪 Usage: /cookievc <raw_url>\n\nExample:\n/cookievc https://pastebin.com/raw/xxxxxx\n\nDownloads the cookie file from the URL and saves it for YouTube yt-dlp."),
        )
        schedule_delete(sent); return

    url = args[0].strip()
    sent = await update.message.reply_text(bq("⏳ Downloading cookies..."))

    try:
        import aiohttp
        async with aiohttp.ClientSession() as session:
            async with session.get(url, timeout=aiohttp.ClientTimeout(total=20)) as resp:
                if resp.status != 200:
                    await sent.edit_text(bq(f"❌ HTTP {resp.status} — could not fetch cookies from that URL."))
                    schedule_delete(sent); return
                content = await resp.read()
                if not content or len(content) < 30:
                    await sent.edit_text(bq("❌ Cookie file is empty or too small. Check the URL."))
                    schedule_delete(sent); return
                os.makedirs("bot", exist_ok=True)
                with open(YOUTUBE_COOKIES_FILE, "wb") as fw:
                    fw.write(content)
        size_kb = len(content) // 1024
        await sent.edit_text(
            bq(f"✅ Cookies updated!\n\nSaved {size_kb} KB to {YOUTUBE_COOKIES_FILE}\n\nYouTube downloads will now use the new cookies.")
        )
    except Exception as e:
        await sent.edit_text(bq(f"❌ Failed to update cookies: {e}"))
        schedule_delete(sent)


async def cmd_stopvc(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Stop VC playback and leave the voice chat."""
    chat = update.effective_chat
    if chat.type not in ("group", "supergroup"):
        sent = await update.message.reply_text(bq("❌ Only works in groups."))
        schedule_delete(sent); return

    chat_id = chat.id
    if _vc_calls is None or chat_id not in _vc_current:
        sent = await update.message.reply_text(bq("❌ Nothing is playing right now."))
        schedule_delete(sent); return

    try:
        await _vc_calls.leave_call(chat_id)
    except Exception:
        pass
    _vc_current.pop(chat_id, None)
    _vc_queue.pop(chat_id, None)
    _vc_paused.pop(chat_id, None)
    _vc_loop.pop(chat_id, None)
    sent = await update.message.reply_text(
        bq("⏹ Stopped! Left the Voice Chat.\n\nUse /playvc to play again.")
    )
    schedule_delete(sent)


async def cmd_skipvc(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Skip current track and play next in queue."""
    try:
        from pytgcalls.types import MediaStream, AudioQuality
    except ImportError:
        await update.message.reply_text(bq("❌ Voice Chat feature not available."))
        return

    chat = update.effective_chat
    if chat.type not in ("group", "supergroup"):
        sent = await update.message.reply_text(bq("❌ Only works in groups."))
        schedule_delete(sent); return

    chat_id = chat.id
    if _vc_calls is None or chat_id not in _vc_current:
        sent = await update.message.reply_text(bq("❌ Nothing is playing right now."))
        schedule_delete(sent); return

    # If loop=single, disable it so skip actually works
    if _vc_loop.get(chat_id) == 1:
        _vc_loop[chat_id] = 0

    skipped_title = _vc_current[chat_id]["title"]
    try:
        played = await _vc_play_next(chat_id)
    except Exception as ex:
        sent = await update.message.reply_text(bq(f"❌ Skip failed: {ex}"))
        schedule_delete(sent); return

    if played:
        cur = _vc_current[chat_id]
        sent = await update.message.reply_text(
            f"<blockquote><b>⏭ Skipped!</b>\n\n"
            f"<b>▶ Now Playing</b>: {_e(cur['title'])}\n"
            f"<b>⏱ Duration</b>: {_vc_dur_fmt(cur.get('duration', 0))}\n"
            f"<b>📋 Queue left</b>: {len(_vc_queue.get(chat_id, []))}</blockquote>",
            parse_mode=ParseMode.HTML,
            reply_markup=_vc_controls_kb(chat_id)
        )
    else:
        sent = await update.message.reply_text(bq(f"⏭ Skipped {skipped_title!r}. Queue empty — stopped VC."))
    schedule_delete(sent, timeout=30)


