async def cmd_loopvc(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Toggle loop mode for VC. Usage: /loopvc  |  /loopvc off|single|queue"""
    chat = update.effective_chat
    if chat.type not in ("group", "supergroup"):
        sent = await update.message.reply_text(bq("❌ Only works in groups."))
        schedule_delete(sent); return

    chat_id = chat.id
    args = (context.args or [])
    cur_loop = _vc_loop.get(chat_id, 0)

    if args:
        arg = args[0].lower()
        if arg in ("0", "off", "disable"):
            new_loop = 0
        elif arg in ("1", "single", "one"):
            new_loop = 1
        elif arg in ("10", "queue", "all"):
            new_loop = 10
        else:
            sent = await update.message.reply_text(
                "<blockquote><b>🔁 Loop Mode</b>\n\n"
                "<b>Usage:</b>\n"
                "• /loopvc — Cycle through modes\n"
                "• /loopvc off — Disable loop\n"
                "• /loopvc single — Loop current track\n"
                "• /loopvc queue — Loop entire queue</blockquote>",
                parse_mode=ParseMode.HTML
            )
            schedule_delete(sent); return
    else:
        # Cycle: off → single → queue → off
        cycle = {0: 1, 1: 10, 10: 0}
        new_loop = cycle.get(cur_loop, 0)

    _vc_loop[chat_id] = new_loop
    labels = {0: "➡️ Loop Off", 1: "🔂 Single Track", 10: "🔁 Entire Queue"}
    desc   = {
        0: "Each track plays once and moves to next.",
        1: "Current track will repeat forever.",
        10: "Queue will repeat after the last track."
    }
    sent = await update.message.reply_text(
        f"<blockquote><b>{labels[new_loop]}</b>\n\n"
        f"{desc[new_loop]}</blockquote>",
        parse_mode=ParseMode.HTML
    )
    schedule_delete(sent, timeout=15)


async def cmd_seekvc(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Seek forward in current VC track. Usage: /seekvc <seconds>"""
    await _seekvc_handler(update, context, backward=False)


async def cmd_seekvcback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Seek backward in current VC track. Usage: /seekvcback <seconds>"""
    await _seekvc_handler(update, context, backward=True)


async def _seekvc_handler(update: Update, context: ContextTypes.DEFAULT_TYPE, backward: bool):
    """Shared seek logic for /seekvc and /seekvcback."""
    import yt_dlp, os, shutil
    try:
        from pytgcalls.types import MediaStream, AudioQuality
    except ImportError:
        await update.message.reply_text(bq("❌ Voice Chat feature not available."))
        return

    chat = update.effective_chat
    if chat.type not in ("group", "supergroup"):
        sent = await update.message.reply_text(bq("❌ Only works in groups."))
        schedule_delete(sent); return

    chat_id = chat.id
    if _vc_calls is None or chat_id not in _vc_current:
        sent = await update.message.reply_text(bq("❌ Nothing is playing right now."))
        schedule_delete(sent); return

    if _vc_paused.get(chat_id):
        sent = await update.message.reply_text(bq("❌ Cannot seek while paused. Resume first."))
        schedule_delete(sent); return

    args = context.args or []
    if not args:
        cmd = "seekvcback" if backward else "seekvc"
        sent = await update.message.reply_text(bq(f"Usage: /{cmd} <seconds>\nExample: /{cmd} 30"))
        schedule_delete(sent); return

    try:
        secs = int(args[0])
        if secs < 5:
            raise ValueError
    except ValueError:
        sent = await update.message.reply_text(bq("❌ Please provide a valid number of seconds (minimum 5)."))
        schedule_delete(sent); return

    cur = _vc_current[chat_id]
    cur_dur = cur.get("duration", 0)
    # We track position via a simple timestamp offset stored in current
    cur_pos = cur.get("seek_pos", 0)

    if backward:
        new_pos = max(0, cur_pos - secs)
        direction = "⏪ Backward"
    else:
        new_pos = cur_pos + secs
        if cur_dur and new_pos >= cur_dur - 5:
            new_pos = max(0, cur_dur - 10)
        direction = "⏩ Forward"

    sent = await update.message.reply_text(
        f"<blockquote>⏩ Seeking {direction} {secs}s...</blockquote>",
        parse_mode=ParseMode.HTML
    )

    try:
        cur_filepath = cur["filepath"]
        cur_yt_url  = cur.get("url", "")

        # Re-download from seek position if we have the YT URL
        # Otherwise re-stream from existing file with ffmpeg offset
        if cur_yt_url and new_pos > 0:
            # Re-download with time offset using yt-dlp postprocessor
            tmp_dir = tempfile.mkdtemp()
            loop = asyncio.get_event_loop()

            def _dl_seek():
                dl_opts = _yt_base_opts({
                    "format": "bestaudio/best",
                    "outtmpl": os.path.join(tmp_dir, "%(title).60s.%(ext)s"),
                    "download_ranges": yt_dlp.utils.download_range_func(
                        [], [[new_pos, float("inf")]]
                    ) if new_pos > 0 else None,
                    "force_keyframes_at_cuts": True,
                })
                # Clean None values
                dl_opts = {k: v for k, v in dl_opts.items() if v is not None}
                with yt_dlp.YoutubeDL(dl_opts) as ydl:
                    info = ydl.extract_info(cur_yt_url, download=True)
                    audio_exts = (".m4a", ".mp3", ".webm", ".opus", ".ogg", ".aac")
                    for f in os.listdir(tmp_dir):
                        if f.endswith(audio_exts):
                            return os.path.join(tmp_dir, f)
                return None

            new_filepath = await loop.run_in_executor(None, _dl_seek)
            if not new_filepath:
                await sent.edit_text(bq("❌ Seek failed: could not re-download from position."))
                shutil.rmtree(tmp_dir, ignore_errors=True)
                return
        else:
            # Use existing file — pytgcalls MediaStream with ffmpeg_parameters
            new_filepath = cur_filepath
            tmp_dir = None

        await _vc_calls.play(
            chat_id,
            MediaStream(
                new_filepath,
                audio_parameters=AudioQuality.HIGH,
                video_flags=MediaStream.Flags.IGNORE,
                *([] if new_pos == 0 else []),
            )
        )
        cur["seek_pos"] = new_pos
        cur["filepath"] = new_filepath

        pos_str = _vc_dur_fmt(new_pos)
        await sent.edit_text(
            f"<blockquote><b>{direction} {secs}s</b>\n\n"
            f"<b>🎵</b> {_e(cur['title'])}\n"
            f"<b>📍 Position</b>: {pos_str}</blockquote>",
            parse_mode=ParseMode.HTML
        )
        schedule_delete(sent, timeout=15)

    except Exception as ex:
        await sent.edit_text(bq(f"❌ Seek failed: {str(ex)[:150]}"))
        schedule_delete(sent)


async def cmd_shufflevc(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Shuffle the VC queue. Usage: /shufflevc"""
    import random
    chat = update.effective_chat
    if chat.type not in ("group", "supergroup"):
        sent = await update.message.reply_text(bq("❌ Only works in groups."))
        schedule_delete(sent); return

    chat_id = chat.id
    if chat_id not in _vc_current:
        sent = await update.message.reply_text(bq("❌ Nothing is playing right now."))
        schedule_delete(sent); return

    q = _vc_queue.get(chat_id, [])
    if len(q) < 2:
        sent = await update.message.reply_text(
            bq("⚠️ Need at least 2 tracks in queue to shuffle!")
        )
        schedule_delete(sent); return

    random.shuffle(q)
    _vc_queue[chat_id] = q

    # Show shuffled queue preview
    preview = "\n".join(
        f"  {i}. {_e(item[0])}"
        for i, item in enumerate(q[:8], 1)
    )
    if len(q) > 8:
        preview += f"\n  ... and {len(q)-8} more"

    sent = await update.message.reply_text(
        f"<blockquote><b>🔀 Queue Shuffled!</b>\n\n"
        f"<b>{len(q)} tracks</b> randomized\n\n"
        f"{preview}</blockquote>",
        parse_mode=ParseMode.HTML
    )
    schedule_delete(sent, timeout=20)


