# ── VC Auth helpers ───────────────────────────────────────────────────────────

def _vc_auth_add(chat_id: int, user_id: int):
    _vc_auth.setdefault(chat_id, set()).add(user_id)

def _vc_auth_remove(chat_id: int, user_id: int):
    _vc_auth.setdefault(chat_id, set()).discard(user_id)

def _vc_is_authorized(chat_id: int, user_id: int) -> bool:
    return user_id in _vc_auth.get(chat_id, set())


async def cmd_authvc(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/authvc <reply|username|id> — Authorize a user to control VC (admin only)."""
    msg  = update.message
    chat = update.effective_chat
    user = update.effective_user
    if not user or chat.type not in ("group", "supergroup"):
        return

    # Must be admin
    member = await context.bot.get_chat_member(chat.id, user.id)
    if member.status not in ("administrator", "creator"):
        sent = await msg.reply_text(bq("❌ Only group admins can authorize VC users."))
        schedule_delete(sent); return

    # Resolve target user
    target_id = None
    if msg.reply_to_message and msg.reply_to_message.from_user:
        target_id = msg.reply_to_message.from_user.id
    elif context.args:
        arg = context.args[0].lstrip("@")
        try:
            target_id = int(arg)
        except ValueError:
            try:
                t = await context.bot.get_chat(arg)
                target_id = t.id
            except Exception:
                pass

    if not target_id:
        sent = await msg.reply_text(bq("❌ Reply to a user or provide their @username / ID.\nUsage: /authvc @user"))
        schedule_delete(sent); return

    _vc_auth_add(chat.id, target_id)
    sent = await msg.reply_text(
        f"<blockquote>✅ <b>VC Auth granted</b>\n\n"
        f"User <code>{target_id}</code> can now control music in this group.\n\n"
        f"<i>Revoke with /unauthvc</i></blockquote>",
        parse_mode=ParseMode.HTML
    )
    schedule_delete(sent, timeout=30)


async def cmd_unauthvc(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/unauthvc <reply|username|id> — Revoke VC control from a user (admin only)."""
    msg  = update.message
    chat = update.effective_chat
    user = update.effective_user
    if not user or chat.type not in ("group", "supergroup"):
        return

    member = await context.bot.get_chat_member(chat.id, user.id)
    if member.status not in ("administrator", "creator"):
        sent = await msg.reply_text(bq("❌ Only group admins can revoke VC auth."))
        schedule_delete(sent); return

    target_id = None
    if msg.reply_to_message and msg.reply_to_message.from_user:
        target_id = msg.reply_to_message.from_user.id
    elif context.args:
        arg = context.args[0].lstrip("@")
        try:
            target_id = int(arg)
        except ValueError:
            try:
                t = await context.bot.get_chat(arg)
                target_id = t.id
            except Exception:
                pass

    if not target_id:
        sent = await msg.reply_text(bq("❌ Reply to a user or provide their @username / ID."))
        schedule_delete(sent); return

    _vc_auth_remove(chat.id, target_id)
    sent = await msg.reply_text(
        f"<blockquote>🚫 <b>VC Auth revoked</b>\n\nUser <code>{target_id}</code> can no longer control music.</blockquote>",
        parse_mode=ParseMode.HTML
    )
    schedule_delete(sent, timeout=20)


async def cmd_authvclist(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/authvclist — Show authorized VC users for this group."""
    chat = update.effective_chat
    if chat.type not in ("group", "supergroup"):
        return

    auth_set = _vc_auth.get(chat.id, set())
    if not auth_set:
        sent = await update.message.reply_text(
            bq("📋 No authorized VC users.\n\nUse /authvc to grant control to non-admins.")
        )
        schedule_delete(sent); return

    lines = ["<blockquote><b>📋 Authorized VC Users</b>\n"]
    for i, uid in enumerate(auth_set, 1):
        lines.append(f"  {i}. <a href='tg://user?id={uid}'>{uid}</a>")
    lines.append("</blockquote>")
    sent = await update.message.reply_text(
        "\n".join(lines), parse_mode=ParseMode.HTML,
        disable_web_page_preview=True
    )
    schedule_delete(sent, timeout=30)


async def cmd_activevc(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/activevc — List all groups where VC is currently active (owner only)."""
    from bot.config import OWNER_ID as _OID
    uid = update.effective_user.id if update.effective_user else 0
    try:
        owner_ids = {int(x) for x in str(_OID).split(",")} if _OID else set()
    except Exception:
        owner_ids = set()

    if uid not in owner_ids:
        sent = await update.message.reply_text(bq("❌ Owner only command."))
        schedule_delete(sent); return

    if not _vc_current:
        sent = await update.message.reply_text(bq("📻 No active Voice Chats right now."))
        schedule_delete(sent); return

    lines = ["<blockquote><b>📻 Active Voice Chats</b>\n"]
    for i, (cid, info) in enumerate(_vc_current.items(), 1):
        title   = info.get("title", "?")[:40]
        dur     = _vc_dur_fmt(info.get("duration", 0))
        q_count = len(_vc_queue.get(cid, []))
        paused  = "⏸" if _vc_paused.get(cid) else "▶️"
        lines.append(f"  {i}. <code>{cid}</code>  {paused}  {_e(title)}  [{dur}]  Queue: {q_count}")
    lines.append(f"\n<b>Total:</b> {len(_vc_current)}</blockquote>")

    sent = await update.message.reply_text(
        "\n".join(lines), parse_mode=ParseMode.HTML
    )
    schedule_delete(sent, timeout=60)


async def cmd_setcookievc(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/setcookievc — Paste YouTube cookies directly (Netscape format). Admin only."""
    import os
    msg  = update.message
    user = update.effective_user
    chat = update.effective_chat
    if not user:
        return

    from bot.config import OWNER_ID as _OID, ADMIN_ID as _AID
    try:
        _allowed = {int(x) for x in f"{_OID},{_AID}".split(",") if x.strip()}
    except Exception:
        _allowed = set()

    # Also allow group admins in group context
    is_allowed = user.id in _allowed
    if not is_allowed and chat and chat.type in ("group", "supergroup"):
        try:
            m = await context.bot.get_chat_member(chat.id, user.id)
            is_allowed = m.status in ("administrator", "creator")
        except Exception:
            pass

    if not is_allowed:
        sent = await msg.reply_text(bq("❌ Admin only command."))
        schedule_delete(sent); return

    # Get cookie text from message body (everything after the command)
    raw_text = msg.text or ""
    parts = raw_text.split(None, 1)
    cookie_text = parts[1].strip() if len(parts) > 1 else ""

    # Also check replied-to message
    if not cookie_text and msg.reply_to_message:
        cookie_text = (msg.reply_to_message.text or msg.reply_to_message.caption or "").strip()

    if not cookie_text or "# Netscape HTTP Cookie File" not in cookie_text[:50]:
        sent = await msg.reply_text(
            "<blockquote><b>🍪 Set YouTube Cookies</b>\n\n"
            "Paste the full cookie content (Netscape format) directly after the command:\n\n"
            "<code>/setcookievc # Netscape HTTP Cookie File\n"
            ".youtube.com TRUE / FALSE ...</code>\n\n"
            "Or reply to a message that contains the cookie text.\n\n"
            "<b>How to get cookies:</b>\n"
            "1. Open youtube.com and log in\n"
            "2. Use <b>Get cookies.txt LOCALLY</b> Chrome extension\n"
            "3. Export → copy all text → paste here</blockquote>",
            parse_mode=ParseMode.HTML
        )
        schedule_delete(sent); return

    cookie_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "bot", "yt_cookies.txt")
    os.makedirs(os.path.dirname(cookie_path), exist_ok=True)
    with open(cookie_path, "w", encoding="utf-8") as f:
        f.write(cookie_text)

    sent = await msg.reply_text(
        f"<blockquote>✅ <b>YouTube cookies saved!</b>\n\n"
        f"<b>{cookie_text.count(chr(10))} lines</b> of cookies stored.\n"
        f"Future /playvc requests will use them automatically.\n\n"
        f"<i>Delete with /delcookievc</i></blockquote>",
        parse_mode=ParseMode.HTML
    )
    schedule_delete(sent, timeout=30)


async def cmd_delcookievc(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/delcookievc — Delete saved YouTube cookies. Admin only."""
    import os
    user = update.effective_user
    if not user:
        return

    from bot.config import OWNER_ID as _OID, ADMIN_ID as _AID
    try:
        _allowed = {int(x) for x in f"{_OID},{_AID}".split(",") if x.strip()}
    except Exception:
        _allowed = set()

    if user.id not in _allowed:
        sent = await update.message.reply_text(bq("❌ Admin only command."))
        schedule_delete(sent); return

    cookie_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "bot", "yt_cookies.txt")
    if os.path.exists(cookie_path):
        os.unlink(cookie_path)
        sent = await update.message.reply_text(bq("🗑 YouTube cookies deleted. yt-dlp will work without cookies now."))
    else:
        sent = await update.message.reply_text(bq("ℹ️ No cookies file found."))
    schedule_delete(sent)


async def _vc_inline_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle inline button taps for VC player controls."""
    query = update.callback_query
    data  = query.data or ""
    await query.answer()

    if data.startswith("vc_pp_"):
        chat_id = int(data.split("_")[2])
        if chat_id not in _vc_current:
            await query.answer("❌ Nothing playing!", show_alert=True); return
        if _vc_paused.get(chat_id):
            try:
                await _vc_calls.resume(chat_id)
                _vc_paused[chat_id] = False
                await query.answer("▶️ Resumed!")
            except Exception as ex:
                await query.answer(f"❌ {ex}", show_alert=True); return
        else:
            try:
                await _vc_calls.pause(chat_id)
                _vc_paused[chat_id] = True
                await query.answer("⏸ Paused!")
            except Exception as ex:
                await query.answer(f"❌ {ex}", show_alert=True); return
        try:
            await query.edit_message_reply_markup(reply_markup=_vc_controls_kb(chat_id))
        except Exception:
            pass

    elif data.startswith("vc_skip_"):
        chat_id = int(data.split("_")[2])
        if chat_id not in _vc_current:
            await query.answer("❌ Nothing playing!", show_alert=True); return
        if _vc_loop.get(chat_id) == 1:
            _vc_loop[chat_id] = 0
        try:
            played = await _vc_play_next(chat_id)
            if played:
                cur = _vc_current[chat_id]
                await query.answer(f"⏭ Now: {cur['title'][:40]}")
                try:
                    await query.edit_message_reply_markup(reply_markup=_vc_controls_kb(chat_id))
                except Exception:
                    pass
            else:
                await query.answer("⏭ Queue empty — stopped!")
        except Exception as ex:
            await query.answer(f"❌ {ex}", show_alert=True)

    elif data.startswith("vc_stop_"):
        chat_id = int(data.split("_")[2])
        try:
            await _vc_calls.leave_call(chat_id)
        except Exception:
            pass
        _vc_current.pop(chat_id, None)
        _vc_queue.pop(chat_id, None)
        _vc_paused.pop(chat_id, None)
        _vc_loop.pop(chat_id, None)
        await query.answer("⏹ Stopped!")
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass

    elif data.startswith("vc_loop_"):
        chat_id  = int(data.split("_")[2])
        cur_loop = _vc_loop.get(chat_id, 0)
        cycle    = {0: 1, 1: 10, 10: 0}
        new_loop = cycle.get(cur_loop, 0)
        _vc_loop[chat_id] = new_loop
        labels = {0: "Loop Off", 1: "🔂 Single", 10: "🔁 Queue"}
        await query.answer(f"Loop: {labels[new_loop]}")
        try:
            await query.edit_message_reply_markup(reply_markup=_vc_controls_kb(chat_id))
        except Exception:
            pass

    elif data.startswith("vc_shuffle_"):
        import random
        chat_id = int(data.split("_")[2])
        q = _vc_queue.get(chat_id, [])
        if len(q) < 2:
            await query.answer("⚠️ Need 2+ tracks to shuffle!", show_alert=True); return
        random.shuffle(q)
        _vc_queue[chat_id] = q
        await query.answer(f"🔀 Shuffled {len(q)} tracks!")

    elif data.startswith("vc_queue_"):
        chat_id = int(data.split("_")[2])
        current = _vc_current.get(chat_id)
        if not current:
            await query.answer("❌ Nothing playing!", show_alert=True); return
        q = _vc_queue.get(chat_id, [])
        preview = f"▶ {current['title'][:35]}\n"
        if q:
            preview += "\n".join(f"{i}. {item[0][:30]}" for i, item in enumerate(q[:5], 1))
            if len(q) > 5:
                preview += f"\n+{len(q)-5} more"
        else:
            preview += "(queue empty)"
        await query.answer(preview, show_alert=True)


