async def _do_yt_download(update: Update, url: str, uid: str, users: dict):
    """Step 1 — fetch video info and show quality selector buttons."""
    import yt_dlp, asyncio
    sent = await update.message.reply_text(
        bq("🔍 Fetching video info..."), parse_mode=ParseMode.HTML
    )

    # Normalize URL → canonical watch URL so YouTube extractor (not generic) is always used.
    # youtu.be/xxx, youtube.com/shorts/xxx, youtube.com/embed/xxx → youtube.com/watch?v=xxx
    import re as _re
    _vid_match = _re.search(
        r"(?:youtu\.be/|youtube\.com/(?:shorts|embed|watch\?v=|v/))([A-Za-z0-9_-]{11})",
        url
    )
    canonical_url = f"https://www.youtube.com/watch?v={_vid_match.group(1)}" if _vid_match else url

    def _extract():
        # DO NOT use cookies here — cookies trigger the web client which needs PO tokens
        # on server IPs, blocking all formats. Without cookies, android client provides
        # format 18 (360p mp4) reliably even with SABR experiment.
        base = {
            "quiet": True, "no_warnings": True, "noplaylist": True,
            "socket_timeout": 30, "retries": 3,
            "geo_bypass": True, "nocheckcertificate": True,
            "extractor_args": {"youtube": {
                "player_client": ["tv_embedded", "ios", "android", "mweb"],
                "skip": ["webpage"],
            }},
        }
        with yt_dlp.YoutubeDL(base) as ydl:
            return ydl.extract_info(canonical_url, download=False)

    loop = asyncio.get_event_loop()
    try:
        info = await loop.run_in_executor(None, _extract)
    except Exception as e:
        await sent.edit_text(
            bq(f"❌ Could not fetch video info:\n{str(e)[:250]}\n\n😎 DEV @Shuvobhai"),
            parse_mode=ParseMode.HTML
        )
        return

    title    = (info.get("title") or "Video")[:60]
    duration = info.get("duration") or 0
    uploader = info.get("channel") or info.get("uploader") or "YouTube"

    # Build quality buttons from real available formats
    fmts = [
        f for f in (info.get("formats") or [])
        if f.get("vcodec") not in (None, "none")
        and f.get("ext") in ("mp4", "webm", "m4v", "3gp")
        and f.get("url")
    ]
    seen, quality_btns = set(), []
    _q_styles = ["primary", "primary", "primary", "primary", "primary"]
    for f in sorted(fmts, key=lambda x: (x.get("height") or 0), reverse=True):
        h_px = f.get("height") or 0
        label_key = h_px or f.get("format_id", "?")
        if label_key in seen:
            continue
        seen.add(label_key)
        fmt_id  = f["format_id"]
        ext     = f.get("ext") or "mp4"
        sz      = f.get("filesize") or f.get("filesize_approx") or 0
        sz_str  = f" · {sz//(1024*1024)}MB" if sz > 1_000_000 else ""
        label   = f"📹 {h_px}p {ext.upper()}{sz_str}" if h_px else f"📹 {fmt_id} {ext.upper()}{sz_str}"
        quality_btns.append(SBtn(label, style="primary", callback_data=f"ytdl_q_{uid}_{fmt_id}"))
        if len(quality_btns) >= 5:
            break

    quality_btns.append(SBtn("✅ Best Available", style="success", callback_data=f"ytdl_q_{uid}_best"))
    quality_btns.append(SBtn("❌ Cancel",         style="danger",  callback_data=f"ytdl_q_{uid}_cancel"))

    rows = [quality_btns[i:i+2] for i in range(0, len(quality_btns), 2)]
    kb   = InlineKeyboardMarkup(rows)

    _ytdl_sessions[uid] = {
        "url": url, "chat_id": update.effective_chat.id,
        "title": title, "duration": duration, "uploader": uploader,
    }

    dur_str = f"{duration//60}m {duration%60}s" if duration else "?"
    await sent.edit_text(
        bq(f"🎬 {title}\n👤 {uploader}  •  ⏱ {dur_str}\n\n📥 Select quality to download:"),
        parse_mode=ParseMode.HTML, reply_markup=kb
    )


async def _do_yt_download_fmt(update: Update, context, query, uid: str):
    """Step 2 — download chosen format and send the video file."""
    import yt_dlp, asyncio, shutil
    session  = _ytdl_sessions.get(uid, {})
    url      = session.get("url", "")
    title    = session.get("title", "Video")
    duration = session.get("duration", 0)
    uploader = session.get("uploader", "YouTube")

    # callback_data = ytdl_q_<uid>_<fmt_id>
    fmt_id = query.data.split(f"ytdl_q_{uid}_", 1)[-1]

    if fmt_id == "cancel":
        try:
            await query.message.delete()
        except Exception:
            pass
        _ytdl_sessions.pop(uid, None)
        return

    try:
        await query.message.edit_text(bq("⬇️ Downloading video…"), parse_mode=ParseMode.HTML)
    except Exception:
        pass

    # Normalize URL to canonical form (same as step 1)
    import re as _re2
    _vm = _re2.search(
        r"(?:youtu\.be/|youtube\.com/(?:shorts|embed|watch\?v=|v/))([A-Za-z0-9_-]{11})",
        url
    )
    canonical_url = f"https://www.youtube.com/watch?v={_vm.group(1)}" if _vm else url

    tmp_dir  = tempfile.mkdtemp()
    out_tmpl = os.path.join(tmp_dir, "%(title).60s.%(ext)s")

    fmt_str = "best[ext=mp4]/best" if fmt_id == "best" else f"{fmt_id}/best[ext=mp4]/best"
    # Same rule as step 1: NO cookies — they block android formats via web-client PO-token requirement
    opts = {
        "quiet": True, "no_warnings": True, "noplaylist": True,
        "socket_timeout": 60, "retries": 3, "geo_bypass": True,
        "nocheckcertificate": True, "format": fmt_str,
        "outtmpl": out_tmpl, "merge_output_format": "mp4",
        "extractor_args": {"youtube": {
            "player_client": ["tv_embedded", "ios", "android", "mweb"],
            "skip": ["webpage"],
        }},
        "postprocessors": [{"key": "FFmpegVideoConvertor", "preferedformat": "mp4"}],
    }

    loop = asyncio.get_event_loop()
    try:
        def _dl():
            with yt_dlp.YoutubeDL(opts) as ydl:
                dl_info = ydl.extract_info(canonical_url, download=True)
                fp = ydl.prepare_filename(dl_info)
                for bad_ext in (".webm", ".mkv"):
                    fp = fp.replace(bad_ext, ".mp4")
                return fp, dl_info

        filepath, dl_info = await loop.run_in_executor(None, _dl)

        # Fallback: pick any file in tmp dir
        if not os.path.exists(filepath):
            for fn in os.listdir(tmp_dir):
                filepath = os.path.join(tmp_dir, fn)
                break

        fsize = os.path.getsize(filepath)
        if fsize > 50 * 1024 * 1024:
            raise Exception(f"File too large ({fsize//(1024*1024)} MB). Pick a lower quality.")

        vtitle   = (dl_info.get("title") or title)[:80]
        dur      = dl_info.get("duration") or duration
        vup      = dl_info.get("uploader") or dl_info.get("channel") or uploader
        dur_str  = f"{dur//60}m {dur%60}s" if dur else "?"

        caption = (
            "<blockquote>"
            "<b>⚡ SHUVO DOWNLOAD ⚡</b>\n\n"
            f"<b>📹 Title</b>    : {_e(vtitle)}\n"
            f"<b>👤 Channel</b>  : {_e(vup)}\n"
            f"<b>⭐ Source</b>   : YouTube\n"
            f"<b>⏱ Duration</b> : {dur_str}\n\n"
            "<b>✅ Downloaded successfully!</b>\n\n"
            "<b>🥫 Dev</b> : @Shuvobhai"
            "</blockquote>"
        )
        _chat_id = session.get("chat_id") or query.message.chat_id
        try:
            await query.message.delete()
        except Exception:
            pass
        with open(filepath, "rb") as vf:
            await context.bot.send_video(
                chat_id=_chat_id,
                video=vf, caption=caption,
                parse_mode=ParseMode.HTML,
                reply_markup=after_result_keyboard(),
                supports_streaming=True,
            )
    except Exception as e:
        err_msg = str(e)[:300]
        _chat_id = session.get("chat_id") or query.message.chat_id
        try:
            await context.bot.send_message(
                chat_id=_chat_id,
                text=(
                    f"<blockquote><b>❌ Download Failed!</b>\n\n{_e(err_msg)}\n\n"
                    "<b>😎 DEV</b> @Shuvobhai ✅</blockquote>"
                ),
                parse_mode=ParseMode.HTML
            )
        except Exception:
            pass
    finally:
        shutil.rmtree(tmp_dir, ignore_errors=True)
        _ytdl_sessions.pop(uid, None)


