### ══════════════════════════════════════════════════════════
###  COMMAND LOCK / UNLOCK  (group admin only)
### ══════════════════════════════════════════════════════════

async def lock_check_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Group=-2 interceptor — silently drops commands locked by a group admin."""
    msg = update.effective_message
    if not msg or not msg.text:
        return
    chat = update.effective_chat
    if not chat or chat.type not in ("group", "supergroup"):
        return
    raw = msg.text.split()[0].lstrip("/").split("@")[0].lower()
    cid = str(chat.id)
    locked = _locks.get(cid, set())
    if raw in locked:
        raise ApplicationHandlerStop


async def _is_group_admin(update: Update, context: ContextTypes.DEFAULT_TYPE) -> bool:
    uid = str(update.effective_user.id)
    if uid == ADMIN_ID:
        return True
    try:
        member = await context.bot.get_chat_member(
            update.effective_chat.id, update.effective_user.id
        )
        return member.status in ("administrator", "creator")
    except Exception:
        return False


async def cmd_lock(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message:
        return
    chat = update.effective_chat
    if not chat or chat.type not in ("group", "supergroup"):
        sent = await update.message.reply_text(bq("❌ /lock only works inside a group."))
        schedule_delete(sent); return
    if not await _is_group_admin(update, context):
        sent = await update.message.reply_text(bq("⛔ Only group admins can lock commands."))
        schedule_delete(sent); return
    if not context.args:
        sent = await update.message.reply_text(
            bq("📌 Usage: /lock <command>\n\nExample:\n/lock aadhar\n/lock pan\n/lock ai"))
        schedule_delete(sent); return
    cmd_name = context.args[0].lstrip("/").split("@")[0].lower()
    if cmd_name in ("lock", "unlock", "locklist"):
        sent = await update.message.reply_text(bq("❌ You cannot lock /lock, /unlock, or /locklist."))
        schedule_delete(sent); return
    cid = str(chat.id)
    data = load_locks()
    locked_set = set(data.get(cid, []))
    if cmd_name in locked_set:
        sent = await update.message.reply_text(bq(f"ℹ️ /{cmd_name} is already locked in this group."))
        schedule_delete(sent); return
    locked_set.add(cmd_name)
    data[cid] = list(locked_set)
    save_locks(data)
    _locks[cid] = locked_set
    sent = await update.message.reply_text(
        bq(f"🔒 /{cmd_name} successfully locked!\n\n"
           f"No one can use this command in this group now.\n\n"
           f"Use /unlock {cmd_name} to restore it."))
    schedule_delete(sent)


async def cmd_unlock(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message:
        return
    chat = update.effective_chat
    if not chat or chat.type not in ("group", "supergroup"):
        sent = await update.message.reply_text(bq("❌ /unlock only works inside a group."))
        schedule_delete(sent); return
    if not await _is_group_admin(update, context):
        sent = await update.message.reply_text(bq("⛔ Only group admins can unlock commands."))
        schedule_delete(sent); return
    if not context.args:
        sent = await update.message.reply_text(
            bq("📌 Usage: /unlock <command>\n\nExample:\n/unlock aadhar\n/unlock pan"))
        schedule_delete(sent); return
    cmd_name = context.args[0].lstrip("/").split("@")[0].lower()
    cid = str(chat.id)
    data = load_locks()
    locked_set = set(data.get(cid, []))
    if cmd_name not in locked_set:
        sent = await update.message.reply_text(bq(f"ℹ️ /{cmd_name} is not locked in this group."))
        schedule_delete(sent); return
    locked_set.discard(cmd_name)
    data[cid] = list(locked_set)
    save_locks(data)
    _locks[cid] = locked_set
    sent = await update.message.reply_text(
        bq(f"🔓 /{cmd_name} successfully unlocked!\n\n"
           f"Everyone can use this command again. ✅"))
    schedule_delete(sent)


async def cmd_locklist(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message:
        return
    chat = update.effective_chat
    if not chat or chat.type not in ("group", "supergroup"):
        sent = await update.message.reply_text(bq("❌ Only works inside a group."))
        schedule_delete(sent); return
    if not await _is_group_admin(update, context):
        sent = await update.message.reply_text(bq("⛔ Only group admins can view the lock list."))
        schedule_delete(sent); return
    cid = str(chat.id)
    locked = _locks.get(cid, set())
    if not locked:
        sent = await update.message.reply_text(bq("✅ No commands are currently locked in this group."))
        schedule_delete(sent); return
    lines = "\n".join(f"🔒 /{c}" for c in sorted(locked))
    sent = await update.message.reply_text(
        bq(f"🔐 Locked commands in this group:\n\n{lines}\n\nUse /unlock <command> to restore any."))
    schedule_delete(sent)


async def _check_allowed_group(update: Update) -> bool:
    """Bot works in ALL groups — always returns False (never blocks)."""
    return False

