async def _do_insta_info_cookie(username: str):
    """Fetch Instagram profile info. Primary: direct IG API pool. Fallback: instagrapi."""
    uname = username.lstrip("@").strip()
    if not uname:
        return bq("❌ Invalid username.\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"), None

    loop = asyncio.get_event_loop()

    # ── Method 1: Direct IG API with multi-cookie pool ────────────────────────
    try:
        data     = await _ig_api_get("/users/web_profile_info/", params={"username": uname})
        u_raw    = (data.get("data") or {}).get("user") or data.get("user") or {}
        if not u_raw or not u_raw.get("id"):
            raise Exception("user_not_found")
        pk = str(u_raw.get("id", ""))

        extra = {}
        try:
            extra = (await _ig_api_get(f"/users/{pk}/info/")).get("user", {})
        except Exception:
            pass

        def _fmt(n):
            if n is None: return "N/A"
            n = int(n)
            if n >= 1_000_000: return f"{n/1_000_000:.2f}M ({n:,})"
            if n >= 1_000:     return f"{n/1_000:.1f}K ({n:,})"
            return str(n)

        from datetime import datetime as _dt
        import re as _re

        reels_count     = extra.get("total_clips_count")
        reels_str       = str(reels_count) if reels_count is not None else "N/A"
        latest_reel_ts  = extra.get("latest_reel_media")
        latest_reel_str = "—"
        if latest_reel_ts:
            try: latest_reel_str = _dt.utcfromtimestamp(int(latest_reel_ts)).strftime("%d %b %Y")
            except Exception: pass

        threads_url   = extra.get("threads_profile_glyph_url", "")
        threads_uname = "—"
        if threads_url:
            _m = _re.search(r"username=([^&]+)", threads_url)
            if _m: threads_uname = f"@{_m.group(1)}"

        _actype_map = {1: "<tg-emoji emoji-id='5166063676687385916'>👤</tg-emoji> Personal", 2: "🌟 Creator", 3: "💼 Business"}
        act_raw  = extra.get("account_type") or u_raw.get("account_type")
        actype   = _actype_map.get(act_raw, "—")
        is_biz   = bool(extra.get("is_business") or u_raw.get("is_business"))
        category = extra.get("category_name") or extra.get("business_category_name") or u_raw.get("category_name") or "—"

        fb_id    = str(extra.get("interop_messaging_user_fbid") or "—")
        fb_id_v2 = str(extra.get("fbid_v2") or "—")
        fb_page  = extra.get("page_name") or "—"

        meta_elig = extra.get("is_eligible_for_meta_verified_label", False)
        meta_str  = "✅ Eligible" if meta_elig else "❌ No"

        pinned_ch_list = (extra.get("pinned_channels_info") or {}).get("pinned_channels_list", [])
        pinned_str = "—"
        if pinned_ch_list:
            pinned_str = ", ".join(pc.get("title", "Channel") for pc in pinned_ch_list if pc.get("title")) or f"{len(pinned_ch_list)} channel(s)"

        edge_f = u_raw.get("edge_followed_by") or {}
        edge_g = u_raw.get("edge_follow") or {}
        bio_links_raw = u_raw.get("bio_links") or extra.get("bio_links") or []
        bio_links_str = "\n            ".join(f"• {bl.get('title') or 'Link'}: {bl.get('url', '')}" for bl in bio_links_raw) or "—"

        hd_info = extra.get("hd_profile_pic_url_info") or {}
        pic_url = (hd_info.get("url") or u_raw.get("profile_pic_url_hd") or u_raw.get("profile_pic_url") or "")

        d = {
            "username":      u_raw.get("username") or uname,
            "fullname":      u_raw.get("full_name") or "—",
            "userid":        pk,
            "fb_id":         fb_id,
            "fb_id_v2":      fb_id_v2,
            "fb_page":       fb_page,
            "threads":       threads_uname,
            "verified":      bool(u_raw.get("is_verified")),
            "private":       bool(u_raw.get("is_private")),
            "actype":        actype,
            "is_biz":        is_biz,
            "category":      category,
            "meta_verified": meta_str,
            "followers":     _fmt(edge_f.get("count") or extra.get("follower_count")),
            "following":     _fmt(edge_g.get("count") or extra.get("following_count")),
            "posts":         str(u_raw.get("edge_owner_to_timeline_media", {}).get("count") or extra.get("media_count") or "N/A"),
            "reels":         reels_str,
            "latest_reel":   latest_reel_str,
            "bio":           (u_raw.get("biography") or extra.get("biography") or "—")[:300],
            "bio_links":     bio_links_str,
            "ext_url":       u_raw.get("external_url") or extra.get("external_url") or "—",
            "channel":       "—",
            "pinned_ch":     pinned_str,
            "email":         extra.get("public_email") or "—",
            "phone":         (f"+{extra.get('public_phone_country_code','')}{extra.get('public_phone_number','')}" if extra.get("public_phone_number") else "—"),
            "city":          extra.get("city_name") or "—",
            "zip":           extra.get("zip") or "—",
            "address":       extra.get("address_street") or "—",
            "pic_url":       pic_url,
        }
        return _build_insta_caption(d), d["pic_url"] or None

    except Exception as _direct_err:
        err_msg = str(_direct_err)
        if "not_found" in err_msg.lower() or "user_not_found" in err_msg.lower():
            return bq(f"📸 Instagram Info\n\n❌ @{h(uname)} not found.\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"), None
        return bq(f"📸 Instagram Info\n\n❌ Failed to fetch @{h(uname)}\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"), None


_PINT_COOKIES_FILE = os.path.join(os.path.dirname(__file__), "bot", "pinterest_cookies.txt")


async def _do_pinterest_download(update: Update, url: str, uid: str, users: dict):
    """Download Pinterest video/image via yt-dlp with cookies."""
    import yt_dlp, asyncio, shutil
    sent = await update.message.reply_text(bq("📌 Downloading Pinterest…"), parse_mode=ParseMode.HTML)
    tmp_dir  = tempfile.mkdtemp()
    out_tmpl = os.path.join(tmp_dir, "%(title).60s.%(ext)s")
    opts = {
        "quiet": True, "no_warnings": True, "noplaylist": True,
        "socket_timeout": 45, "retries": 3,
        "geo_bypass": True, "nocheckcertificate": True,
        "format": "best[ext=mp4]/best[ext=jpg]/best[ext=jpeg]/best[ext=png]/best",
        "outtmpl": out_tmpl,
        "merge_output_format": "mp4",
    }
    if os.path.exists(_PINT_COOKIES_FILE):
        opts["cookiefile"] = _PINT_COOKIES_FILE
    loop = asyncio.get_event_loop()
    try:
        def _dl():
            with yt_dlp.YoutubeDL(opts) as ydl:
                info = ydl.extract_info(url, download=True)
                fp   = ydl.prepare_filename(info)
                return fp, info
        filepath, info = await loop.run_in_executor(None, _dl)
        if not os.path.exists(filepath):
            for fn in os.listdir(tmp_dir):
                filepath = os.path.join(tmp_dir, fn); break
        fsize = os.path.getsize(filepath)
        if fsize > 50 * 1024 * 1024:
            raise Exception(f"File too large ({fsize//(1024*1024)} MB).")
        vtitle   = (info.get("title") or "Pinterest")[:80]
        ext      = os.path.splitext(filepath)[-1].lower()
        caption  = (
            "<blockquote><b>📌 PINTEREST DOWNLOAD</b>\n\n"
            f"<b>🖼 Title</b>   : {_e(vtitle)}\n"
            f"<b>⭐ Source</b>  : Pinterest\n\n"
            "<b>✅ Downloaded!</b>\n\n"
            "<b>🥫 Dev</b> : @Shuvobhai</blockquote>"
        )
        await sent.delete()
        kb = after_result_keyboard()
        if ext in (".mp4", ".webm", ".mov", ".mkv"):
            with open(filepath, "rb") as vf:
                await update.message.reply_video(video=vf, caption=caption,
                    parse_mode=ParseMode.HTML, reply_markup=kb, supports_streaming=True)
        else:
            with open(filepath, "rb") as pf:
                await update.message.reply_photo(photo=pf, caption=caption,
                    parse_mode=ParseMode.HTML, reply_markup=kb)
    except Exception as e:
        err_msg = str(e)[:250]
        try:
            await sent.edit_text(
                bq(f"❌ Pinterest Download Failed!\n\n{err_msg}\n\n😎 DEV @Shuvobhai"),
                parse_mode=ParseMode.HTML)
        except Exception:
            pass
    finally:
        shutil.rmtree(tmp_dir, ignore_errors=True)


