    # ── Helper: send downloaded list ────────────────────────────────────────
    async def _send_files(downloaded):
        """downloaded = list of (filepath, duration_sec)"""
        total = len(downloaded)
        cap   = _make_caption(total)
        if total == 0:
            raise Exception("No files to send")

        if total == 1:
            fp, dur = downloaded[0]
            ext = os.path.splitext(fp)[1].lower()
            if ext in VIDEO_EXTS:
                await update.message.reply_video(
                    video=open(fp, "rb"), caption=cap,
                    parse_mode=ParseMode.HTML, duration=dur,
                    reply_markup=kb, supports_streaming=True,
                )
            else:
                await update.message.reply_photo(
                    photo=open(fp, "rb"), caption=cap,
                    parse_mode=ParseMode.HTML, reply_markup=kb,
                )
        else:
            BATCH = 10
            for batch_start in range(0, total, BATCH):
                batch = downloaded[batch_start:batch_start + BATCH]
                media_group = []
                handles = []
                for j, (fp, dur) in enumerate(batch):
                    ext = os.path.splitext(fp)[1].lower()
                    fh  = open(fp, "rb")
                    handles.append(fh)
                    item_cap = cap if (batch_start == 0 and j == 0) else None
                    pm = ParseMode.HTML if item_cap else None
                    if ext in VIDEO_EXTS:
                        media_group.append(InputMediaVideo(
                            media=fh, caption=item_cap, parse_mode=pm,
                            duration=dur, supports_streaming=True,
                        ))
                    else:
                        media_group.append(InputMediaPhoto(
                            media=fh, caption=item_cap, parse_mode=pm,
                        ))
                await update.message.reply_media_group(media=media_group)
                for fh in handles:
                    try: fh.close()
                    except Exception: pass
            await update.message.reply_text(
                bq(f"📸 Instagram\n✅ {total} item(s) downloaded!\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"),
                parse_mode=ParseMode.HTML, reply_markup=kb,
            )

    # ── Method 0: Direct IG API with multi-cookie pool ──────────────────────
    async def _try_direct_api():
        import re as _re, urllib.request as _ureq
        # Extract shortcode from URL
        _sc = _re.search(r"/(?:p|reel|tv|reels)/([A-Za-z0-9_-]+)", url)
        if not _sc:
            raise Exception("no_shortcode")
        shortcode = _sc.group(1)
        # Decode shortcode → media_id
        _ALPHA = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_"
        media_id = 0
        for ch in shortcode:
            media_id = media_id * 64 + _ALPHA.index(ch)

        info = await _ig_api_get(f"/media/{media_id}/info/")
        items_raw = info.get("items") or []
        if not items_raw:
            raise Exception("no_items")
        item = items_raw[0]
        media_type = item.get("media_type", 1)

        def _best_img(m):
            cands = (m.get("image_versions2") or {}).get("candidates") or []
            return cands[0]["url"] if cands else None

        def _best_vid(m):
            if m.get("video_url"): return m["video_url"]
            vers = m.get("video_versions") or []
            return vers[0]["url"] if vers else None

        result = []
        if media_type == 8:  # Carousel
            for i, cm in enumerate((item.get("carousel_media") or [])):
                mt = cm.get("media_type", 1)
                if mt == 2:
                    vurl = _best_vid(cm)
                    if vurl:
                        fp = os.path.join(tmp_dir, f"d_{i:03d}.mp4")
                        _ureq.urlretrieve(vurl, fp)
                        result.append((fp, int(cm.get("video_duration", 0) or 0)))
                else:
                    iurl = _best_img(cm)
                    if iurl:
                        fp = os.path.join(tmp_dir, f"d_{i:03d}.jpg")
                        _ureq.urlretrieve(iurl, fp)
                        result.append((fp, 0))
        elif media_type == 2:  # Video
            vurl = _best_vid(item)
            if vurl:
                fp = os.path.join(tmp_dir, "d_000.mp4")
                _ureq.urlretrieve(vurl, fp)
                result.append((fp, int(item.get("video_duration", 0) or 0)))
        else:  # Photo
            iurl = _best_img(item)
            if iurl:
                fp = os.path.join(tmp_dir, "d_000.jpg")
                _ureq.urlretrieve(iurl, fp)
                result.append((fp, 0))
        if not result:
            raise Exception("no_downloadable_media")
        return result

    # ── Method 1: instagrapi (best for carousel) ────────────────────────────
    async def _try_instagrapi():
        def _fetch_and_download():
            global _ig_client_instance, _ig_client_sessionid
            try:
                cl = _get_ig_client()
            except Exception:
                raise

            try:
                pk    = cl.media_pk_from_url(url)
                media = cl.media_info(pk)
            except Exception as e:
                # If session expired/challenged, reset client and retry once
                _ig_client_instance  = None
                _ig_client_sessionid = None
                cl    = _get_ig_client()
                pk    = cl.media_pk_from_url(url)
                media = cl.media_info(pk)
            # media_type: 1=Photo, 2=Video, 8=Album/Carousel
            items = []
            if media.media_type == 8 and media.resources:
                # Carousel: collect all resources
                for res in media.resources:
                    items.append(res)
            else:
                items = [media]

            result = []
            for i, item in enumerate(items):
                if item.media_type == 2 and item.video_url:
                    # Video resource
                    fp = os.path.join(tmp_dir, f"{i:03d}.mp4")
                    import urllib.request as _req
                    _req.urlretrieve(str(item.video_url), fp)
                    dur = int(item.video_duration) if item.video_duration else 0
                    result.append((fp, dur))
                elif item.thumbnail_url:
                    # Photo resource — get highest quality
                    photo_url = str(item.thumbnail_url)
                    # Try to get full-size from resources
                    if hasattr(item, "image_versions2") and item.image_versions2:
                        pass  # instagrapi already resolves best URL
                    fp = os.path.join(tmp_dir, f"{i:03d}.jpg")
                    import urllib.request as _req
                    _req.urlretrieve(photo_url, fp)
                    result.append((fp, 0))
            return result

        return await loop.run_in_executor(None, _fetch_and_download)

    # ── Method 2: yt-dlp fallback ───────────────────────────────────────────
    async def _try_ytdlp():
        import yt_dlp as _yt_dlp
        cookie_file = _write_insta_cookies_txt() if _insta_cookies_have_session() else None

        dl_opts = {
            "quiet": True,
            "no_warnings": True,
            "noplaylist": False,
            "socket_timeout": 30,
            "outtmpl": os.path.join(tmp_dir, "ytdlp_%(autonumber)s.%(ext)s"),
            "format": "best",
        }
        if cookie_file:
            dl_opts["cookiefile"] = cookie_file

        def _dl():
            with _yt_dlp.YoutubeDL(dl_opts) as ydl:
                info = ydl.extract_info(url, download=True)
                return info

        info = await loop.run_in_executor(None, _dl)

        all_files = sorted(
            [os.path.join(tmp_dir, f) for f in os.listdir(tmp_dir)
             if os.path.isfile(os.path.join(tmp_dir, f)) and f.startswith("ytdlp_")],
            key=lambda f: os.path.getmtime(f)
        )
        result = []
        for fp in all_files:
            ext = os.path.splitext(fp)[1].lower()
            if ext not in IMAGE_EXTS and ext not in VIDEO_EXTS:
                continue
            if os.path.getsize(fp) > 50 * 1024 * 1024:
                continue
            dur = 0
            if info:
                entries = info.get("entries") or [info]
                for e in entries:
                    if e and e.get("id") and e.get("id") in os.path.basename(fp):
                        dur = e.get("duration") or 0
                        break
            result.append((fp, dur))
        return result

    try:
        downloaded = []

        # Method 0: Direct IG API (fastest, no login overhead)
        try:
            downloaded = await _try_direct_api()
        except Exception:
            pass

        # Method 1: instagrapi (handles carousel, slower)
        if not downloaded:
            try:
                downloaded = await _try_instagrapi()
            except Exception:
                pass

        # Method 2: yt-dlp (last resort)
        if not downloaded:
            try:
                downloaded = await _try_ytdlp()
            except Exception as ytdlp_err:
                raise ytdlp_err

        if not downloaded:
            raise Exception("No media found in this post")

        _anim.cancel()
        await sent.delete()
        await _send_files(downloaded)

    except Exception as e:
        _anim.cancel()
        try:
            await sent.edit_text(
                bq(f"📸 Instagram Download\n\n❌ Failed: {h(str(e)[:150])}\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅"),
                parse_mode=ParseMode.HTML,
            )
        except Exception:
            pass
    finally:
        try:
            _shutil.rmtree(tmp_dir, ignore_errors=True)
        except Exception:
            pass


