def force_join_admin_keyboard():
    cfg      = load_config()
    channels = cfg.get("required_channels", [])
    rows     = []
    rows.append([SBtn("➖➖ 📋 Force Join Channels ➖➖", style="primary", callback_data="noop")])
    if channels:
        for i, ch in enumerate(channels):
            title   = ch.get("title", "Unnamed")
            chat_id = ch.get("chat_id")
            icon    = "✅" if chat_id else "⚠️"
            rows.append([SBtn(f"🗑 {icon} [{i+1}] {title}", style="danger", callback_data=f"admin_fj_del_{i}")])
    else:
        rows.append([SBtn("⚠️ No channels added yet", callback_data="noop")])
    rows.append([SBtn("➕ Add Channel / Group", style="success", callback_data="admin_fj_add")])
    rows.append([SBtn("🔙 Back to Admin Panel", style="primary", callback_data="admin_panel")])
    return InlineKeyboardMarkup(rows)

async def broadcast(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    /broadcast <text>             → text broadcast to all users
    Reply any msg + /broadcast   → copy that msg (photo/sticker/video/text) to all users
    """
    users = load_users()
    user, _ = get_user(users, update.effective_user.id)
    if not user["is_admin"]: return
    msg       = update.message
    admin_uid = str(update.effective_user.id)

    async def _do_broadcast(prog, send_fn, label):
        sent_count, fail_count, block_count = 0, 0, 0
        all_users = [(uid, u) for uid, u in users.items() if not u["banned"]]
        total = len(all_users)
        for i, (uid, u) in enumerate(all_users):
            for attempt in range(3):
                try:
                    await send_fn(uid)
                    sent_count += 1
                    break
                except Exception as e:
                    err = str(e)
                    if "Retry" in err or "retry" in err or "flood" in err.lower():
                        import re as _re2
                        nums = _re2.findall(r"\d+", err)
                        wait = int(nums[0]) + 1 if nums else 5
                        await asyncio.sleep(wait)
                    elif "Forbidden" in err or "blocked" in err.lower() or "deactivated" in err.lower() or "kicked" in err.lower():
                        block_count += 1
                        break
                    else:
                        if attempt == 2:
                            fail_count += 1
                        await asyncio.sleep(1)
            await asyncio.sleep(0.05)
            if (i + 1) % 50 == 0:
                try:
                    await prog.edit_text(bq(f"📡 Broadcasting...\n✅ {sent_count} / {total} sent"))
                except Exception:
                    pass
        write_log(f"[BROADCAST] Admin {admin_uid} {label} → {sent_count}/{total} users")
        try:
            await prog.edit_text(bq(
                f"✅ Broadcast complete!\n"
                f"📊 Delivered : {sent_count}\n"
                f"🚫 Blocked   : {block_count}\n"
                f"❌ Failed    : {fail_count}\n"
                f"👥 Total     : {total}"
            ))
        except Exception:
            pass
        schedule_delete(prog)

    # ── Mode 1: reply to a message → copy it (supports any media) ──
    if msg.reply_to_message:
        src_chat   = msg.reply_to_message.chat_id
        src_msg_id = msg.reply_to_message.message_id
        prog = await msg.reply_text(bq("📡 Broadcasting... please wait."))
        async def _copy(uid):
            await context.bot.copy_message(chat_id=uid, from_chat_id=src_chat, message_id=src_msg_id)
        await _do_broadcast(prog, _copy, "media broadcast")
        return

    # ── Mode 2: /broadcast <text> → text only ──
    if context.args:
        text = " ".join(context.args)
        prog = await msg.reply_text(bq("📡 Broadcasting... please wait."))
        async def _send(uid):
            await context.bot.send_message(chat_id=uid, text=f"📢 {text}")
        await _do_broadcast(prog, _send, f"text broadcast: {text[:80]}")
        return

    # ── No args, no reply → show usage ──
    sent = await msg.reply_text(
        bq(
            "📢 Broadcast Usage\n\n"
            "• /broadcast Hello everyone! — text only\n"
            "• Reply to any photo/sticker/video/text with /broadcast — sends that media to everyone\n\n"
            "✅ Supports: text, photo, sticker, video, voice, document"
        )
    )
    schedule_delete(sent)

