async def cmd_giveall(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    /giveall cr <amount>     — give credits to ALL users
    /giveall prem <days>     — give premium to ALL users (0 = lifetime)
    """
    users = load_users()
    user, uid = get_user(users, update.effective_user.id)
    if not user["is_admin"]:
        sent = await update.message.reply_text(bq("⛔ Admin only.")); schedule_delete(sent); return

    args = context.args
    if not args or len(args) < 2:
        sent = await update.message.reply_text(bq(
            "<tg-emoji emoji-id='5262889711466193287'>🎁</tg-emoji> GiveAll Usage\n\n"
            "Give credits to everyone:\n"
            "  /giveall cr 10\n\n"
            "Give premium to everyone:\n"
            "  /giveall prem 7   → 7 days\n"
            "  /giveall prem 30  → 30 days\n"
            "  /giveall prem 0   → Lifetime 🔥"
        ))
        schedule_delete(sent); return

    gtype = args[0].lower()
    raw   = args[1].lower().rstrip("d")
    try:
        value = int(raw)
    except ValueError:
        sent = await update.message.reply_text(bq("❌ Value must be a number. E.g. 10 or 7d")); schedule_delete(sent); return

    all_users = [(k, v) for k, v in users.items() if not v.get("banned")]
    total = len(all_users)

    if gtype == "cr":
        prize_label = f"💎 {value} Credits"
    elif gtype == "prem":
        dur_label   = "Lifetime 🔥" if value == 0 else f"{value} Day(s)"
        prize_label = f"👑 Premium {dur_label}"
    else:
        sent = await update.message.reply_text(bq("❌ Type must be 'cr' or 'prem'.")); schedule_delete(sent); return

    prog = await update.message.reply_text(bq(f"<tg-emoji emoji-id='5262889711466193287'>🎁</tg-emoji> Giving {prize_label} to {total} users..."))
    given, notified = 0, 0

    for user_id, u in all_users:
        if gtype == "cr":
            u["credits"] = u.get("credits", 0) + value
        elif gtype == "prem":
            u["premium"] = True
            if value == 0:
                u["premium_until"] = None
            else:
                current = u.get("premium_until")
                base    = datetime.fromisoformat(current) if current and datetime.now() < datetime.fromisoformat(current) else datetime.now()
                u["premium_until"] = (base + timedelta(days=value)).isoformat()
        given += 1
        if given % 100 == 0:
            try: await prog.edit_text(bq(f"<tg-emoji emoji-id='5262889711466193287'>🎁</tg-emoji> Processing...\n✅ {given} / {total}"))
            except Exception: pass

    save_users(users)

    # Notify all users (best-effort, flood-safe)
    notify_text = bq(
        f"<tg-emoji emoji-id='5262889711466193287'>🎁</tg-emoji> Gift from Admin!\n\n"
        f"🏆 You received: {prize_label}\n"
        f"🎉 Enjoy!\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> @Shuvobhai"
    )
    for user_id, u in all_users:
        try:
            await context.bot.send_message(chat_id=int(user_id), text=notify_text)
            notified += 1
        except Exception:
            pass
        await asyncio.sleep(0.05)

    write_log(f"[GIVEALL] Admin {uid} gave {prize_label} to {given} users")
    try:
        await prog.edit_text(bq(
            f"✅ GiveAll complete!\n\n"
            f"🏆 Prize     : {prize_label}\n"
            f"👥 Given     : {given}\n"
            f"📩 Notified  : {notified}\n"
            f"📊 Total     : {total}"
        ))
    except Exception: pass
    schedule_delete(prog)


async def redeem(update: Update, context: ContextTypes.DEFAULT_TYPE):
    users = load_users()
    user, uid = get_user(users, update.effective_user.id, update.effective_user.username or "")
    if user["banned"]:
        sent = await update.message.reply_text(bq("⛔ You are banned.")); schedule_delete(sent); return
    if not context.args:
        sent = await update.message.reply_text(bq("Usage: /redeem \nExample: /redeem SHUVO_abc123"))
        schedule_delete(sent); return
    code_str = context.args[0].strip()
    codes = load_codes()
    if code_str not in codes:
        sent = await update.message.reply_text(bq("❌ Invalid code.")); schedule_delete(sent); return
    code = codes[code_str]
    if code.get("expires_at"):
        if datetime.now() > datetime.fromisoformat(code["expires_at"]):
            sent = await update.message.reply_text(bq("❌ This code has expired.")); schedule_delete(sent); return
    if uid in code.get("used_by", []):
        sent = await update.message.reply_text(bq("❌ You have already used this code.")); schedule_delete(sent); return
    code_type = code.get("type", "credits")
    code.setdefault("used_by", []).append(uid)

    if code_type == "premium":
        days = code.get("days", 0)
        if days == 0:
            user["premium"] = True
            user["premium_until"] = None
            label = "Lifetime Premium"
        else:
            current_until = user.get("premium_until")
            if current_until and datetime.now() < datetime.fromisoformat(current_until):
                base = datetime.fromisoformat(current_until)
            else:
                base = datetime.now()
            user["premium"] = True
            user["premium_until"] = (base + timedelta(days=days)).isoformat()
            label = f"{days}-Day Premium"
        save_users(users)
        save_codes(codes)
        write_log(f"[REDEEM-PREMIUM] User {uid} redeemed code {code_str} → {label}")
        sent = await update.message.reply_text(
            bq(f"✅ Premium Activated!\n💎 {label} unlocked!\n🎉 All features are now FREE for you!\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅")
        )
        schedule_delete(sent)
        return

    credits = code["credits"]
    user["credits"] += credits
    save_users(users)
    save_codes(codes)
    write_log(f"[REDEEM] User {uid} redeemed code {code_str} for +{credits} credits (balance: {user['credits']})")
    sent = await update.message.reply_text(
        bq(f"✅ Code redeemed!\n<tg-emoji emoji-id='5262889711466193287'>🎁</tg-emoji> +{credits} credits added.\n<tg-emoji emoji-id='5224257782013769471'>💰</tg-emoji> Balance: {user['credits']}\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅")
    )
    schedule_delete(sent)

async def gen(update: Update, context: ContextTypes.DEFAULT_TYPE):
    users = load_users()
    admin, _ = get_user(users, update.effective_user.id)
    if not admin["is_admin"]: return
    if len(context.args) < 2:
        sent = await update.message.reply_text(bq("Usage: /gen <user_id or @username> <amount>"))
        schedule_delete(sent); return
    raw_target = context.args[0]
    try:
        amount = int(context.args[1])
    except ValueError:
        sent = await update.message.reply_text(bq("❌ Amount must be a number.")); schedule_delete(sent); return
    if raw_target.startswith("@") or not raw_target.isdigit():
        target, target_id = find_user_by_username(users, raw_target)
        if target is None:
            sent = await update.message.reply_text(bq("❌ User not found.")); schedule_delete(sent); return
    else:
        target_id = raw_target
        target, _ = get_user(users, target_id)
    target["credits"] += amount
    save_users(users)
    write_log(f"[GEN] Admin {str(update.effective_user.id)} added {amount} credits to user {target_id} (balance: {target['credits']})")
    sent = await update.message.reply_text(bq(f"✅ Added {amount} credits.\n<tg-emoji emoji-id='5224257782013769471'>💰</tg-emoji> New balance: {target['credits']}"))
    schedule_delete(sent)

def _is_allowed_ban_chat(update: Update) -> bool:
    """Allow /ban and /unban only in bot DM or the configured log group."""
    chat = update.effective_chat
    if not chat: return False
    if chat.type == "private": return True
    cfg = load_config()
    log_group = cfg.get("log_group_id")
    if log_group and str(chat.id) == str(log_group): return True
    return False

async def ban_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.effective_user: return
    if not is_owner(update.effective_user.id): return   # silent — owner only
    if not _is_allowed_ban_chat(update): return         # silent — DM or log group only
    users = load_users()
    _, admin_uid = get_user(users, update.effective_user.id)
    if not context.args:
        sent = await update.message.reply_text(bq("Usage: /ban <user_id>")); schedule_delete(sent); return
    target_id = context.args[0]
    target, _ = get_user(users, target_id)
    target["banned"] = True
    save_users(users)
    write_log(f"[BAN] Owner banned user {target_id}")
    sent = await update.message.reply_text(bq(f"⛔ User {h(target_id)} banned."))
    schedule_delete(sent)

async def unban_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.effective_user: return
    if not is_owner(update.effective_user.id): return   # silent — owner only
    if not _is_allowed_ban_chat(update): return         # silent — DM or log group only
    users = load_users()
    _, admin_uid = get_user(users, update.effective_user.id)
    if not context.args:
        sent = await update.message.reply_text(bq("Usage: /unban <user_id>")); schedule_delete(sent); return
    target_id = context.args[0]
    target, _ = get_user(users, target_id)
    target["banned"] = False
    save_users(users)
    write_log(f"[UNBAN] Owner unbanned user {target_id}")
    sent = await update.message.reply_text(bq(f"✅ User {h(target_id)} unbanned."))
    schedule_delete(sent)

async def addadmin(update: Update, context: ContextTypes.DEFAULT_TYPE):
    users = load_users()
    admin, admin_uid = get_user(users, update.effective_user.id)
    if not admin["is_admin"]: return
    if not context.args:
        sent = await update.message.reply_text(bq("Usage: /addadmin <user_id>")); schedule_delete(sent); return
    target_id = context.args[0]
    target, _ = get_user(users, target_id)
    target["is_admin"] = True
    save_users(users)
