async def cmd_addpremium(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Usage: /addpremium <user_id> <days>  (0 days = lifetime)"""
    users = load_users()
    admin, admin_uid = get_user(users, update.effective_user.id)
    if not admin["is_admin"]: return
    if len(context.args) < 2:
        sent = await update.message.reply_text(bq("Usage: /addpremium <user_id> <days>\n0 days = Lifetime\nExample: /addpremium 123456 30"))
        schedule_delete(sent); return
    target_id = context.args[0]
    try:
        days = int(context.args[1])
    except ValueError:
        sent = await update.message.reply_text(bq("❌ Days must be a number. 0 = Lifetime.")); schedule_delete(sent); return
    target, _ = get_user(users, target_id)
    target["premium"] = True
    if days == 0:
        target["premium_until"] = None
        label = "Lifetime"
    else:
        current_until = target.get("premium_until")
        if current_until and datetime.now() < datetime.fromisoformat(current_until):
            base = datetime.fromisoformat(current_until)
        else:
            base = datetime.now()
        target["premium_until"] = (base + timedelta(days=days)).isoformat()
        label = f"{days} Days (until {(base + timedelta(days=days)).strftime('%Y-%m-%d')})"
    save_users(users)
    write_log(f"[ADDPREMIUM] Admin {admin_uid} gave premium to {target_id} — {label}")
    sent = await update.message.reply_text(bq(f"💎 Premium activated for {h(target_id)}!\n⏳ Duration: {label}"))
    schedule_delete(sent)
    try:
        await context.bot.send_message(
            chat_id=int(target_id),
            text=bq(f"🎉 You have been given Premium!\n💎 Duration: {label}\n🚀 All features are now FREE for you!\n\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> @Shuvobhai")
        )
    except Exception:
        pass


async def cmd_rmpremium(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Usage: /rmpremium <user_id>"""
    users = load_users()
    admin, admin_uid = get_user(users, update.effective_user.id)
    if not admin["is_admin"]: return
    if not context.args:
        sent = await update.message.reply_text(bq("Usage: /rmpremium <user_id>")); schedule_delete(sent); return
    target_id = context.args[0]
    target, _ = get_user(users, target_id)
    target["premium"] = False
    target["premium_until"] = None
    save_users(users)
    write_log(f"[RMPREMIUM] Admin {admin_uid} removed premium from {target_id}")
    sent = await update.message.reply_text(bq(f"✅ Premium removed from {h(target_id)}."))
    schedule_delete(sent)


async def cmd_genpremcode(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Usage: /genpremcode <days> [max_users]  (0 days = lifetime)"""
    uid = str(update.effective_user.id)
    users = load_users()
    if not (users.get(uid, {}).get("is_admin") or is_owner(uid)):
        return
    if not context.args:
        await update.message.reply_text(
            "📋 Usage:\n/genpremcode <days> [max_users]\n\n"
            "Examples:\n/genpremcode 30 — 30-day premium, unlimited\n"
            "/genpremcode 7 5 — 7-day premium, max 5 users\n"
            "/genpremcode 0 — Lifetime premium"
        )
        return
    try:
        days = int(context.args[0])
        max_users = int(context.args[1]) if len(context.args) > 1 else 0
    except ValueError:
        await update.message.reply_text(bq("❌ Numbers only.")); return
    chars = string.ascii_letters + string.digits
    code = "PREM_" + "".join(random.choices(chars, k=8))
    codes = load_codes()
    codes[code] = {
        "type": "premium",
        "days": days,
        "credits": 0,
        "max_users": max_users,
        "expires_at": None,
        "used_by": [],
        "created_by": uid,
        "created_at": datetime.utcnow().isoformat(),
    }
    save_codes(codes)
    label = "Lifetime" if days == 0 else f"{days} Days"
    max_str = str(max_users) if max_users > 0 else "Unlimited"
    await update.message.reply_text(
        f"✅ Premium Code Generated!\n\n"
        f"🎫 Code: <code>{code}</code>\n"
        f"💎 Type: {label} Premium\n"
        f"👥 Max Users: {max_str}\n\n"
        f"Share: /redeem {code}",
        parse_mode="HTML"
    )


def _db_page_text(page: int) -> str:
    dbs = load_databases()
    total = len(dbs)
    total_pages = max(1, (total + DB_PAGE_SIZE - 1) // DB_PAGE_SIZE)
    start = page * DB_PAGE_SIZE
    end   = min(start + DB_PAGE_SIZE, total)
    lines = [f"🗄 Available Databases  [{page+1}/{total_pages}]",
             f"📊 Total: {total:,}\n"]
    dbs_list = dbs if isinstance(dbs, list) else list(dbs.values())
    for i, db in enumerate(dbs_list[start:end], start=start+1):
        title = db.get("title") or db.get("name") or str(db)[:50] if isinstance(db, dict) else str(db)[:50]
        lines.append(f"{i}. {h(title)}")
    return "\n".join(lines)

def _db_page_keyboard(page: int) -> InlineKeyboardMarkup:
    dbs = load_databases()
    dbs_list = dbs if isinstance(dbs, list) else list(dbs.values())
    total_pages = max(1, (len(dbs_list) + DB_PAGE_SIZE - 1) // DB_PAGE_SIZE)
    nav = []
    if page > 0:
        nav.append(SBtn("◀️ Prev", style="primary", callback_data=f"db_page_{page-1}"))
    if page < total_pages - 1:
        nav.append(SBtn("Next ▶️", style="primary", callback_data=f"db_page_{page+1}"))
    rows = []
    if nav:
        rows.append(nav)
    rows.append([SBtn("🏠 Main Menu", style="primary", callback_data="back_home")])
    return InlineKeyboardMarkup(rows)

async def databases_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    sent = await update.message.reply_text(bq(_db_page_text(0)), reply_markup=_db_page_keyboard(0))
    schedule_delete(sent)


async def app_toggle(update: Update, context: ContextTypes.DEFAULT_TYPE):
    users = load_users()
    user, _ = get_user(users, update.effective_user.id)
    if not user["is_admin"]:
        sent = await update.message.reply_text(bq("⛔ Admin only.")); schedule_delete(sent); return
    if not context.args or context.args[0].lower() not in ("on", "off"):
        sent = await update.message.reply_text(bq("Usage: /app on or /app off"))
        schedule_delete(sent); return
    chat_id = str(update.effective_chat.id)
    action  = context.args[0].lower()
    cfg     = load_config()
    chats   = cfg.get("autoapprove_chats", [])
    if action == "on":
        if chat_id not in chats: chats.append(chat_id)
        cfg["autoapprove_chats"] = chats; save_config(cfg)
        sent = await update.message.reply_text(bq(f"✅ Auto-Approve ON\n🆔 Chat: {chat_id}"))
    else:
        if chat_id in chats: chats.remove(chat_id)
        cfg["autoapprove_chats"] = chats; save_config(cfg)
        sent = await update.message.reply_text(bq(f"🔴 Auto-Approve OFF\n🆔 Chat: {chat_id}"))
    schedule_delete(sent)


async def track_bot_groups(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Track groups where the bot is added or removed."""
    try:
        result = update.my_chat_member
        if not result:
            return
        chat = result.chat
        new_status = result.new_chat_member.status
        cid = str(chat.id)
        groups = load_groups()
        if new_status in ("member", "administrator"):
            try:
                invite_link = ""
                if chat.username:
                    invite_link = f"https://t.me/{chat.username}"
                else:
                    try:
                        link_obj = await context.bot.export_chat_invite_link(chat.id)
                        invite_link = link_obj if isinstance(link_obj, str) else ""
                    except Exception:
                        invite_link = ""
                groups[cid] = {
                    "id": cid,
                    "title": chat.title or "Unknown",
                    "username": f"@{chat.username}" if chat.username else "",
                    "invite_link": invite_link,
                    "type": chat.type,
                    "is_admin": new_status == "administrator",
                }
                save_groups(groups)
            except Exception:
                pass
        elif new_status in ("left", "kicked", "banned"):
            if cid in groups:
                del groups[cid]
                save_groups(groups)
    except Exception:
        pass


async def auto_approve_request(update: Update, context: ContextTypes.DEFAULT_TYPE):
    req = update.chat_join_request
    chat = req.chat
    user = req.from_user
    cfg  = load_config()
    if is_autoapprove(chat.id):
        asyncio.create_task(_do_approve(req))
        return
    # Notify owner via log group about the join request
    log_group = cfg.get("log_group_id")
    if log_group:
        try:
            uname = f"@{user.username}" if user.username else f"<a href='tg://user?id={user.id}'>{user.first_name}</a>"
            chat_link = f"https://t.me/{chat.username}" if chat.username else f"<code>{chat.id}</code>"
            text = (
                f"🔔 <b>New Join Request</b>\n\n"
                f"<tg-emoji emoji-id='5166063676687385916'>👤</tg-emoji> User: {uname} (<code>{user.id}</code>)\n"
                f"💬 Group: <b>{chat.title}</b> ({chat_link})\n\n"
                f"<i>Auto-approve is OFF for this group.</i>\n"
                f"Use <code>/autoapprove {chat.id} on</code> to enable."
            )
            await context.bot.send_message(
                chat_id=int(log_group), text=text,
                parse_mode=ParseMode.HTML, disable_web_page_preview=True
            )
        except Exception:
            pass


async def _do_approve(req):
    try:
        await req.approve()
    except Exception:
        pass


