async def button_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    data  = query.data

    # ── Anti-spam: progressive per-user cooldown ──
    _uid_str = str(query.from_user.id)
    _now = time.monotonic()
    _cd  = _button_cooldown.get(_uid_str) or {"penalty_until": 0.0, "last_hit": 0.0, "hits": 0, "extend_count": 0}

    # Still under penalty — escalate if they keep clicking during block
    if _now < _cd["penalty_until"]:
        _cd["extend_count"] = _cd.get("extend_count", 0) + 1
        _hard = _cd["extend_count"] >= _SPAM_HARD_THRESHOLD
        if _hard:
            _cd["penalty_until"] = _now + _SPAM_HARD_BLOCK
        else:
            _cd["penalty_until"] += _SPAM_EXTEND
        _button_cooldown[_uid_str] = _cd
        new_secs_left = int(_cd["penalty_until"] - _now) + 1
        if _hard:
            msg = (
                f"🚨 HARD BLOCK! 10 minuter jonno lock!\n"
                f"⏳ {new_secs_left}s baki.\n"
                f"🛑 Khub beshi spam korli — 10 min block!"
            )
        else:
            warns = ["⚠️ Spam kora band koro!", "🛑 Aro spam korle 10min block hobe!", "🚨 Anti-spam active — ruko!"]
            warn = warns[min(_cd["extend_count"] - 1, len(warns) - 1)]
            msg = f"🚫 Tui block e acho! {new_secs_left}s baki.\n{warn}"
        try:
            await query.answer(msg, show_alert=True)
        except Exception:
            pass
        return

    # Count rapid consecutive hits within the window
    if _now - _cd["last_hit"] <= _SPAM_WINDOW:
        _cd["hits"] += 1
    else:
        _cd["hits"] = 1   # reset on slow tap
        _cd["extend_count"] = 0

    _cd["last_hit"] = _now

    # Escalate penalty based on hit count — no penalty for normal use (< 5 rapid clicks)
    penalty_secs = 0.0
    for min_hits, secs in _SPAM_LEVELS:
        if _cd["hits"] >= min_hits:
            penalty_secs = secs
            break

    if penalty_secs > 0:
        _cd["penalty_until"] = _now + penalty_secs

    # Heavy spam: nuke their active page and hard-lock 30s
    if _cd["hits"] >= _SPAM_NUKE:
        _cd["extend_count"] = 0
        _button_cooldown[_uid_str] = _cd
        old = _active_msg.pop(_uid_str, None)
        if old:
            asyncio.create_task(_delete_msg(old))
        try:
            await query.answer(
                "🚫 Onek beshi tap korecho! 30s block.\n"
                "⚠️ Block e click korle 10min lock hobe!\n"
                "✋ Anti-spam system active.",
                show_alert=True
            )
        except Exception:
            pass
        return

    _button_cooldown[_uid_str] = _cd

    # ── Group ownership check ──
    # In groups, only the person who triggered the command can press its buttons.
    # "Public" buttons that anyone may press are whitelisted below.
    _PUBLIC_BUTTONS = ("verify_join", "cf_accept_", "cf_decline_", "cf_cancel_")
    _is_public_btn  = any(
        data == b or data.startswith(b) for b in _PUBLIC_BUTTONS
    )
    if not _is_public_btn:
        _chat_type = query.message.chat.type if query.message else "private"
        if _chat_type in ("group", "supergroup"):
            _reply = query.message.reply_to_message if query.message else None
            if _reply and _reply.from_user and not _reply.from_user.is_bot:
                _orig_uid = _reply.from_user.id
                if query.from_user.id != _orig_uid and not is_owner(query.from_user.id):
                    try:
                        await query.answer(
                            "❌ This button is not for you!\n"
                            "🚫 Use /start to open your own menu.",
                            show_alert=True
                        )
                    except Exception:
                        pass
