# ── /stats (admin) ──
async def cmd_stats(update: Update, context: ContextTypes.DEFAULT_TYPE):
    users = load_users()
    if not users.get(str(update.effective_user.id), {}).get("is_admin") and not is_owner(update.effective_user.id):
        return
    codes = load_codes()
    total = len(users)
    banned = sum(1 for u in users.values() if u.get("banned"))
    admins = sum(1 for u in users.values() if u.get("is_admin"))
    total_codes = len(codes)
    now = datetime.utcnow()
    active = 0
    for c in codes.values():
        exp = c.get("expires_at")
        if not exp:
            active += 1
        else:
            try:
                if now < datetime.fromisoformat(exp):
                    active += 1
            except Exception:
                pass
    await update.message.reply_text(
        f"📊 Bot Statistics\n\n"
        f"👥 Total Users: {total}\n"
        f"🚫 Banned: {banned}\n"
        f"<tg-emoji emoji-id='6253517256794311831'>😎</tg-emoji> Admins: {admins}\n\n"
        f"🎫 Total Codes: {total_codes}\n"
        f"✅ Active Codes: {active}"
    )


async def cmd_top(update: Update, context: ContextTypes.DEFAULT_TYPE):
    users = load_users()

    # Filter out admin/banned for fair ranking
    def display_name(uid, u):
        name = (u.get("first_name") or u.get("username") or f"User {uid}").strip()
        return name[:20]

    entries = [
        (uid, u) for uid, u in users.items()
        if not u.get("is_admin") and not u.get("banned") and uid.lstrip("-").isdigit()
    ]

    # Top 10 by credits
    top_credits = sorted(entries, key=lambda x: x[1].get("credits", 0), reverse=True)[:10]
    # Top 10 by total_refers
    top_refers  = sorted(entries, key=lambda x: x[1].get("total_refers", 0), reverse=True)[:10]

