# ── /gencode (admin) ──
async def cmd_gencode(update: Update, context: ContextTypes.DEFAULT_TYPE):
    uid = str(update.effective_user.id)
    users = load_users()
    if not (users.get(uid, {}).get("is_admin") or is_owner(uid)):
        await update.message.reply_text(bq("❌ Admin only command."))
        return
    if not context.args:
        await update.message.reply_text(bq(
            "📋 Usage: /gencode &lt;credits&gt; [max_users] [days]\n\n"
            "Examples:\n/gencode 50 — 50 credits, unlimited\n"
            "/gencode 100 10 — max 10 users\n"
            "/gencode 50 5 7 — expires in 7 days"
        ))
        return
    try:
        credits_amount = int(context.args[0])
        max_users = int(context.args[1]) if len(context.args) > 1 else 0
        days = int(context.args[2]) if len(context.args) > 2 else 0
    except ValueError:
        await update.message.reply_text(bq("❌ Numbers only. Example: /gencode 50 10 7"))
        return
    chars = string.ascii_letters + string.digits
    code = "SHUVO_" + "".join(random.choices(chars, k=8))
    expires_at = (datetime.utcnow() + timedelta(days=days)).isoformat() if days > 0 else None
    codes = load_codes()
    codes[code] = {
        "credits": credits_amount,
        "max_users": max_users,
        "expires_at": expires_at,
        "used_by": [],
        "created_by": uid,
        "created_at": datetime.utcnow().isoformat(),
    }
    save_codes(codes)
    max_str = str(max_users) if max_users > 0 else "Unlimited"
    exp_str = f"{days} days" if days > 0 else "Never"
    await update.message.reply_text(
        f"✅ Code Generated!\n\n"
        f"🎫 Code: {code}\n"
        f"🔋 Credits: {credits_amount}\n"
        f"👥 Max Users: {max_str}\n"
        f"⏳ Expires: {exp_str}\n\n"
        f"Share: /redeem {code}"
    )


# ── /listcodes (admin) ──
async def cmd_listcodes(update: Update, context: ContextTypes.DEFAULT_TYPE):
    uid = str(update.effective_user.id)
    users = load_users()
    if not (users.get(uid, {}).get("is_admin") or is_owner(uid)):
        return
    codes = load_codes()
    if not codes:
        await update.message.reply_text(bq("📭 No codes yet."))
        return
    now = datetime.utcnow()
    lines = [f"📋 Codes ({len(codes)} total):\n"]
    for code, c in list(codes.items())[-20:]:
        used = len(c.get("used_by", []))
        max_u = c.get("max_users", 0)
        max_str = str(max_u) if max_u > 0 else "∞"
        exp = c.get("expires_at")
        if exp:
            try:
                exp_dt = datetime.fromisoformat(exp)
                expired_mark = " ⛔" if now > exp_dt else ""
                exp_str = exp_dt.strftime("%m/%d") + expired_mark
            except Exception:
                exp_str = "?"
        else:
            exp_str = "∞"
        lines.append(f"• {code}\n  <tg-emoji emoji-id='5224257782013769471'>💰</tg-emoji>{c['credits']}cr | 👥{used}/{max_str} | ⏳{exp_str}\n")
    await update.message.reply_text(bq("\n".join(lines)))


# ── /delcode (admin) ──
async def cmd_delcode(update: Update, context: ContextTypes.DEFAULT_TYPE):
    uid = str(update.effective_user.id)
    users = load_users()
    if not (users.get(uid, {}).get("is_admin") or is_owner(uid)):
        return
    if not context.args:
        await update.message.reply_text(bq("Usage: /delcode &lt;CODE&gt;"))
        return
    code = context.args[0].strip()
    codes = load_codes()
    if code not in codes:
        await update.message.reply_text(bq("❌ Code not found."))
        return
    del codes[code]
    save_codes(codes)
    await update.message.reply_text(bq(f"✅ {h(code)} deleted."))


# ── /addcredits (admin) ──
async def cmd_addcredits(update: Update, context: ContextTypes.DEFAULT_TYPE):
    uid = str(update.effective_user.id)
    users = load_users()
    if not (users.get(uid, {}).get("is_admin") or is_owner(uid)):
        return
    if len(context.args) < 2:
        await update.message.reply_text(bq("Usage: /addcredits &lt;user_id&gt; &lt;amount&gt;"))
        return
    try:
        target_uid = context.args[0].strip()
        amount = int(context.args[1])
    except ValueError:
        await update.message.reply_text(bq("❌ Invalid arguments."))
        return
    target_user, _ = get_user(users, target_uid)
    new_bal = target_user.get("credits", 0) + amount
    users[target_uid]["credits"] = new_bal
    save_users(users)
    await update.message.reply_text(f"✅ Credits Added!\n<tg-emoji emoji-id='5166063676687385916'>👤</tg-emoji> {target_uid}\n🔋 +{amount} → Balance: {new_bal}")


# ── /clear (group admin) ──
async def cmd_reupdate(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin only: update all pip packages from requirements.txt"""
    uid = str(update.effective_user.id)
    users = load_users()
    if not (users.get(uid, {}).get("is_admin") or is_owner(uid)):
        return
    sent = await update.message.reply_text(
        bq("🔄 Updating packages...\n\n⏳ Please wait..."),
        parse_mode=ParseMode.HTML
    )
    try:
        import subprocess as _sp, sys as _sys
        req_file = os.path.join(os.path.dirname(os.path.abspath(__file__)), "requirements.txt")
        proc = await asyncio.create_subprocess_exec(
            _sys.executable, "-m", "pip", "install", "-r", req_file, "--upgrade", "-q",
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE
        )
        _, stderr = await asyncio.wait_for(proc.communicate(), timeout=120)
        err_text = (stderr.decode(errors="ignore") or "").strip()
        if proc.returncode == 0:
            await sent.edit_text(
                bq("✅ Update Complete!\n\nAll packages updated successfully.\nUse /redeploy to restart the bot."),
                parse_mode=ParseMode.HTML
            )
        else:
            await sent.edit_text(
                bq(f"⚠️ Update finished with warnings:\n\n{err_text[:300] or 'No details.'}"),
                parse_mode=ParseMode.HTML
            )
    except asyncio.TimeoutError:
        await sent.edit_text(bq("❌ Update timed out. Try again."), parse_mode=ParseMode.HTML)
    except Exception as e:
        await sent.edit_text(bq(f"❌ Update failed:\n{str(e)[:300]}"), parse_mode=ParseMode.HTML)


async def cmd_redeploy(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin only: restart the bot process"""
    uid = str(update.effective_user.id)
    users = load_users()
    if not (users.get(uid, {}).get("is_admin") or is_owner(uid)):
        return
    await update.message.reply_text(
        bq("🔁 Restarting bot...\n\n✅ Bot will be back in a few seconds!"),
        parse_mode=ParseMode.HTML
    )
    write_log(f"[REDEPLOY] Admin {uid} triggered restart")
    await asyncio.sleep(1)
    os.execv(sys.executable, [sys.executable] + sys.argv)


