# ── QR Code Generator ──
async def cmd_qr(update: Update, context: ContextTypes.DEFAULT_TYPE):
    import qrcode as _qrcode
    if update.message:
        users = load_users()
        user, _ = get_user(users, update.effective_user.id, update.effective_user.username or "")
        if not user.get("is_admin") and "tools" in user.get("blocked_cmds", []):
            sent = await update.message.reply_text(bq("🚫 Utility tools have been disabled for your account.\n\nContact admin."))
            schedule_delete(sent); return
    text = " ".join(context.args).strip() if context.args else ""
    if not text:
        await update.message.reply_text(bq("❌ Usage: /qr &lt;text or URL&gt;\n\nExample: /qr https://github.com"))
        return
    sent = await update.message.reply_text(_ld("Generating QR code...", ["📷","🔲","✅","<tg-emoji emoji-id='5465169893580086142'>⭐</tg-emoji>","💫","🎯"], ["Building QR code...","Encoding data...","Rendering...","Almost done..."]), parse_mode=ParseMode.HTML)
    anim = await _anim_start(sent, "Generating QR code...", ["📷","🔲","✅","<tg-emoji emoji-id='5465169893580086142'>⭐</tg-emoji>","💫","🎯"], ["Building QR code...","Encoding data...","Rendering...","Almost done..."])
    qr = _qrcode.QRCode(version=1, error_correction=_qrcode.constants.ERROR_CORRECT_L, box_size=10, border=4)
    qr.add_data(text)
    qr.make(fit=True)
    img = qr.make_image(fill_color="white", back_color="black")
    buf = BytesIO()
    img.save(buf, format="PNG")
    buf.seek(0)
    anim.cancel()
    await sent.delete()
    await update.message.reply_photo(photo=buf, caption="📷 Here's your QR Code!")


