async def cmd_love(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if len(context.args) < 2:
        await update.message.reply_text(bq("❌ Usage: /love Name1 Name2\n\nExample: /love Alice Bob"))
        return
    name1, name2 = context.args[0], context.args[1]
    sent = await update.message.reply_text(_ld(f"Calculating love between {_e(name1)} & {_e(name2)}...", ["💕","❤️","💘","💝","💖","💑"], ["Calculating compatibility...","Checking chemistry...","Analysing match...","Almost done..."]), parse_mode=ParseMode.HTML)
    anim = await _anim_start(sent, f"Calculating love between {_e(name1)} & {_e(name2)}...", ["💕","❤️","💘","💝","💖","💑"], ["Calculating compatibility...","Checking chemistry...","Analysing match...","Almost done..."])
    await asyncio.sleep(2.2)
    anim.cancel()
    pct = random.randint(10, 100)
    if pct <= 30:
        msg = random.choice(["Love is in the air but needs a little spark. 🌱", "A good start but there's room to grow. 💫", "It's just the beginning of something beautiful. 🌸"])
    elif pct <= 70:
        msg = random.choice(["A strong connection is there. Keep nurturing it. 💪", "You've got a good chance. Work on it. 🌹", "Love is blossoming, keep going. 🌺"])
    else:
        msg = random.choice(["Wow! It's a match made in heaven! 💑", "Perfect match! Cherish this bond. 💍", "Destined to be together! 🎉"])
    await sent.edit_text(
        f"💕 <b>{_e(name1)}</b> + <b>{_e(name2)}</b> = <b>{pct}%</b>\n\n{msg}",
        parse_mode=ParseMode.HTML
    )
    schedule_delete(sent)


