# ── Password Generator ──
async def cmd_genpassword(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ1234567890!@#$%^&*()_+"
    if context.args:
        try:
            length = int(context.args[0])
            if length < 1:
                raise ValueError
        except ValueError:
            await update.message.reply_text(bq("❌ Please provide a valid positive number.\nExample: /genpassword 12"))
            return
    else:
        length = random.choice([8, 10, 12, 14, 16])
    pwd = "".join(random.choices(chars, k=length))
    await update.message.reply_text(
        f"🔐 <b>Generated Password</b>\n\n"
        f"<b>Length:</b> {length}\n"
        f"<b>Password:</b> <code>{_e(pwd)}</code>",
        parse_mode=ParseMode.HTML
    )


