async def cmd_decode(update: Update, context: ContextTypes.DEFAULT_TYPE):
    hex_input = "".join(context.args).replace(" ", "") if context.args else ""
    if not hex_input:
        await update.message.reply_text(bq("❌ Usage: /decode &lt;hex&gt;\n\nExample: /decode 48656c6c6f"))
