    await update.message.reply_text(
        f"<tg-emoji emoji-id='5465169893580086142'>⭐</tg-emoji> <b>Hex Input:</b>\n<code>{_e(hex_input)}</code>\n\n🔡 <b>Decoded:</b>\n{_e(decoded)}",
        parse_mode=ParseMode.HTML
    )


