# ── Meme Maker (MMF) ──
async def cmd_mmf(update: Update, context: ContextTypes.DEFAULT_TYPE):
    import textwrap as _textwrap
    reply = update.message.reply_to_message
    if not reply or not (reply.photo or (reply.document and reply.document.mime_type and reply.document.mime_type.startswith("image/"))):
        await update.message.reply_text(bq("❌ Reply to an image with /mmf &lt;top text&gt;;&lt;bottom text&gt;"))
        return
    text = " ".join(context.args).strip() if context.args else ""
    if not text:
        await update.message.reply_text(bq("❌ Provide text after /mmf\n\nExample: /mmf Top text;Bottom text"))
        return
    sent = await update.message.reply_text(_ld("Creating meme...", ["🎨","😂","🤣","🖌️","💫","🎭"], ["Fetching image...","Drawing text...","Adding style...","Almost done..."]), parse_mode=ParseMode.HTML)
    anim = await _anim_start(sent, "Creating meme...", ["🎨","😂","🤣","🖌️","💫","🎭"], ["Fetching image...","Drawing text...","Adding style...","Almost done..."])
    try:
        if reply.photo:
            file = await context.bot.get_file(reply.photo[-1].file_id)
        else:
            file = await context.bot.get_file(reply.document.file_id)
        buf = BytesIO()
        await file.download_to_memory(buf)
        buf.seek(0)
        img = Image.open(buf).convert("RGBA")
        i_width, i_height = img.size
        draw = ImageDraw.Draw(img)
        font_size = int((60 / 640) * i_width) or 30
        font = None
        for font_path in [
            "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
            "/usr/share/fonts/TTF/DejaVuSans-Bold.ttf",
            "/usr/share/fonts/dejavu/DejaVuSans-Bold.ttf",
        ]:
            try:
                font = ImageFont.truetype(font_path, font_size)
                break
            except Exception:
                pass
        if font is None:
            font = ImageFont.load_default()

        def draw_outlined_text(txt, y_start):
            y = y_start
            for line in _textwrap.wrap(txt, width=20):
                try:
                    bbox = font.getbbox(line)
                    tw, th = bbox[2] - bbox[0], bbox[3] - bbox[1]
                except Exception:
                    tw, th = len(line) * 15, 30
                x = (i_width - tw) / 2
                for dx, dy in [(-2, 0), (2, 0), (0, -2), (0, 2)]:
                    draw.text((x + dx, y + dy), line, font=font, fill=(0, 0, 0))
                draw.text((x, y), line, font=font, fill=(255, 255, 255))
                y += th + 5
            return y

        parts = text.split(";", 1)
        upper_text = parts[0].strip()
        lower_text = parts[1].strip() if len(parts) > 1 else ""
        if upper_text:
            draw_outlined_text(upper_text, 10)
        if lower_text:
            lines = _textwrap.wrap(lower_text, width=20)
            try:
                bbox = font.getbbox("A")
                lh = bbox[3] - bbox[1] + 5
            except Exception:
                lh = 35
            y_start = i_height - lh * len(lines) - 20
            draw_outlined_text(lower_text, max(y_start, i_height // 2))

        out = BytesIO()
        img.save(out, format="PNG")
        out.seek(0)
        anim.cancel()
        await sent.delete()
        await update.message.reply_photo(photo=out, caption="😂 Here's your meme!")
    except Exception as e:
        anim.cancel()
        await sent.edit_text(f"❌ Failed to create meme: {e}")


# ── Background Remove ──
async def cmd_rmbg(update: Update, context: ContextTypes.DEFAULT_TYPE):
    reply = update.message.reply_to_message
    if not reply or not reply.photo:
        await update.message.reply_text(bq("📸 Reply to a photo to remove its background.\n\nUsage: Reply to image + /rmbg"))
        return
    sent = await update.message.reply_text(_ld("Removing background...", ["🖌️","✂️","🎨","✨","💫","🖼️"], ["Removing background...","Cutting out object...","Cleaning edges...","Almost done..."]), parse_mode=ParseMode.HTML)
    anim = await _anim_start(sent, "Removing background...", ["🖌️","✂️","🎨","✨","💫","🖼️"], ["Removing background...","Cutting out object...","Cleaning edges...","Almost done..."])
    try:
        file = await context.bot.get_file(reply.photo[-1].file_id)
        buf = BytesIO()
        await file.download_to_memory(buf)
        buf.seek(0)
        async with httpx.AsyncClient(timeout=30) as client:
            r = await client.post(
                "https://api.remove.bg/v1.0/removebg",
                headers={"X-API-Key": "23nfCEipDijgVv6SH14oktJe"},
                files={"image_file": ("image.png", buf, "image/png")},
                data={"size": "auto"},
            )
        anim.cancel()
        if r.status_code != 200 or "image" not in r.headers.get("content-type", ""):
            try:
                err = safe_json(r, {})
                detail = err.get("errors", [{}])[0].get("detail", "Unknown error")
            except Exception:
                detail = r.text[:200]
            await sent.edit_text(f"❌ Background removal failed: {detail}")
            schedule_delete(sent)
            return
        out = BytesIO(r.content)
        out.name = "no_bg.png"
        await sent.delete()
        await update.message.reply_document(document=out, filename="no_bg.png", caption="✅ Background removed!")
    except Exception as e:
        anim.cancel()
        await sent.edit_text(f"❌ Error: {e}")
        schedule_delete(sent)


