async def cmd_stdl(update: Update, context: ContextTypes.DEFAULT_TYPE):
    reply = update.message.reply_to_message
    if not reply or not reply.sticker:
        await update.message.reply_text(bq("❌ Reply to a sticker to download it."))
        return
    sent = await update.message.reply_text(_ld("Downloading sticker...", ["⬇️","📥","💾","🎭","✨","✅"], ["Fetching sticker file...","Downloading...","Converting...","Almost done..."]), parse_mode=ParseMode.HTML)
    anim = await _anim_start(sent, "Downloading sticker...", ["⬇️","📥","💾","🎭","✨","✅"], ["Fetching sticker file...","Downloading...","Converting...","Almost done..."])
    try:
        st = reply.sticker
        file = await context.bot.get_file(st.file_id)
        buf = BytesIO()
        await file.download_to_memory(buf)
        buf.seek(0)
        if st.is_animated:
            buf.name = "sticker.tgs"
            anim.cancel()
            await update.message.reply_document(document=buf, filename="sticker.tgs", caption="🎭 Animated sticker")
        elif st.is_video:
            buf.name = "sticker.webm"
            anim.cancel()
            await update.message.reply_document(document=buf, filename="sticker.webm", caption="🎬 Video sticker")
        else:
            img = Image.open(buf).convert("RGBA")
            out = BytesIO()
            img.save(out, format="PNG")
            out.seek(0)
            anim.cancel()
            await update.message.reply_document(document=out, filename="sticker.png", caption="🖼 Static sticker")
        await sent.delete()
    except Exception as e:
        anim.cancel()
        await sent.edit_text(f"❌ Failed: {e}")


