_MASTI_DATA = {
    "cutie":   ("🍑", "{mention} is {pct}% cute baby 🥀"),
    "horny":   ("🔥", "{mention} is {pct}% horny!"),
    "hot":     ("🔥", "{mention} is {pct}% hot!"),
    "sexy":    ("💋", "{mention} is {pct}% sexy!"),
    "gay":     ("🍷", "{mention} is {pct}% gay!"),
    "lesbian": ("💜", "{mention} is {pct}% lesbian!"),
}

async def _masti_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    cmd = update.message.text.split()[0].lstrip("/").lower().split("@")[0]
    emoji, tmpl = _MASTI_DATA.get(cmd, ("🎲", "{mention} is {pct}%!"))
    target = update.message.reply_to_message.from_user if update.message.reply_to_message else update.effective_user
    mention = f"<a href='tg://user?id={target.id}'>{_e(target.first_name)}</a>"
    pct = random.randint(1, 100)
    text = tmpl.format(mention=mention, pct=pct)
    await update.message.reply_text(f"{emoji} {text}", parse_mode=ParseMode.HTML)


