# ── Helpers ──
def _group_only(update: Update) -> bool:
    return update.effective_chat.type in ("group", "supergroup")

async def _is_group_admin(context, chat_id: int, user_id: int) -> bool:
    try:
        member = await context.bot.get_chat_member(chat_id, user_id)
        return member.status in ("administrator", "creator")
    except Exception:
        return False

async def _is_bot_admin(context, chat_id: int) -> bool:
    try:
        me = await context.bot.get_me()
        member = await context.bot.get_chat_member(chat_id, me.id)
        return member.status in ("administrator", "creator")
    except Exception:
        return False


# ── Mute / Unmute / Temp Mute ──
async def cmd_mute(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _group_only(update):
        return await update.message.reply_text("⚠️ Use this command in a group.")
    if not await _is_group_admin(context, update.effective_chat.id, update.effective_user.id):
        return await update.message.reply_text("❌ Only admins can use this.")
    target = update.message.reply_to_message.from_user if update.message.reply_to_message else None
    if not target:
        return await update.message.reply_text("❌ Reply to a user to mute them.")
    try:
        from telegram import ChatPermissions as _CP
        await context.bot.restrict_chat_member(
            update.effective_chat.id, target.id,
            permissions=_CP(can_send_messages=False)
        )
        mention = f'<a href="tg://user?id={target.id}">{_html.escape(target.first_name)}</a>'
        await update.message.reply_text(f"🔇 {mention} has been muted.", parse_mode=ParseMode.HTML)
    except Exception as e:
        await update.message.reply_text(f"❌ Failed: {e}")

