# ── Purge / Delete / Pin / Unpin ──
async def cmd_purge(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _group_only(update):
        return await update.message.reply_text("⚠️ Use this command in a supergroup.")
    if not await _is_group_admin(context, update.effective_chat.id, update.effective_user.id):
        return await update.message.reply_text("❌ Only admins can use this.")
    if not update.message.reply_to_message:
        return await update.message.reply_text("❌ Reply to the message you want to purge from.")
    start_id = update.message.reply_to_message.message_id
    end_id = update.message.message_id
    ids = list(range(start_id, end_id + 1))
    deleted = 0
    for i in range(0, len(ids), 100):
        batch = ids[i:i + 100]
        try:
            await context.bot.delete_messages(update.effective_chat.id, batch)
            deleted += len(batch)
        except Exception:
            for mid in batch:
                try:
                    await context.bot.delete_message(update.effective_chat.id, mid)
                    deleted += 1
                except Exception:
                    pass
        await asyncio.sleep(0.3)
    confirm = await update.message.reply_text(
        f"✅ Purged <b>{deleted}</b> messages.", parse_mode=ParseMode.HTML
    )
    await asyncio.sleep(3)
    try:
        await confirm.delete()
    except Exception:
        pass

