async def cmd_id(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    chat = update.effective_chat
    reply = update.message.reply_to_message
    lines = [f"🆔 <b>Your ID:</b> <code>{user.id}</code>"]
    if chat.type != "private":
        lines.append(f"💬 <b>Chat ID:</b> <code>{chat.id}</code>")
    if reply:
        lines.append(f"📨 <b>Message ID:</b> <code>{reply.message_id}</code>")
        if reply.from_user:
            lines.append(f"<tg-emoji emoji-id='5166063676687385916'>👤</tg-emoji> <b>Replied User ID:</b> <code>{reply.from_user.id}</code>")
    if context.args:
        try:
            target = await context.bot.get_chat(context.args[0])
            lines.append(f"🔍 <b>Searched ID:</b> <code>{target.id}</code>")
        except Exception:
            lines.append("❌ Couldn't find that user/chat.")
    await update.message.reply_text("\n".join(lines), parse_mode=ParseMode.HTML)

async def cmd_whois(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if update.message.reply_to_message and update.message.reply_to_message.from_user:
        user = update.message.reply_to_message.from_user
    elif context.args:
        try:
            user = await context.bot.get_chat(context.args[0])
        except Exception:
            return await update.message.reply_text("❌ User not found.")
    else:
        user = update.effective_user
    first = getattr(user, "first_name", "") or ""
    last = getattr(user, "last_name", "") or ""
