# ── Welcome System ──
_WELCOME_FILE = "bot/welcome_settings.json"

def _load_welcome() -> dict:
    try:
        with open(_WELCOME_FILE) as f:
            return json.load(f)
    except Exception:
        return {}

def _save_welcome(data: dict):
    try:
        with open(_WELCOME_FILE, "w") as f:
            json.dump(data, f, indent=2)
    except Exception:
        pass

async def cmd_welcome(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _group_only(update):
        return await update.message.reply_text("⚠️ Use this command in a group.")
    if not await _is_group_admin(context, update.effective_chat.id, update.effective_user.id):
        return await update.message.reply_text("❌ Only admins can use this.")
    chat_id = str(update.effective_chat.id)
    settings = _load_welcome()
    if not context.args:
        cfg = settings.get(chat_id, {})
        state = cfg.get("enabled", False)
        msg = cfg.get("message", "")
        await update.message.reply_text(
            f"👋 Welcome is: <b>{'ON ✅' if state else 'OFF ❌'}</b>\n"
            f"Message: {_html.escape(msg) if msg else '<i>Default</i>'}\n\n"
            "Usage:\n/welcome on\n/welcome off\n/welcome set Your message here\n\n"
            "Variables: {mention} {name} {group}",
            parse_mode=ParseMode.HTML
        )
        return
    arg = context.args[0].lower()
    if arg == "on":
        settings.setdefault(chat_id, {})["enabled"] = True
        _save_welcome(settings)
        await update.message.reply_text("✅ Welcome messages enabled!")
    elif arg == "off":
        settings.setdefault(chat_id, {})["enabled"] = False
        _save_welcome(settings)
        await update.message.reply_text("❌ Welcome messages disabled.")
    elif arg == "set" and len(context.args) > 1:
        msg = " ".join(context.args[1:])
        settings.setdefault(chat_id, {})["message"] = msg
        _save_welcome(settings)
        await update.message.reply_text(f"✅ Welcome message set:\n{_html.escape(msg)}", parse_mode=ParseMode.HTML)
    else:
        await update.message.reply_text("❌ Usage: /welcome on | off | set <message>")

async def _welcome_new_member(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message or not update.message.new_chat_members:
        return
    chat_id = str(update.effective_chat.id)
    settings = _load_welcome()
    cfg = settings.get(chat_id, {})
    if not cfg.get("enabled", False):
        return
    for member in update.message.new_chat_members:
        if member.is_bot:
            continue
        mention = f'<a href="tg://user?id={member.id}">{_html.escape(member.first_name)}</a>'
        grp = _html.escape(update.effective_chat.title or "the group")
        default_msg = f"👋 Welcome {mention} to <b>{grp}</b>! 🎉"
        msg = cfg.get("message") or default_msg
        msg = msg.replace("{mention}", mention).replace("{name}", _html.escape(member.first_name)).replace("{group}", grp)
        await update.message.reply_text(msg, parse_mode=ParseMode.HTML)


# ── Tag Commands ──
_tagall_stop: dict[int, bool] = {}

async def cmd_tagall(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _group_only(update):
        return await update.message.reply_text("⚠️ Use this command in a group.")
    if not await _is_group_admin(context, update.effective_chat.id, update.effective_user.id):
        return await update.message.reply_text("❌ Only admins can use this.")
    _u_chk = load_users()
    _u_me, _ = get_user(_u_chk, update.effective_user.id, update.effective_user.username or "")
    if not _u_me.get("is_admin") and "group" in _u_me.get("blocked_cmds", []):
        return await update.message.reply_text(bq("🚫 Group commands have been disabled for your account.\n\nContact admin."))
    chat_id = update.effective_chat.id
    _tagall_stop[chat_id] = False
    msg_text = " ".join(context.args) if context.args else "📣 Attention everyone!"
    sent = await update.message.reply_text("📋 <i>Fetching members...</i>", parse_mode=ParseMode.HTML)
    try:
        admins = await context.bot.get_chat_administrators(chat_id)
        mentions = []
        for a in admins:
            if _tagall_stop.get(chat_id):
                break
            if not a.user.is_bot:
                mentions.append(f'<a href="tg://user?id={a.user.id}">{_html.escape(a.user.first_name)}</a>')
        await sent.delete()
        batch = []
        for m in mentions:
            if _tagall_stop.get(chat_id):
                break
            batch.append(m)
            if len(batch) >= 5:
                await update.message.reply_text(" ".join(batch), parse_mode=ParseMode.HTML)
                batch.clear()
                await asyncio.sleep(1)
        if batch and not _tagall_stop.get(chat_id):
            await update.message.reply_text(" ".join(batch), parse_mode=ParseMode.HTML)
        if not _tagall_stop.get(chat_id):
            await update.message.reply_text(f"📣 {_html.escape(msg_text)}", parse_mode=ParseMode.HTML)
    except Exception as e:
        await sent.edit_text(f"❌ Error: {e}")

async def cmd_tagstop(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _group_only(update):
        return await update.message.reply_text("⚠️ Use this command in a group.")
    _tagall_stop[update.effective_chat.id] = True
    await update.message.reply_text("⏹ Tagging stopped.")

