async def _fun_tag(update: Update, context: ContextTypes.DEFAULT_TYPE, msgs: list, label: str):
    if not _group_only(update):
        return await update.message.reply_text("⚠️ Use this command in a group.")
    chat_id = update.effective_chat.id
    _tagall_stop[chat_id] = False
    try:
        admins = await context.bot.get_chat_administrators(chat_id)
        mentions = [
            f'<a href="tg://user?id={a.user.id}">{_html.escape(a.user.first_name)}</a>'
            for a in admins if not a.user.is_bot
        ]
    except Exception:
        return await update.message.reply_text("❌ Need admin rights to fetch members.")
    msg_text = random.choice(msgs)
    batch = []
    for m in mentions:
        if _tagall_stop.get(chat_id):
            break
        batch.append(m)
        if len(batch) >= 5:
            await update.message.reply_text(f"{label}\n" + " ".join(batch), parse_mode=ParseMode.HTML)
            batch.clear()
            await asyncio.sleep(1)
    if batch and not _tagall_stop.get(chat_id):
        await update.message.reply_text(f"{label}\n" + " ".join(batch), parse_mode=ParseMode.HTML)
    if not _tagall_stop.get(chat_id):
        await update.message.reply_text(msg_text, parse_mode=ParseMode.HTML)

