async def cmd_lottery(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if await _check_maintenance(update): return
    users = load_users()
    user, uid_str = get_user(
        users, update.effective_user.id,
        update.effective_user.username or "",
        update.effective_user.first_name or ""
    )
    if user.get("banned"): return

    args    = context.args or []
    chat_id = update.effective_chat.id
    _load_lotteries()

    # ── /lottery  (no args) — help + active list ─────────────────
    if not args:
        active = {lid: lot for lid, lot in _lotteries.items() if lot["status"] == "active"}
        if active:
            lines = []
            for lid, lot in list(active.items())[:8]:
                tl = _time_left(lot.get("ends_at", ""))
                lines.append(
                    f"🎰 <b>#{lid}</b> | 💵 {lot['amount']} cr | "
                    f"👥 {len(lot['participants'])} | ⏳ {tl}"
                )
            active_txt = "\n".join(lines)
        else:
            active_txt = "  No active lotteries right now."

