async def cmd_ban_group(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Group-level ban using bot's ban_chat_member (not bot-user DB ban)."""
    if not _group_only(update):
        return await update.message.reply_text("⚠️ Use in a group.")
    if not await _is_group_admin(context, update.effective_chat.id, update.effective_user.id):
        return await update.message.reply_text("❌ Only admins can use this.")
    target = update.message.reply_to_message.from_user if update.message.reply_to_message else None
    if not target:
        return await update.message.reply_text("❌ Reply to a user to ban them.")
    try:
        await context.bot.ban_chat_member(update.effective_chat.id, target.id)
        mention = f'<a href="tg://user?id={target.id}">{_html.escape(target.first_name)}</a>'
        await update.message.reply_text(f"⛔ {mention} has been banned.", parse_mode=ParseMode.HTML)
    except Exception as e:
        await update.message.reply_text(f"❌ Failed: {e}")

async def cmd_unban_group(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Group-level unban using bot's unban_chat_member."""
    if not _group_only(update):
        return await update.message.reply_text("⚠️ Use in a group.")
    if not await _is_group_admin(context, update.effective_chat.id, update.effective_user.id):
        return await update.message.reply_text("❌ Only admins can use this.")
    target = update.message.reply_to_message.from_user if update.message.reply_to_message else None
    if not target and context.args:
        try:
            target = await context.bot.get_chat(context.args[0])
        except Exception:
            pass
    if not target:
        return await update.message.reply_text("❌ Reply to a user to unban them.")
    try:
        await context.bot.unban_chat_member(update.effective_chat.id, target.id, only_if_banned=True)
        mention = f'<a href="tg://user?id={target.id}">{_html.escape(target.first_name)}</a>'
        await update.message.reply_text(f"✅ {mention} has been unbanned.", parse_mode=ParseMode.HTML)
    except Exception as e:
        await update.message.reply_text(f"❌ Failed: {e}")

async def dot_command_router(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Routes messages starting with '.' to the appropriate command handler."""
    if not update.message or not update.message.text:
        return
    text = update.message.text.strip()
    if not text.startswith("."):
        return
    # Parse: .command arg1 arg2 ...
    parts = text[1:].split()
    if not parts:
        return
    cmd = parts[0].lower().split("@")[0]  # strip @botname if present
    args = parts[1:]
    handler = _DOT_CMD_MAP.get(cmd)
    if not handler:
        return  # unknown dot command — ignore silently
    # Inject args into context so handlers work the same way
    context.args = args
    await handler(update, context)


