SEP16 = "<tg-emoji emoji-id='6307665627481903641'>➖</tg-emoji>" * 16

def _tog_btn(label, key, blocked, uid):
    is_off = key in blocked
    style  = "danger" if is_off else "success"
    icon   = "🔴" if is_off else "🟢"
    return SBtn(f"{icon} {label}", style=style, callback_data=f"upanel_tog_{key}_{uid}")

def _status(key, blocked):
    return "🔴" if key in blocked else "🟢"


