async def cmd_user(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Owner-only: /user <id>  or reply to a message."""
    users = load_users()
    caller, caller_uid = get_user(users, update.effective_user.id)
    if not caller["is_admin"] and not is_owner(caller_uid):
        return

    target_id = None

    # Check reply first
    if update.message.reply_to_message and update.message.reply_to_message.from_user:
        target_id = str(update.message.reply_to_message.from_user.id)

    # Then check args
    if not target_id and context.args:
        arg = context.args[0].lstrip("@")
        # If it's numeric treat as ID; else search by username
        if arg.isdigit():
            target_id = arg
        else:
            all_u = load_users()
            for uid_k, u_data in all_u.items():
                if (u_data.get("username") or "").lower() == arg.lower():
                    target_id = uid_k
                    break

    if not target_id:
        sent = await update.message.reply_text(
            bq("❌ Usage: /user <user_id>  or reply to a user's message\n\nExample: /user 123456789")
        )
        schedule_delete(sent)
        return

    all_users = load_users()
    target, _ = get_user(all_users, target_id)
    save_users(all_users)

    txt, kb = _build_user_panel(target_id, target)
    await update.message.reply_text(txt, parse_mode=ParseMode.HTML, reply_markup=kb)


# ── Premium Emoji Bot Subclass ────────────────────────────────────────────────
class _PremiumBot(ExtBot):
    """Drop-in Bot subclass that auto-upgrades every plain emoji in outgoing
    HTML messages to its premium animated tg-emoji equivalent.
    Applies to: send_message, edit_message_text, send_photo, send_video,
    send_audio, send_document, send_voice, send_animation."""

    @staticmethod
    def _fix(t):
        return _pe_all(str(t)) if t else t

    @staticmethod
    def _html_mode(kwargs):
        """True when parse_mode is not explicitly overridden to None/plain."""
        pm = kwargs.get('parse_mode')
        return pm is None or pm not in ('', 'Markdown', 'MarkdownV2')

    async def send_message(self, chat_id, text=None, **kwargs):
        if text and self._html_mode(kwargs):
            text = self._fix(text)
        return await super().send_message(chat_id, text=text, **kwargs)

    async def edit_message_text(self, text, **kwargs):
        if text and self._html_mode(kwargs):
            text = self._fix(text)
        return await super().edit_message_text(text, **kwargs)

    async def send_photo(self, chat_id, photo, caption=None, **kwargs):
        if caption and self._html_mode(kwargs):
            caption = self._fix(caption)
        return await super().send_photo(chat_id, photo, caption=caption, **kwargs)

    async def send_video(self, chat_id, video, caption=None, **kwargs):
        if caption and self._html_mode(kwargs):
            caption = self._fix(caption)
        return await super().send_video(chat_id, video, caption=caption, **kwargs)

    async def send_audio(self, chat_id, audio, caption=None, **kwargs):
        if caption and self._html_mode(kwargs):
            caption = self._fix(caption)
        return await super().send_audio(chat_id, audio, caption=caption, **kwargs)

    async def send_document(self, chat_id, document, caption=None, **kwargs):
        if caption and self._html_mode(kwargs):
            caption = self._fix(caption)
        return await super().send_document(chat_id, document, caption=caption, **kwargs)

    async def send_voice(self, chat_id, voice, caption=None, **kwargs):
        if caption and self._html_mode(kwargs):
            caption = self._fix(caption)
        return await super().send_voice(chat_id, voice, caption=caption, **kwargs)

    async def send_animation(self, chat_id, animation, caption=None, **kwargs):
        if caption and self._html_mode(kwargs):
            caption = self._fix(caption)
        return await super().send_animation(chat_id, animation, caption=caption, **kwargs)
