# ── /news ─────────────────────────────────────────────────────────────────────
async def cmd_news(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message: return
    query = " ".join(context.args).strip() if context.args else ""
    sent = await update.message.reply_text(bq("📰 News fetch korchi..."), parse_mode=ParseMode.HTML)
    try:
        rss = "https://feeds.bbci.co.uk/news/rss.xml" if not query else f"https://feeds.bbci.co.uk/news/search/rss.xml?q={urllib.parse.quote(query)}"
        url = f"https://api.rss2json.com/v1/api.json?rss_url={urllib.parse.quote(rss)}&api_key=free&count=6"
        async with httpx.AsyncClient(timeout=15) as client:
            r = await client.get(url)
        data = safe_json(r, {})
        items = data.get("items", [])
        if not items:
            await sent.edit_text(bq("❌ Kono news paoa jachhe na. Ektu por try koro."))
            schedule_delete(sent); return
        lines = [f"📰 <b>Latest News</b>{' — ' + h(query) if query else ''}\n"]
        for i, it in enumerate(items[:5], 1):
            title = h(it.get("title", "")[:90])
            link  = it.get("link", "")
            lines.append(f"{i}. <a href='{link}'>{title}</a>")
        lines.append(f"\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅")
        await sent.edit_text("\n".join(lines), disable_web_page_preview=True)
    except Exception as e:
        await sent.edit_text(bq(f"❌ Error: {h(str(e)[:200])}"))
    schedule_delete(sent)


