# ── /hn (HackerNews summaries) ────────────────────────────────────────────────
async def cmd_hackernews(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message: return
    if await _check_maintenance(update): return
    users = load_users()
    user, uid = get_user(users, update.effective_user.id, update.effective_user.username or "")
    if await _check_banned(update, user): return
    sent = await update.message.reply_text(_ld("HackerNews fetch korchi...", ["📰","💻","🔬","🚀","⚡","🌐"], ["Loading top stories...","Summarizing with AI...","Almost done..."]), parse_mode=ParseMode.HTML)
    anim = await _anim_start(sent, "HackerNews fetch korchi...", ["📰","💻","🔬","🚀","⚡","🌐"], ["Loading top stories...","Summarizing..."])
    try:
        async with httpx.AsyncClient(timeout=15) as client:
            r = await client.get("https://hacker-news.firebaseio.com/v0/topstories.json")
            top_ids = safe_json(r, [])[:5]
            stories = []
            for sid in top_ids:
                ir = await client.get(f"https://hacker-news.firebaseio.com/v0/item/{sid}.json")
                item = safe_json(ir, {})
                if item.get("title"):
                    stories.append(item)
        if not stories:
            anim.cancel()
            await sent.edit_text(bq("❌ HackerNews stories load hoy nai. Ektu por try koro."))
            schedule_delete(sent); return
        # Build summary prompt
        story_lines = "\n".join(f"{i+1}. {s.get('title','')} ({s.get('url','no url')[:60]})" for i, s in enumerate(stories))
        ai_prompt = (
            f"Summarize these 5 HackerNews top stories in 1 short sentence each (max 15 words). "
            f"Be informative. Format: '1. [summary]' numbered list.\n\n{story_lines}"
        )
        summaries_raw = await ai_groq(uid, ai_prompt)
        anim.cancel()
        lines = ["🔥 <b>HackerNews Top Stories</b>\n"]
        for i, s in enumerate(stories):
            title = h(s.get("title", "")[:70])
            url   = s.get("url", f"https://news.ycombinator.com/item?id={s.get('id','')}")
            score = s.get("score", 0)
            lines.append(f"{i+1}. <a href='{url}'>{title}</a>  ⬆️{score}")
        lines.append(f"\n💡 <b>AI Summaries:</b>\n{fmt_ai(summaries_raw, max_lines=10)}")
        lines.append(f"\n<tg-emoji emoji-id='6147464060305676048'>😎</tg-emoji> DEV @Shuvobhai ✅")
        await sent.edit_text("\n".join(lines), disable_web_page_preview=True)
    except Exception as e:
        anim.cancel()
        await sent.edit_text(bq(f"❌ Error: {h(str(e)[:200])}"))
    schedule_delete(sent)


