def main():
    os.makedirs("bot", exist_ok=True)
    _build_dot_map()

    # Write PID so controller bot can manage this process
    with open(PID_FILE, "w") as f:
        f.write(str(os.getpid()))

    write_log(f"SHUVO BOT started — PID {os.getpid()}")

